    v_runtime_attack_accuracy_modifier := coalesce(nullif(v_runtime_modifier_summary->>'attack_accuracy', '')::integer, 0);
    v_runtime_damage_modifier := coalesce(nullif(v_runtime_modifier_summary->>'damage', '')::integer, 0);
