create or replace function public.creator_delete_weapon(
  p_weapon_model_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_weapon public.odyssey_weapon_model_defs%rowtype;
  v_character_weapon_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_weapon
  from public.odyssey_weapon_model_defs weapon
  where weapon.id = p_weapon_model_id;

  if not found then
    return public.odyssey_creator_error(
      'WEAPON_NOT_FOUND',
      'Weapon model was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown weapon model id.'))
    );
  end if;

  select count(*)::integer
  into v_character_weapon_count
  from public.odyssey_character_weapons weapon
  where weapon.weapon_model_id = p_weapon_model_id;

  if v_character_weapon_count > 0 then
    v_details := jsonb_build_array(
      jsonb_build_object(
        'field', 'character_weapons',
        'count', v_character_weapon_count,
        'message', 'Weapon model is assigned to one or more character weapons.'
      )
    );
    return public.odyssey_creator_error(
      'WEAPON_MODEL_IN_USE',
      'Weapon model is still referenced and cannot be deleted.',
      v_details
    );
  end if;

  delete from public.odyssey_weapon_model_defs weapon
  where weapon.id = p_weapon_model_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_weapon_model_id,
    'deleted_code', v_weapon.code
  );
end;
$$;

grant execute on function public.creator_delete_weapon(uuid) to anon, authenticated;

create or replace function public.creator_delete_item_def(
  p_item_def_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_item public.odyssey_item_defs%rowtype;
  v_character_item_count integer := 0;
  v_reload_feature_count integer := 0;
  v_ability_resource_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_item
  from public.odyssey_item_defs item
  where item.id = p_item_def_id;

  if not found then
    return public.odyssey_creator_error(
      'ITEM_DEF_NOT_FOUND',
      'Item definition was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown item definition id.'))
    );
  end if;

  select count(*)::integer
  into v_character_item_count
  from public.odyssey_character_items item
  where item.item_def_id = p_item_def_id;

  if v_character_item_count > 0 then
    v_details := v_details || jsonb_build_array(
      jsonb_build_object(
        'field', 'character_items',
        'count', v_character_item_count,
        'message', 'Item definition is assigned to one or more character inventory records.'
      )
    );
  end if;

  select count(*)::integer
  into v_reload_feature_count
  from public.odyssey_weapon_feature_defs feature
  where feature.requires_reload_item_code = v_item.code;

  if v_reload_feature_count > 0 then
    v_details := v_details || jsonb_build_array(
      jsonb_build_object(
        'field', 'requires_reload_item_code',
        'count', v_reload_feature_count,
        'message', 'Item definition is referenced by one or more weapon features as a reload item.'
      )
    );
  end if;

  select count(*)::integer
  into v_ability_resource_count
  from public.odyssey_ability_defs ability
  where ability.resource_item_code = v_item.code;

  if v_ability_resource_count > 0 then
    v_details := v_details || jsonb_build_array(
      jsonb_build_object(
        'field', 'resource_item_code',
        'count', v_ability_resource_count,
        'message', 'Item definition is referenced by one or more abilities as a resource item.'
      )
    );
  end if;

  if jsonb_array_length(v_details) > 0 then
    return public.odyssey_creator_error(
      'ITEM_DEF_IN_USE',
      'Item definition is still referenced and cannot be deleted.',
      v_details
    );
  end if;

  delete from public.odyssey_item_defs item
  where item.id = p_item_def_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_item_def_id,
    'deleted_code', v_item.code
  );
end;
$$;

grant execute on function public.creator_delete_item_def(uuid) to anon, authenticated;



alter table public.odyssey_perk_defs
  alter column description set default '';

alter table public.odyssey_perk_defs
  alter column required_skill_level set default 1;

alter table public.odyssey_perk_defs
  add column if not exists linked_skill_id uuid references public.odyssey_skill_defs(id) on delete set null,
  add column if not exists perk_type text not null default 'passive',
  add column if not exists activation_type text not null default 'passive',
  add column if not exists resolution_mode text not null default 'backend',
  add column if not exists is_enabled boolean not null default true;

update public.odyssey_perk_defs
set
  description = coalesce(description, ''),
  required_skill_level = greatest(coalesce(required_skill_level, 1), 1),
  linked_skill_id = coalesce(linked_skill_id, skill_def_id),
  perk_type = case
    when coalesce(lower(trim(perk_type)), '') in ('passive', 'active', 'narrative') then lower(trim(perk_type))
    when coalesce(lower(trim(effect_type)), '') in ('special_action', 'grant_reaction') then 'narrative'
    else 'passive'
  end,
  activation_type = case
    when coalesce(lower(trim(activation_type)), '') in ('passive', 'manual', 'reaction', 'scene_start') then lower(trim(activation_type))
    else case
      when coalesce(lower(trim(effect_type)), '') = 'grant_reaction' then 'reaction'
      else 'passive'
    end
  end,
  resolution_mode = case
    when coalesce(lower(trim(resolution_mode)), '') in ('backend', 'gm_resolved', 'hybrid') then lower(trim(resolution_mode))
    else 'backend'
  end,
  is_enabled = coalesce(is_enabled, true);

create or replace function public.odyssey_sync_perk_def_legacy_fields()
returns trigger
language plpgsql
as $$
begin
  if new.linked_skill_id is null and new.skill_def_id is not null then
    new.linked_skill_id := new.skill_def_id;
  elsif new.skill_def_id is null and new.linked_skill_id is not null then
    new.skill_def_id := new.linked_skill_id;
  elsif tg_op = 'INSERT' and new.linked_skill_id is not null then
    new.skill_def_id := new.linked_skill_id;
  elsif tg_op = 'UPDATE' and new.linked_skill_id is distinct from old.linked_skill_id then
    new.skill_def_id := new.linked_skill_id;
  elsif tg_op = 'UPDATE' and new.skill_def_id is distinct from old.skill_def_id then
    new.linked_skill_id := new.skill_def_id;
  end if;

  new.description := coalesce(new.description, '');
  new.required_skill_level := greatest(coalesce(new.required_skill_level, 1), 1);
  new.perk_type := case
    when coalesce(lower(trim(new.perk_type)), '') in ('passive', 'active', 'narrative') then lower(trim(new.perk_type))
    else 'passive'
  end;
  new.activation_type := case
    when coalesce(lower(trim(new.activation_type)), '') in ('passive', 'manual', 'reaction', 'scene_start') then lower(trim(new.activation_type))
    else 'passive'
  end;
  new.resolution_mode := case
    when coalesce(lower(trim(new.resolution_mode)), '') in ('backend', 'gm_resolved', 'hybrid') then lower(trim(new.resolution_mode))
    else 'backend'
  end;
  new.is_enabled := coalesce(new.is_enabled, true);

  return new;
end;
$$;

drop trigger if exists odyssey_sync_perk_def_legacy_fields on public.odyssey_perk_defs;
create trigger odyssey_sync_perk_def_legacy_fields
before insert or update on public.odyssey_perk_defs
for each row
execute function public.odyssey_sync_perk_def_legacy_fields();

do $$
begin
  if not exists (
    select 1
    from pg_constraint
    where conrelid = 'public.odyssey_perk_defs'::regclass
      and conname = 'odyssey_perk_defs_perk_type_check'
  ) then
    alter table public.odyssey_perk_defs
      add constraint odyssey_perk_defs_perk_type_check
      check (perk_type in ('passive', 'active', 'narrative'));
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conrelid = 'public.odyssey_perk_defs'::regclass
      and conname = 'odyssey_perk_defs_activation_type_check'
  ) then
    alter table public.odyssey_perk_defs
      add constraint odyssey_perk_defs_activation_type_check
      check (activation_type in ('passive', 'manual', 'reaction', 'scene_start'));
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conrelid = 'public.odyssey_perk_defs'::regclass
      and conname = 'odyssey_perk_defs_resolution_mode_check'
  ) then
    alter table public.odyssey_perk_defs
      add constraint odyssey_perk_defs_resolution_mode_check
      check (resolution_mode in ('backend', 'gm_resolved', 'hybrid'));
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conrelid = 'public.odyssey_perk_defs'::regclass
      and conname = 'odyssey_perk_defs_required_skill_level_check'
  ) then
    alter table public.odyssey_perk_defs
      add constraint odyssey_perk_defs_required_skill_level_check
      check (required_skill_level >= 1);
  end if;
end;
$$;

