create or replace function public.use_ability(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $
declare
  v_character_weapon_id uuid := public.odyssey_try_parse_uuid(p_payload->>'character_weapon_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(coalesce(p_payload->>'character_id', p_payload->>'attacker_character_id'));
  v_lock_state jsonb := '{}'::jsonb;
begin
  if v_character_weapon_id is not null and v_character_id is not null then
    v_lock_state := public.odyssey_get_weapon_lock_state(v_character_id, v_character_weapon_id);
    if coalesce((v_lock_state->>'locked')::boolean, false)
       or coalesce((v_lock_state->>'actor_attack_locked')::boolean, false) then
      return jsonb_build_object(
        'ok', false,
        'error', coalesce(v_lock_state->>'error', 'WEAPON_LOCKED'),
        'message', coalesce(v_lock_state->>'message', 'Weapon is locked.')
      );
    end if;
  end if;

  return public.odyssey_use_ability_legacy(p_payload);
end;
$;

create or replace function public.perform_attack(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_character_ability_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_ability_id');
  v_ability_code text := lower(trim(coalesce(v_payload->>'ability_code', '')));
  v_attacker_character_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'attacker_character_id', v_payload->>'character_id'));
  v_target_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'target_character_id');
  v_target_body_part_id uuid := public.odyssey_try_parse_uuid(v_payload->>'target_body_part_id');
  v_weapon_id uuid := public.odyssey_try_parse_uuid(v_payload->>'weapon_id');
  v_character_weapon_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'character_weapon_id', v_payload->>'weapon_id'));
  v_distance_m numeric := greatest(coalesce(nullif(trim(coalesce(v_payload->>'distance_m', '')), '')::numeric, 0), 0);
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_lock_state jsonb := '{}'::jsonb;
  v_perk_context_result jsonb := jsonb_build_object(
    'ok', true,
    'attack_accuracy_bonus', 0,
    'ammo_base_damage_multiplier', 1,
    'flags', '{}'::jsonb,
    'perk_modifiers', '[]'::jsonb,
    'consume_effect_ids', '[]'::jsonb
  );
  v_attack_context jsonb := '{}'::jsonb;
  v_existing_bonus integer := 0;
  v_perk_bonus integer := 0;
  v_result jsonb := '{}'::jsonb;
  v_retry_effect jsonb := jsonb_build_object('ok', true, 'applied', false);
  v_post_hooks jsonb := jsonb_build_object('ok', true);
  v_refresh_attacker boolean := false;
  v_target_alive_before boolean := true;
  v_target_alive_after boolean := true;
  v_target_movement_version integer := 0;
begin
  if v_target_character_id is not null then
    select coalesce(s.is_alive, true)
    into v_target_alive_before
    from public.odyssey_character_combat_state s
    where s.character_id = v_target_character_id;

    if v_encounter_id is not null then
      select coalesce(e.movement_version, 0)
      into v_target_movement_version
      from public.odyssey_initiative_entries e
      where e.encounter_id = v_encounter_id
        and e.character_id = v_target_character_id
        and e.is_active = true
      order by e.updated_at desc, e.id desc
      limit 1;
    end if;
  end if;

  if v_character_ability_id is not null or v_ability_code <> '' then
    if v_attacker_character_id is not null and v_character_weapon_id is not null then
      v_lock_state := public.odyssey_get_weapon_lock_state(v_attacker_character_id, v_character_weapon_id);
      if coalesce((v_lock_state->>'locked')::boolean, false)
         or coalesce((v_lock_state->>'actor_attack_locked')::boolean, false) then
        return jsonb_build_object(
          'ok', false,
          'error', coalesce(v_lock_state->>'error', 'WEAPON_LOCKED'),
          'message', coalesce(v_lock_state->>'message', 'Weapon is currently locked.'),
          'character_weapon_id', v_character_weapon_id
        );
      end if;
    end if;

    return public.odyssey_perform_ability_attack(v_payload);
  end if;

  if v_attacker_character_id is not null and v_character_weapon_id is not null then
    v_lock_state := public.odyssey_get_weapon_lock_state(v_attacker_character_id, v_character_weapon_id);
    if coalesce((v_lock_state->>'locked')::boolean, false)
       or coalesce((v_lock_state->>'actor_attack_locked')::boolean, false) then
      return jsonb_build_object(
        'ok', false,
        'error', coalesce(v_lock_state->>'error', 'WEAPON_LOCKED'),
        'message', coalesce(v_lock_state->>'message', 'Weapon is currently locked.'),
        'character_weapon_id', v_character_weapon_id
      );
    end if;

    v_perk_context_result := public.odyssey_get_character_attack_perk_context(
      v_attacker_character_id,
      v_character_weapon_id,
      v_target_character_id,
      v_target_body_part_id,
      v_distance_m,
      nullif(trim(coalesce(v_payload->>'fire_mode_code', '')), ''),
      nullif(trim(coalesce(v_payload->>'attack_type', '')), ''),
      v_encounter_id
    );

    if coalesce((v_perk_context_result->>'ok')::boolean, false) = false then
      return v_perk_context_result;
    end if;
  end if;

  v_attack_context := case
    when jsonb_typeof(v_payload->'attack_context') = 'object' then v_payload->'attack_context'
    else '{}'::jsonb
  end;
  v_existing_bonus := coalesce(nullif(trim(coalesce(v_attack_context->>'manual_attack_bonus', '')), '')::integer, 0);
  v_perk_bonus := coalesce(nullif(trim(coalesce(v_perk_context_result->>'attack_accuracy_bonus', '')), '')::integer, 0);

  if v_perk_bonus <> 0 then
    v_attack_context := v_attack_context || jsonb_build_object('manual_attack_bonus', v_existing_bonus + v_perk_bonus);
    v_payload := v_payload || jsonb_build_object('attack_context', v_attack_context);
  end if;

  v_payload := v_payload || jsonb_build_object('perk_context', v_perk_context_result - 'ok');
  v_result := public.odyssey_perform_weapon_attack(v_payload);

  if coalesce((v_result->>'ok')::boolean, false) = true then
    if jsonb_array_length(coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb)) > 0 then
      update public.odyssey_character_effects e
      set
        is_active = false,
        rounds_left = 0,
        updated_at = timezone('utc', now())
      where e.character_id = v_attacker_character_id
        and e.id in (
          select public.odyssey_try_parse_uuid(value)
          from jsonb_array_elements_text(coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb)) value
        );
      v_refresh_attacker := true;
    end if;

    if v_target_character_id is not null then
      v_target_alive_after := coalesce(
        nullif(v_result#>>'{target_state,is_alive}', '')::boolean,
        nullif(v_result#>>'{target_state,combat_state,is_alive}', '')::boolean,
        v_target_alive_before
      );
    end if;

    v_post_hooks := public.odyssey_apply_perk_post_attack_hooks(
      jsonb_build_object(
        'attacker_character_id', v_attacker_character_id,
        'character_weapon_id', v_character_weapon_id,
        'target_character_id', v_target_character_id,
        'target_movement_version', v_target_movement_version,
        'created_by', coalesce(v_payload->>'actor_token_id', ''),
        'hit', coalesce(v_result->>'hit', 'false'),
        'target_alive_before', v_target_alive_before,
        'target_alive_after', v_target_alive_after
      )
    );

    if not coalesce((v_result->>'hit')::boolean, false) then
      v_retry_effect := public.odyssey_grant_first_time_no_retry_effect(
        v_attacker_character_id,
        v_character_weapon_id,
        v_target_character_id,
        v_target_movement_version,
        coalesce(v_payload->>'actor_token_id', '')
      );
      if coalesce((v_retry_effect->>'applied')::boolean, false) = true then
        v_refresh_attacker := true;
      end if;
    end if;

    if v_refresh_attacker and v_attacker_character_id is not null then
      v_result := v_result || jsonb_build_object(
        'attacker_state',
        coalesce(public.odyssey_refresh_character_combat_state(v_attacker_character_id)->'combat_state', '{}'::jsonb),
        'post_attack_perks',
          jsonb_build_object(
            'consumed_effect_ids', coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb),
            'retry_effect', v_retry_effect,
            'post_hooks', v_post_hooks
          )
      );
    else
      v_result := v_result || jsonb_build_object(
        'post_attack_perks',
          jsonb_build_object(
            'consumed_effect_ids', coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb),
            'retry_effect', v_retry_effect,
            'post_hooks', v_post_hooks
          )
      );
    end if;

    return public.odyssey_finalize_attack_result(v_result, v_target_character_id, v_target_body_part_id);
  end if;

  return v_result;
end;
$;

grant execute on function public.get_effective_character_stats(uuid) to anon, authenticated;
grant execute on function public.odyssey_get_weapon_runtime_context(uuid) to anon, authenticated;
grant execute on function public.odyssey_get_weapon_lock_state(uuid, uuid) to anon, authenticated;
grant execute on function public.odyssey_get_character_attack_perk_context(uuid, uuid, uuid, uuid, numeric, text, text, uuid) to anon, authenticated;
grant execute on function public.odyssey_grant_first_time_no_retry_effect(uuid, uuid, uuid, integer, text) to anon, authenticated;
grant execute on function public.odyssey_apply_perk_post_attack_hooks(jsonb) to anon, authenticated;
grant execute on function public.use_character_perk(jsonb) to anon, authenticated;
grant execute on function public.activate_weapon_feature(jsonb) to anon, authenticated;
grant execute on function public.use_ability(jsonb) to anon, authenticated;
grant execute on function public.perform_attack(jsonb) to anon, authenticated;
grant execute on function public.get_character_armory(uuid) to anon, authenticated;
grant execute on function public.get_character_runtime_bundle(jsonb) to anon, authenticated;
-- ===== END 65_perk_combat_automation_and_weapon_locks.sql =====

-- ===== BEGIN 69_fix_body_part_defaults_and_remove_duplicates.sql =====
do $$
declare
  v_fk record;
  v_character_id uuid;
  v_rows integer := 0;
  v_affected_characters integer := 0;
  v_merged_duplicate_body_parts integer := 0;
  v_relinked_equipment_items integer := 0;
  v_removed_empty_shield_slots integer := 0;
  v_removed_empty_special_slots integer := 0;
  v_characters_skipped_due_to_real_equipment integer := 0;
begin
  create temp table tmp_odyssey_body_part_fk_columns (
    schema_name text not null,
    table_name text not null,
    column_name text not null
  ) on commit drop;

  insert into tmp_odyssey_body_part_fk_columns (
    schema_name,
    table_name,
    column_name
  )
  select
    ns.nspname as schema_name,
    cls.relname as table_name,
    att.attname as column_name
  from pg_constraint con
  join pg_class cls
    on cls.oid = con.conrelid
  join pg_namespace ns
    on ns.oid = cls.relnamespace
  join lateral unnest(con.conkey) with ordinality as child_key(attnum, ord)
    on true
  join lateral unnest(con.confkey) with ordinality as parent_key(attnum, ord)
    on parent_key.ord = child_key.ord
  join pg_attribute att
    on att.attrelid = con.conrelid
   and att.attnum = child_key.attnum
  where con.contype = 'f'
    and con.confrelid = 'public.odyssey_character_body_parts'::regclass
    and array_length(con.conkey, 1) = 1
    and array_length(con.confkey, 1) = 1;

  create temp table tmp_odyssey_body_part_refcounts (
    body_part_id uuid primary key,
    refcount bigint not null default 0
  ) on commit drop;

  for v_fk in
    select *
    from tmp_odyssey_body_part_fk_columns
  loop
    execute format(
      'insert into tmp_odyssey_body_part_refcounts (body_part_id, refcount)
       select t.%1$I as body_part_id, count(*)::bigint as refcount
       from %2$I.%3$I t
       where t.%1$I is not null
       group by t.%1$I
       on conflict (body_part_id) do update
       set refcount = tmp_odyssey_body_part_refcounts.refcount + excluded.refcount',
      v_fk.column_name,
      v_fk.schema_name,
      v_fk.table_name
    );
  end loop;

  create temp table tmp_odyssey_body_part_ranked on commit drop as
  with body_part_rows as (
    select
      b.id,
      b.character_id,
      b.body_part_def_id,
      b.custom_name,
      b.part_key,
      b.max_critical,
      b.critical,
      b.serious,
      b.minor,
      b.disabled,
      b.destroyed,
      coalesce(b.natural_armor_value, 0) as natural_armor_value,
      coalesce(b.notes, '') as notes,
      b.sort_order,
      b.created_at,
      d.code as def_code,
      coalesce((
        select count(*)::integer
        from public.odyssey_character_equipment_items e
        where e.equipped_body_part_id = b.id
      ), 0) as equipment_ref_count,
      coalesce(refs.refcount, 0) as any_ref_count,
      case
        when lower(trim(coalesce(b.part_key, ''))) = lower(trim(coalesce(d.code, ''))) then 1
        else 0
      end as exact_code_match,
      case
        when public.odyssey_resolve_body_part_code(b.part_key, d.code) = d.code then 1
        else 0
      end as normalized_code_match,
      case
        when coalesce(b.minor, 0) > 0
          or coalesce(b.serious, 0) > 0
          or coalesce(b.critical, 0) > 0
          or coalesce(b.natural_armor_value, 0) > 0
          or coalesce(b.disabled, false)
          or coalesce(b.destroyed, false)
          or nullif(trim(coalesce(b.notes, '')), '') is not null
        then 1
        else 0
      end as has_state
    from public.odyssey_character_body_parts b
    join public.odyssey_body_part_defs d
      on d.id = b.body_part_def_id
    left join tmp_odyssey_body_part_refcounts refs
      on refs.body_part_id = b.id
    where b.body_part_def_id is not null
  )
  select
    body_part_rows.*,
    count(*) over (
      partition by body_part_rows.character_id, body_part_rows.body_part_def_id
    ) as duplicate_count,
    row_number() over (
      partition by body_part_rows.character_id, body_part_rows.body_part_def_id
      order by
        body_part_rows.exact_code_match desc,
        body_part_rows.normalized_code_match desc,
        body_part_rows.equipment_ref_count desc,
        body_part_rows.any_ref_count desc,
        body_part_rows.has_state desc,
        body_part_rows.created_at asc,
        body_part_rows.id asc
    ) as duplicate_rank
  from body_part_rows;

  create temp table tmp_odyssey_body_part_relink on commit drop as
  select
    dup.character_id,
    dup.body_part_def_id,
    dup.id as duplicate_id,
    canon.id as canonical_id
  from tmp_odyssey_body_part_ranked dup
  join tmp_odyssey_body_part_ranked canon
    on canon.character_id = dup.character_id
   and canon.body_part_def_id = dup.body_part_def_id
   and canon.duplicate_rank = 1
  where dup.duplicate_count > 1
    and dup.duplicate_rank > 1;

  create temp table tmp_odyssey_body_part_merge on commit drop as
  select
    canon.character_id,
    canon.body_part_def_id,
    canon.id as canonical_id,
    canon.def_code,
    min(all_rows.sort_order)::integer as merged_sort_order,
    max(coalesce(all_rows.max_critical, 0))::integer as merged_max_critical,
    max(coalesce(all_rows.critical, 0))::integer as merged_critical,
    max(coalesce(all_rows.serious, 0))::integer as merged_serious,
    max(coalesce(all_rows.minor, 0))::integer as merged_minor,
    bool_or(coalesce(all_rows.disabled, false)) as merged_disabled,
    bool_or(coalesce(all_rows.destroyed, false)) as merged_destroyed,
    max(coalesce(all_rows.natural_armor_value, 0))::integer as merged_natural_armor_value,
    coalesce(
      min(nullif(trim(coalesce(all_rows.notes, '')), ''))
        filter (where nullif(trim(coalesce(all_rows.notes, '')), '') is not null),
      ''
    ) as merged_notes,
    coalesce(
      min(nullif(trim(coalesce(all_rows.custom_name, '')), ''))
        filter (where nullif(trim(coalesce(all_rows.custom_name, '')), '') is not null),
      ''
    ) as merged_custom_name
  from tmp_odyssey_body_part_ranked canon
  join tmp_odyssey_body_part_ranked all_rows
    on all_rows.character_id = canon.character_id
   and all_rows.body_part_def_id = canon.body_part_def_id
  where canon.duplicate_count > 1
    and canon.duplicate_rank = 1
  group by
    canon.character_id,
    canon.body_part_def_id,
    canon.id,
    canon.def_code;

  create temp table tmp_odyssey_affected_characters (
    character_id uuid primary key
  ) on commit drop;

  update public.odyssey_character_body_parts b
  set
    part_key = merge_rows.def_code,
    max_critical = greatest(coalesce(merge_rows.merged_max_critical, 0), 0),
    critical = greatest(coalesce(merge_rows.merged_critical, 0), 0),
    serious = greatest(coalesce(merge_rows.merged_serious, 0), 0),
    minor = greatest(coalesce(merge_rows.merged_minor, 0), 0),
    disabled = coalesce(merge_rows.merged_disabled, false),
    destroyed = coalesce(merge_rows.merged_destroyed, false),
    natural_armor_value = greatest(coalesce(merge_rows.merged_natural_armor_value, 0), 0),
    sort_order = coalesce(merge_rows.merged_sort_order, b.sort_order),
    custom_name = case
      when nullif(trim(coalesce(b.custom_name, '')), '') is not null then b.custom_name
      when nullif(trim(coalesce(merge_rows.merged_custom_name, '')), '') is not null then merge_rows.merged_custom_name
      else b.custom_name
    end,
    notes = case
      when nullif(trim(coalesce(b.notes, '')), '') is not null then b.notes
      when nullif(trim(coalesce(merge_rows.merged_notes, '')), '') is not null then merge_rows.merged_notes
      else ''
    end,
    updated_at = timezone('utc', now())
  from tmp_odyssey_body_part_merge merge_rows
  where b.id = merge_rows.canonical_id;

  insert into tmp_odyssey_affected_characters (character_id)
  select distinct character_id
  from tmp_odyssey_body_part_merge
  on conflict (character_id) do nothing;

  for v_fk in
    select *
    from tmp_odyssey_body_part_fk_columns
  loop
    execute format(
      'update %1$I.%2$I target
       set %3$I = map.canonical_id
       from tmp_odyssey_body_part_relink map
       where target.%3$I = map.duplicate_id
         and target.%3$I is distinct from map.canonical_id',
      v_fk.schema_name,
      v_fk.table_name,
      v_fk.column_name
    );
    get diagnostics v_rows = row_count;
    v_relinked_equipment_items := v_relinked_equipment_items + v_rows;
  end loop;

  delete from public.odyssey_character_body_parts body_part
  using tmp_odyssey_body_part_relink relink
  where body_part.id = relink.duplicate_id;
  get diagnostics v_merged_duplicate_body_parts = row_count;

  with normalized_rows as (
    update public.odyssey_character_body_parts b
    set
      part_key = d.code,
      sort_order = d.sort_order,
      updated_at = timezone('utc', now())
    from public.odyssey_body_part_defs d
    where d.id = b.body_part_def_id
      and d.is_custom = false
      and d.code not in ('shield', 'special')
      and public.odyssey_resolve_body_part_code(b.part_key, d.code) = d.code
      and b.part_key is distinct from d.code
      and not exists (
        select 1
        from public.odyssey_character_body_parts existing_part
        where existing_part.character_id = b.character_id
          and existing_part.id <> b.id
          and existing_part.part_key = d.code
      )
    returning b.character_id
  )
  insert into tmp_odyssey_affected_characters (character_id)
  select distinct character_id
  from normalized_rows
  on conflict (character_id) do nothing;

  truncate table tmp_odyssey_body_part_refcounts;

  for v_fk in
    select *
    from tmp_odyssey_body_part_fk_columns
  loop
    execute format(
      'insert into tmp_odyssey_body_part_refcounts (body_part_id, refcount)
       select t.%1$I as body_part_id, count(*)::bigint as refcount
       from %2$I.%3$I t
       where t.%1$I is not null
       group by t.%1$I
       on conflict (body_part_id) do update
       set refcount = tmp_odyssey_body_part_refcounts.refcount + excluded.refcount',
      v_fk.column_name,
      v_fk.schema_name,
      v_fk.table_name
    );
  end loop;

  create temp table tmp_odyssey_placeholder_candidates on commit drop as
  select
    b.id,
    b.character_id,
    d.code
  from public.odyssey_character_body_parts b
  join public.odyssey_body_part_defs d
    on d.id = b.body_part_def_id
  left join tmp_odyssey_body_part_refcounts refs
    on refs.body_part_id = b.id
  where d.code in ('shield', 'special')
    and coalesce(refs.refcount, 0) = 0
    and coalesce(b.natural_armor_value, 0) = 0
    and coalesce(b.armor_value, 0) = 0
    and coalesce(b.minor, 0) = 0
    and coalesce(b.serious, 0) = 0
    and coalesce(b.critical, 0) = 0
    and coalesce(b.armor_critical, 0) = 0
    and coalesce(b.armor_max_critical, 0) = 0
    and coalesce(b.armor_destroyed, false) = false
    and coalesce(b.disabled, false) = false
    and coalesce(b.destroyed, false) = false
    and nullif(trim(coalesce(b.notes, '')), '') is null
    and nullif(trim(coalesce(b.custom_name, '')), '') is null;

  insert into tmp_odyssey_affected_characters (character_id)
  select distinct character_id
  from tmp_odyssey_placeholder_candidates
  on conflict (character_id) do nothing;

  select
    count(distinct b.character_id)
  into v_characters_skipped_due_to_real_equipment
  from public.odyssey_character_body_parts b
  join public.odyssey_body_part_defs d
    on d.id = b.body_part_def_id
  left join tmp_odyssey_body_part_refcounts refs
    on refs.body_part_id = b.id
  where d.code in ('shield', 'special')
    and coalesce(refs.refcount, 0) > 0;

  delete from public.odyssey_character_body_parts body_part
  using tmp_odyssey_placeholder_candidates candidate
  where body_part.id = candidate.id
    and candidate.code = 'shield';
  get diagnostics v_removed_empty_shield_slots = row_count;

  delete from public.odyssey_character_body_parts body_part
  using tmp_odyssey_placeholder_candidates candidate
  where body_part.id = candidate.id
    and candidate.code = 'special';
  get diagnostics v_removed_empty_special_slots = row_count;

  for v_character_id in
    select character_id
    from tmp_odyssey_affected_characters
    order by character_id
  loop
    perform public.recompute_character_armor(v_character_id);
    perform public.odyssey_refresh_character_combat_state(v_character_id);
    v_affected_characters := v_affected_characters + 1;
  end loop;

  raise notice 'affected_characters=%', v_affected_characters;
  raise notice 'merged_duplicate_body_parts=%', v_merged_duplicate_body_parts;
  raise notice 'relinked_equipment_items=%', v_relinked_equipment_items;
  raise notice 'removed_empty_shield_slots=%', v_removed_empty_shield_slots;
  raise notice 'removed_empty_special_slots=%', v_removed_empty_special_slots;
  raise notice 'characters_skipped_due_to_real_equipment=%', v_characters_skipped_due_to_real_equipment;
end;
$$;
-- ===== END 69_fix_body_part_defaults_and_remove_duplicates.sql =====


-- ===== BEGIN 73_body_part_slot_normalization_fix.sql =====
create or replace function public.odyssey_normalize_body_part_slot_code(
  p_value text
)
returns text
language sql
immutable
as $$
  select case public.odyssey_normalize_part_code(p_value)
    when 'arm_l' then 'l_arm'
    when 'arm_r' then 'r_arm'
    when 'leg_l' then 'l_leg'
    when 'leg_r' then 'r_leg'
    when 'left_arm' then 'l_arm'
    when 'right_arm' then 'r_arm'
    when 'left_leg' then 'l_leg'
    when 'right_leg' then 'r_leg'
    when 'leftarm' then 'l_arm'
    when 'rightarm' then 'r_arm'
    when 'leftleg' then 'l_leg'
    when 'rightleg' then 'r_leg'
    when 'larm' then 'l_arm'
    when 'rarm' then 'r_arm'
    when 'lleg' then 'l_leg'
    when 'rleg' then 'r_leg'
    else public.odyssey_normalize_part_code(p_value)
  end;
$$;

grant execute on function public.odyssey_normalize_body_part_slot_code(text) to anon, authenticated;

create or replace function public.equip_character_equipment_item(
  p_item_id uuid,
  p_body_part_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_item public.odyssey_character_equipment_items%rowtype;
  v_model public.odyssey_equipment_model_defs%rowtype;
  v_body_part record;
  v_allowed_codes text[] := '{}'::text[];
  v_effective_part_code text := '';
  v_refresh jsonb := '{}'::jsonb;
  v_is_armor_protection boolean := false;
  v_existing_equipped record;
  v_default_body_part_code text := '';
begin
  select *
  into v_item
  from public.odyssey_character_equipment_items e
  where e.id = p_item_id
  for update of e;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'EQUIPMENT_ITEM_NOT_FOUND',
      'item_id', p_item_id
    );
  end if;

  select *
  into v_model
  from public.odyssey_equipment_model_defs m
  where m.id = v_item.equipment_model_id;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'EQUIPMENT_MODEL_NOT_FOUND',
      'item_id', p_item_id
    );
  end if;

  select
    b.id,
    b.character_id,
    b.part_key,
    public.odyssey_resolve_body_part_code(b.part_key, d.code) as part_code
  into v_body_part
  from public.odyssey_character_body_parts b
  left join public.odyssey_body_part_defs d on d.id = b.body_part_def_id
  where b.id = p_body_part_id
  for update of b;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'BODY_PART_NOT_FOUND',
      'body_part_id', p_body_part_id
    );
  end if;

  if v_body_part.character_id <> v_item.character_id then
    return jsonb_build_object(
      'ok', false,
      'error', 'BODY_PART_CHARACTER_MISMATCH',
      'item_id', p_item_id,
      'body_part_id', p_body_part_id
    );
  end if;

  if not coalesce(v_model.can_equip, true) then
    return jsonb_build_object(
      'ok', false,
      'error', 'ITEM_CANNOT_BE_EQUIPPED',
      'item_id', p_item_id,
      'equipment_model_code', v_model.code
    );
  end if;

  if not coalesce(v_model.can_equip_to_body_part, true) then
    return jsonb_build_object(
      'ok', false,
      'error', 'ITEM_CANNOT_EQUIP_TO_BODY_PART',
      'item_id', p_item_id,
      'equipment_model_code', v_model.code
    );
  end if;

  v_effective_part_code := public.odyssey_normalize_body_part_slot_code(v_body_part.part_code);
  v_default_body_part_code := public.odyssey_normalize_body_part_slot_code(v_model.default_body_part_code);

  if jsonb_typeof(v_model.flags->'allowed_body_part_codes') = 'array' then
    select coalesce(
      array_agg(
        distinct public.odyssey_normalize_body_part_slot_code(body_code.value)
      ) filter (where public.odyssey_normalize_body_part_slot_code(body_code.value) <> ''),
      '{}'::text[]
    )
    into v_allowed_codes
    from jsonb_array_elements_text(v_model.flags->'allowed_body_part_codes') as body_code(value);
  end if;

  if coalesce(array_length(v_allowed_codes, 1), 0) > 0 then
    if not (v_effective_part_code = any (v_allowed_codes)) then
      return jsonb_build_object(
        'ok', false,
        'error', 'BODY_PART_NOT_ALLOWED',
        'item_id', p_item_id,
        'equipment_model_code', v_model.code,
        'body_part_code', v_effective_part_code,
        'allowed_body_part_codes', to_jsonb(v_allowed_codes)
      );
    end if;
  elsif v_default_body_part_code <> '' then
    if v_default_body_part_code <> v_effective_part_code then
      return jsonb_build_object(
        'ok', false,
        'error', 'BODY_PART_NOT_ALLOWED',
        'item_id', p_item_id,
        'equipment_model_code', v_model.code,
        'body_part_code', v_effective_part_code,
        'default_body_part_code', v_default_body_part_code
      );
    end if;
  end if;

  v_is_armor_protection := lower(trim(coalesce(v_model.item_type, ''))) in (
    'armor',
    'shield',
    'special_protection'
  );

  if v_is_armor_protection then
    select
      e.id,
      coalesce(nullif(trim(e.custom_name), ''), occupied_model.name) as item_name
    into v_existing_equipped
    from public.odyssey_character_equipment_items e
    join public.odyssey_equipment_model_defs occupied_model on occupied_model.id = e.equipment_model_id
    where e.character_id = v_item.character_id
      and e.is_equipped = true
      and e.equipped_body_part_id = p_body_part_id
      and e.id <> p_item_id
      and lower(trim(coalesce(occupied_model.item_type, ''))) in (
        'armor',
        'shield',
        'special_protection'
      )
    order by e.updated_at desc nulls last, e.created_at desc, e.id
    for update of e
    limit 1;

    if found then
      return jsonb_build_object(
        'ok', false,
        'error', 'BODY_PART_ARMOR_SLOT_OCCUPIED',
        'message', 'This body part already has an equipped armor item.',
        'body_part_id', p_body_part_id,
        'body_part_code', v_effective_part_code,
        'equipped_item',
          jsonb_build_object(
            'id', v_existing_equipped.id,
            'name', v_existing_equipped.item_name
          )
      );
    end if;
  end if;

  update public.odyssey_character_equipment_items
  set
    is_equipped = true,
    equipped_body_part_id = p_body_part_id,
    updated_at = timezone('utc', now())
  where id = p_item_id;

  perform public.recompute_character_armor(v_item.character_id);
  v_refresh := public.odyssey_refresh_character_combat_state(v_item.character_id);

  return jsonb_build_object(
    'ok', true,
    'item', public.odyssey_get_equipment_item_json(p_item_id),
    'armor_summary', public.get_character_armor_summary(v_item.character_id),
    'combat_state', coalesce(v_refresh->'combat_state', '{}'::jsonb)
  );
end;
$$;

grant execute on function public.equip_character_equipment_item(uuid, uuid) to anon, authenticated;
-- ===== END 73_body_part_slot_normalization_fix.sql =====


-- ===== BEGIN 76_runtime_bundle_refactor_and_equipment_metadata.sql =====
-- Goal:
--   1) Keep ONE public RPC: public.get_character_runtime_bundle(jsonb)
--   2) Rename the old legacy implementation to an internal helper
--   3) Enrich sections.equipment with the model metadata required by Character Screen
--
-- IMPORTANT:
--   This preserves combat_session behavior in get_character_runtime_bundle.
--   It intentionally keeps one internal helper; physically inlining a ~25k-character
--   implementation into the public function brings no meaningful performance benefit.

begin;

do $migration$
declare
  v_public_sql text;
  v_anchor text := E'\n  if v_campaign_id = \'\' then';
  v_injection text := $inject$

  -- Equipment UI needs model metadata to determine compatible body parts.
  -- Keep the base bundle data, then overlay canonical model fields.
  if jsonb_typeof(v_bundle #> '{sections,equipment}') = 'array' then
    select jsonb_set(
      v_bundle,
      '{sections,equipment}',
      coalesce(
        jsonb_agg(
          existing.item
          || jsonb_build_object(
            'can_equip', coalesce(model.can_equip, true),
            'can_equip_to_body_part', coalesce(model.can_equip_to_body_part, true),
            'default_body_part_code', model.default_body_part_code,
            'flags', coalesce(to_jsonb(model.flags), '{}'::jsonb),
            'tags', coalesce(to_jsonb(model.tags), '[]'::jsonb),
            'effect_data', coalesce(to_jsonb(model.effect_data), '{}'::jsonb),
            'model', jsonb_build_object(
              'id', model.id,
              'code', model.code,
              'name', model.name,
              'item_type', model.item_type,
              'description', coalesce(model.description, ''),
              'can_equip', coalesce(model.can_equip, true),
              'can_equip_to_body_part', coalesce(model.can_equip_to_body_part, true),
              'default_body_part_code', model.default_body_part_code,
              'flags', coalesce(to_jsonb(model.flags), '{}'::jsonb),
              'tags', coalesce(to_jsonb(model.tags), '[]'::jsonb),
              'effect_data', coalesce(to_jsonb(model.effect_data), '{}'::jsonb)
            )
          )
          order by existing.ordinality
        ),
        '[]'::jsonb
      ),
      true
    )
    into v_bundle
    from jsonb_array_elements(v_bundle #> '{sections,equipment}')
      with ordinality as existing(item, ordinality)
    left join public.odyssey_equipment_model_defs model
      on model.id = public.odyssey_try_parse_uuid(existing.item->>'equipment_model_id');
  end if;

$inject$;
begin
  if to_regprocedure('public.get_character_runtime_bundle(jsonb)') is null then
    raise exception 'Missing public.get_character_runtime_bundle(jsonb)';
  end if;

  if to_regprocedure('public.odyssey_get_character_runtime_bundle_legacy(jsonb)') is null
     and to_regprocedure('public.odyssey_build_character_runtime_sections(jsonb)') is null then
    raise exception 'Missing runtime-bundle implementation function';
  end if;

  select pg_get_functiondef('public.get_character_runtime_bundle(jsonb)'::regprocedure)
    into v_public_sql;

  v_public_sql := replace(v_public_sql, E'\r\n', E'\n');

  if to_regprocedure('public.odyssey_get_character_runtime_bundle_legacy(jsonb)') is not null then
    alter function public.odyssey_get_character_runtime_bundle_legacy(jsonb)
      rename to odyssey_build_character_runtime_sections;
  end if;

  v_public_sql := replace(
    v_public_sql,
    'public.odyssey_get_character_runtime_bundle_legacy(',
    'public.odyssey_build_character_runtime_sections('
  );
  v_public_sql := replace(
    v_public_sql,
    'odyssey_get_character_runtime_bundle_legacy(',
    'odyssey_build_character_runtime_sections('
  );

  if position('Equipment UI needs model metadata' in v_public_sql) = 0 then
    if position(v_anchor in v_public_sql) = 0 then
      raise exception 'Could not find the expected insertion point in get_character_runtime_bundle';
    end if;

    v_public_sql := replace(v_public_sql, v_anchor, v_injection || v_anchor);
  end if;

  execute v_public_sql;
end
$migration$;

do $verify$
declare
  v_sql text;
begin
  if to_regprocedure('public.odyssey_get_character_runtime_bundle_legacy(jsonb)') is not null then
    raise exception 'Legacy runtime-bundle function still exists';
  end if;

  select pg_get_functiondef('public.get_character_runtime_bundle(jsonb)'::regprocedure)
    into v_sql;

  if position('odyssey_build_character_runtime_sections' in v_sql) = 0 then
    raise exception 'Public runtime bundle does not call the internal sections helper';
  end if;

  if position('Equipment UI needs model metadata' in v_sql) = 0 then
    raise exception 'Equipment metadata enrichment was not added';
  end if;
end
$verify$;

commit;

-- Manual verification after applying:
-- select jsonb_pretty(
--   public.get_character_runtime_bundle(
--     jsonb_build_object(
--       'character_id', '918f214a-1dfa-4aa2-9c62-cdefdeb8285c',
--       'sections', jsonb_build_array('combat', 'equipment')
--     )
--   ) #> '{sections,equipment}'
-- );
-- ===== END 76_runtime_bundle_refactor_and_equipment_metadata.sql =====


-- ===== BEGIN 77_effective_skill_satisfies_penalty_requirements_v2.sql =====
-- Replaces migration 77 that failed due to a whitespace-sensitive text substitution.
--
-- Rule:
-- Any active effect that grants an effective skill level may satisfy a skill-gated
-- penalty requirement. This includes equipment, implants, prosthetics, abilities,
-- and other active character effects represented by the normal effect engine.
--
-- Current use:
-- get_character_armor_summary() uses this rule for armor training requirements.

begin;

create or replace function public.odyssey_character_has_effective_skill(
  p_character_id uuid,
  p_skill_code text,
  p_minimum_level integer default 1
)
returns boolean
language sql
stable
as $function$
  select exists (
    select 1
    from public.odyssey_get_effective_character_skill_states(p_character_id) skill
    where skill.skill_code = lower(trim(coalesce(p_skill_code, '')))
      and coalesce(skill.effective_level, 0) >= greatest(coalesce(p_minimum_level, 1), 1)
  );
$function$;

create or replace function public.get_character_armor_summary(p_character_id uuid)
returns jsonb
language plpgsql
stable
as $function$
declare
  v_character_exists boolean := false;
  v_total_equipped_armor_value integer := 0;
  v_class_def jsonb := '{}'::jsonb;
  v_required_skill_code text := null;
  v_has_required_skill boolean := false;
  v_penalty_profile text := 'none';
  v_penalty_profile_data jsonb := '{}'::jsonb;
  v_penalty_effect_data jsonb := '{}'::jsonb;
  v_head_protected boolean := false;
  v_torso_protected boolean := false;
  v_special_protection boolean := false;
  v_helpless_execution_protected boolean := false;
begin
  select exists(
    select 1
    from public.odyssey_characters c
    where c.id = p_character_id
      and coalesce(c.is_deleted, false) = false
  )
  into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'character_id', p_character_id
    );
  end if;

  select coalesce(sum(coalesce(e.armor_value, 0)), 0)
  into v_total_equipped_armor_value
  from public.odyssey_character_equipment_items e
  where e.character_id = p_character_id
    and e.is_equipped = true
    and e.equipped_body_part_id is not null;

  v_class_def := public.odyssey_get_armor_class_definition(v_total_equipped_armor_value);
  v_required_skill_code := nullif(trim(coalesce(v_class_def->>'required_skill_code', '')), '');

  -- Migration 77:
  -- Use the authoritative effective level, not only permanent rows in
  -- odyssey_character_skills. Therefore any active item/implant/prosthetic/effect
  -- that grants the required passive skill can satisfy the armor requirement.
  if v_required_skill_code is not null then
    v_has_required_skill := public.odyssey_character_has_effective_skill(
      p_character_id,
      v_required_skill_code,
      1
    );
  else
    v_has_required_skill := true;
  end if;

  if coalesce(v_class_def->>'code', 'none') = 'none' then
    v_penalty_profile := 'none';
    v_penalty_profile_data := '{}'::jsonb;
  elsif v_has_required_skill then
    v_penalty_profile := 'trained';
    v_penalty_profile_data := coalesce(v_class_def->'trained_penalties', '{}'::jsonb);
  else
    v_penalty_profile := 'untrained';
    v_penalty_profile_data := coalesce(v_class_def->'untrained_penalties', '{}'::jsonb);
  end if;

  v_penalty_effect_data := public.odyssey_build_armor_penalty_effect_data(v_penalty_profile_data);

  with equipped_items as (
    select
      case
        when jsonb_typeof(e.data->'flags') = 'object'
          then coalesce(m.flags, '{}'::jsonb) || (e.data->'flags')
        else coalesce(m.flags, '{}'::jsonb)
      end as effective_flags,
      public.odyssey_resolve_body_part_code(b.part_key, d.code) as body_part_code
    from public.odyssey_character_equipment_items e
    join public.odyssey_equipment_model_defs m on m.id = e.equipment_model_id
    join public.odyssey_character_body_parts b on b.id = e.equipped_body_part_id
    left join public.odyssey_body_part_defs d on d.id = b.body_part_def_id
    where e.character_id = p_character_id
      and e.is_equipped = true
      and e.equipped_body_part_id is not null
  )
  select
    coalesce(bool_or(body_part_code = 'head'), false),
    coalesce(bool_or(body_part_code = 'torso'), false),
    coalesce(
      bool_or(
        lower(coalesce(effective_flags->>'protects_helpless_execution', 'false'))
          in ('true', '1', 'yes', 'on')
      ),
      false
    )
  into
    v_head_protected,
    v_torso_protected,
    v_special_protection
  from equipped_items;

  v_helpless_execution_protected :=
    coalesce(v_class_def->>'code', 'none') in ('medium', 'heavy', 'superheavy')
    and (
      (v_head_protected and v_torso_protected)
      or v_special_protection
    );

  return jsonb_build_object(
    'ok', true,
    'character_id', p_character_id,
    'total_equipped_armor_value', v_total_equipped_armor_value,
    'armor_class', coalesce(v_class_def->>'code', 'none'),
    'required_skill_code', v_required_skill_code,
    'has_required_skill', v_has_required_skill,
    'penalty_profile', v_penalty_profile,
    'head_protected', v_head_protected,
    'torso_protected', v_torso_protected,
    'special_protection', v_special_protection,
    'helpless_execution_protected', v_helpless_execution_protected,
    'penalty_effect_data', v_penalty_effect_data,
    'class_definition', v_class_def
  );
end;
$function$;

-- Rebuild existing armor penalty effects immediately.
do $refresh$
declare
  v_character record;
begin
  for v_character in
    select c.id
    from public.odyssey_characters c
    where coalesce(c.is_deleted, false) = false
      and (
        exists (
          select 1
          from public.odyssey_character_equipment_items e
          where e.character_id = c.id
            and e.is_equipped = true
        )
        or exists (
          select 1
          from public.odyssey_character_effects effect_row
          where effect_row.character_id = c.id
            and effect_row.effect_key = 'armor_penalty'
            and effect_row.is_active = true
        )
      )
  loop
    perform public.recompute_character_armor(v_character.id);
    perform public.odyssey_refresh_character_combat_state(v_character.id);
  end loop;
end
$refresh$;

commit;

-- Verification:
-- select
--   public.get_character_armor_summary('918f214a-1dfa-4aa2-9c62-cdefdeb8285c')
--     ->> 'has_required_skill' as has_required_skill,
--   public.get_character_armor_summary('918f214a-1dfa-4aa2-9c62-cdefdeb8285c')
--     ->> 'penalty_profile' as penalty_profile;
--
-- With Prot-EXO-01 equipped:
-- has_required_skill = true
-- penalty_profile = trained
-- ===== END 77_effective_skill_satisfies_penalty_requirements_v2.sql =====

-- ===== BEGIN 78_tactical_move_and_positions.sql =====
-- Odyssey System: tactical movement foundation
-- Stage 78: encounter grid settings, authoritative combat positions,
--           move RPC, and GM sync from Owlbear.

create table if not exists public.odyssey_combat_grid_settings (
  encounter_id uuid primary key references public.odyssey_combat_encounters(id) on delete cascade,
  grid_type text not null,
  distance_mode text not null,
  meters_per_cell integer not null default 1,
  anchor_scene_x numeric not null,
  anchor_scene_y numeric not null,
  grid_dpi numeric not null,
  updated_at timestamptz not null default timezone('utc', now())
);

do $$
begin
  if not exists (
    select 1
    from pg_constraint
    where conname = 'odyssey_combat_grid_settings_grid_type_check'
  ) then
    alter table public.odyssey_combat_grid_settings
      add constraint odyssey_combat_grid_settings_grid_type_check
      check (grid_type in ('square', 'hex_vertical', 'hex_horizontal'));
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'odyssey_combat_grid_settings_distance_mode_check'
  ) then
    alter table public.odyssey_combat_grid_settings
      add constraint odyssey_combat_grid_settings_distance_mode_check
      check (distance_mode in ('chebyshev', 'manhattan', 'hex'));
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'odyssey_combat_grid_settings_meters_per_cell_check'
  ) then
    alter table public.odyssey_combat_grid_settings
      add constraint odyssey_combat_grid_settings_meters_per_cell_check
      check (meters_per_cell > 0);
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'odyssey_combat_grid_settings_grid_dpi_check'
  ) then
    alter table public.odyssey_combat_grid_settings
      add constraint odyssey_combat_grid_settings_grid_dpi_check
      check (grid_dpi > 0);
  end if;
end;
$$;

drop trigger if exists odyssey_touch_updated_at_combat_grid_settings on public.odyssey_combat_grid_settings;
create trigger odyssey_touch_updated_at_combat_grid_settings
before update on public.odyssey_combat_grid_settings
for each row
execute function public.odyssey_touch_updated_at();

create table if not exists public.odyssey_combat_positions (
  encounter_id uuid not null references public.odyssey_combat_encounters(id) on delete cascade,
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  token_id text not null,
  cell_q integer not null,
  cell_r integer not null,
  scene_x numeric not null,
  scene_y numeric not null,
  updated_at timestamptz not null default timezone('utc', now()),
  primary key (encounter_id, character_id),
  unique (encounter_id, token_id)
);

create index if not exists odyssey_combat_positions_encounter_token_idx
  on public.odyssey_combat_positions (encounter_id, token_id);

drop trigger if exists odyssey_touch_updated_at_combat_positions on public.odyssey_combat_positions;
create trigger odyssey_touch_updated_at_combat_positions
before update on public.odyssey_combat_positions
for each row
execute function public.odyssey_touch_updated_at();

alter table public.odyssey_combat_grid_settings enable row level security;
alter table public.odyssey_combat_positions enable row level security;

drop policy if exists "odyssey_combat_grid_settings_full_access" on public.odyssey_combat_grid_settings;
create policy "odyssey_combat_grid_settings_full_access"
on public.odyssey_combat_grid_settings
for all
to anon, authenticated
using (true)
with check (true);

drop policy if exists "odyssey_combat_positions_full_access" on public.odyssey_combat_positions;
create policy "odyssey_combat_positions_full_access"
on public.odyssey_combat_positions
for all
to anon, authenticated
using (true)
with check (true);

grant select, insert, update, delete on public.odyssey_combat_grid_settings to anon, authenticated;
grant select, insert, update, delete on public.odyssey_combat_positions to anon, authenticated;

create or replace function public.odyssey_tactical_distance_cells(
  p_grid_type text,
  p_distance_mode text,
  p_from_q integer,
  p_from_r integer,
  p_to_q integer,
  p_to_r integer
)
returns integer
language plpgsql
immutable
as $$
declare
  v_grid_type text := lower(trim(coalesce(p_grid_type, '')));
  v_distance_mode text := lower(trim(coalesce(p_distance_mode, '')));
  v_dx integer := abs(coalesce(p_to_q, 0) - coalesce(p_from_q, 0));
  v_dy integer := abs(coalesce(p_to_r, 0) - coalesce(p_from_r, 0));
begin
  case v_grid_type
    when 'square' then
      case v_distance_mode
        when 'manhattan' then
          return v_dx + v_dy;
        when 'chebyshev' then
          return greatest(v_dx, v_dy);
        else
          raise exception 'Unsupported square distance mode: %', v_distance_mode;
      end case;
    when 'hex_vertical', 'hex_horizontal' then
      return (
        abs(coalesce(p_to_q, 0) - coalesce(p_from_q, 0))
        + abs(coalesce(p_to_r, 0) - coalesce(p_from_r, 0))
        + abs(
          (coalesce(p_to_q, 0) + coalesce(p_to_r, 0))
          - (coalesce(p_from_q, 0) + coalesce(p_from_r, 0))
        )
      ) / 2;
    else
      raise exception 'Unsupported tactical grid type: %', v_grid_type;
  end case;
end;
$$;

create or replace function public.odyssey_build_combat_runtime(
  p_encounter_id uuid,
  p_actor_player_id text default null,
  p_actor_is_gm boolean default false,
  p_include_hidden boolean default false,
  p_log_limit integer default 5
)
returns jsonb
language plpgsql
stable
set search_path = public
as $$
declare
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_actor_player_id text := coalesce(nullif(trim(coalesce(p_actor_player_id, '')), ''), '');
  v_actor_is_gm boolean := coalesce(p_actor_is_gm, false);
  v_include_hidden boolean := coalesce(p_include_hidden, false);
  v_log_limit integer := greatest(1, least(coalesce(p_log_limit, 5), 100));
  v_viewer_character_ids uuid[] := array[]::uuid[];
  v_participants jsonb := '[]'::jsonb;
  v_log_rows jsonb := '[]'::jsonb;
  v_tactical_grid jsonb := null;
begin
  if p_encounter_id is null then
    return jsonb_build_object(
      'ok', true,
      'encounter', null,
      'current_turn', null,
      'visible_participants', '[]'::jsonb,
      'viewer_controlled_character_ids', '[]'::jsonb,
      'log', '[]'::jsonb,
      'state_version', 0,
      'tactical_grid', null
    );
  end if;

  select *
  into v_encounter
  from public.odyssey_combat_encounters e
  where e.id = p_encounter_id;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ENCOUNTER_NOT_FOUND',
      'message', 'Encounter was not found.'
    );
  end if;

  if v_actor_player_id <> '' then
    select coalesce(array_agg(c.id), array[]::uuid[])
    into v_viewer_character_ids
    from public.odyssey_characters c
    where coalesce(c.is_deleted, false) = false
      and c.owner_player_id = v_actor_player_id;
  end if;

  select
    jsonb_build_object(
      'encounter_id', g.encounter_id,
      'grid_type', g.grid_type,
      'distance_mode', g.distance_mode,
      'meters_per_cell', g.meters_per_cell,
      'anchor_scene_x', g.anchor_scene_x,
      'anchor_scene_y', g.anchor_scene_y,
      'grid_dpi', g.grid_dpi,
      'updated_at', g.updated_at
    )
  into v_tactical_grid
  from public.odyssey_combat_grid_settings g
  where g.encounter_id = p_encounter_id;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'initiative_entry_id', e.id,
        'character_id', c.id,
        'character_key', c.character_key,
        'display_name', public.odyssey_character_display_name(c.id),
        'character_bucket', c.character_bucket,
        'owner_player_id', c.owner_player_id,
        'owner_player_name', c.owner_player_name,
        'token_id', coalesce(pos.token_id, link.token_id, ''),
        'initiative_value', e.initiative_value,
        'reaction_value', e.reaction_value,
        'roll_value', e.roll_value,
        'bonus_value', e.bonus_value,
        'order_index', e.order_index,
        'is_active', e.is_active,
        'is_current_turn', v_encounter.active_entry_id = e.id,
        'action_current', e.action_current,
        'action_max', e.action_max,
        'move_current', e.move_current,
        'move_max', e.move_max,
        'reaction_action_current', e.reaction_action_current,
        'reaction_action_max', e.reaction_action_max,
        'action_converted_to_move', e.action_converted_to_move,
        'hide_from_initiative_ui', e.hide_from_initiative_ui,
        'joined_round', e.joined_round,
        'movement_version', e.movement_version,
        'turn_version', e.turn_version,
        'removed_at', e.removed_at,
        'removed_reason', e.removed_reason,
        'position',
          case
            when pos.character_id is null then null
            else jsonb_build_object(
              'cell_q', pos.cell_q,
              'cell_r', pos.cell_r,
              'scene_x', pos.scene_x,
              'scene_y', pos.scene_y,
              'updated_at', pos.updated_at
            )
          end,
        'control', public.odyssey_can_control_character(c.id, v_actor_player_id, v_actor_is_gm),
        'state',
          jsonb_build_object(
            'state_version', coalesce(s.state_version, c.active_combat_state_version, 0),
            'status_summary', coalesce(nullif(trim(s.status_summary), ''), public.odyssey_build_character_status_summary(c.id)),
            'is_alive', coalesce(s.is_alive, true),
            'is_conscious', coalesce(s.is_conscious, true)
          )
      )
      order by e.order_index, e.created_at, e.id
    ),
    '[]'::jsonb
  )
  into v_participants
  from public.odyssey_initiative_entries e
  join public.odyssey_characters c on c.id = e.character_id
  left join public.odyssey_character_combat_state s on s.character_id = c.id
  left join public.odyssey_combat_positions pos
    on pos.encounter_id = e.encounter_id
   and pos.character_id = e.character_id
  left join lateral (
    select t.token_id
    from public.odyssey_token_links t
    where t.room_id = v_encounter.room_id
      and t.scene_id = v_encounter.scene_id
      and t.character_id = c.id
      and t.is_active = true
    order by t.updated_at desc, t.created_at desc, t.id desc
    limit 1
  ) link on true
  where e.encounter_id = p_encounter_id
    and (
      v_actor_is_gm
      or not e.hide_from_initiative_ui
      or (v_actor_is_gm and v_include_hidden)
    );

  v_log_rows := coalesce(
    public.combat_get_log(
      jsonb_build_object(
        'encounter_id', p_encounter_id,
        'room_id', v_encounter.room_id,
        'actor_player_id', v_actor_player_id,
        'actor_is_gm', v_actor_is_gm,
        'limit', v_log_limit
      )
    )->'rows',
    '[]'::jsonb
  );

  return jsonb_build_object(
    'ok', true,
    'encounter',
      jsonb_build_object(
        'id', v_encounter.id,
        'campaign_id', v_encounter.campaign_id,
        'room_id', v_encounter.room_id,
        'scene_id', v_encounter.scene_id,
        'name', v_encounter.name,
        'status', v_encounter.status,
        'current_round', v_encounter.current_round,
        'active_character_id', v_encounter.active_character_id,
        'active_entry_id', v_encounter.active_entry_id,
        'state_version', v_encounter.state_version,
        'action_default', v_encounter.action_default,
        'move_default', v_encounter.move_default,
        'started_at', v_encounter.started_at,
        'last_transition_at', v_encounter.last_transition_at
      ),
    'current_turn',
      case
        when v_encounter.active_entry_id is null then null
        else (
          select participant
          from jsonb_array_elements(v_participants) participant
          where public.odyssey_try_parse_uuid(participant->>'initiative_entry_id') = v_encounter.active_entry_id
          limit 1
        )
      end,
    'visible_participants', v_participants,
    'viewer_controlled_character_ids', to_jsonb(v_viewer_character_ids),
    'log', v_log_rows,
    'state_version', coalesce(v_encounter.state_version, 0),
    'tactical_grid', v_tactical_grid
  );
end;
$$;

create or replace function public.combat_sync_positions_from_owlbear(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_campaign_id text := coalesce(nullif(trim(coalesce(v_payload->>'campaign_id', '')), ''), '');
  v_room_id text := coalesce(nullif(trim(coalesce(v_payload->>'room_id', '')), ''), '');
  v_scene_id text := coalesce(nullif(trim(coalesce(v_payload->>'scene_id', '')), ''), '');
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_grid_type text := lower(trim(coalesce(v_payload->>'grid_type', '')));
  v_distance_mode text := lower(trim(coalesce(v_payload->>'distance_mode', '')));
  v_meters_per_cell integer := greatest(coalesce(nullif(trim(coalesce(v_payload->>'meters_per_cell', '')), '')::integer, 1), 1);
  v_anchor_scene_x numeric := coalesce(nullif(trim(coalesce(v_payload->>'anchor_scene_x', '')), '')::numeric, 0);
  v_anchor_scene_y numeric := coalesce(nullif(trim(coalesce(v_payload->>'anchor_scene_y', '')), '')::numeric, 0);
  v_grid_dpi numeric := coalesce(nullif(trim(coalesce(v_payload->>'grid_dpi', '')), '')::numeric, 0);
  v_positions jsonb := case when jsonb_typeof(v_payload->'positions') = 'array' then v_payload->'positions' else '[]'::jsonb end;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_item jsonb;
  v_character_id uuid;
  v_token_id text;
  v_cell_q integer;
  v_cell_r integer;
  v_scene_x numeric;
  v_scene_y numeric;
  v_synced_count integer := 0;
begin
  if not v_actor_is_gm then
    return jsonb_build_object('ok', false, 'error', 'CONTROL_DENIED', 'message', 'Only the GM may sync tactical positions.');
  end if;

  if v_encounter_id is null then
    if v_room_id = '' or v_scene_id = '' then
      return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'encounter_id or room/scene context is required.');
    end if;

    select *
    into v_encounter
    from public.odyssey_get_active_encounter(v_campaign_id, v_room_id, v_scene_id)
    for update;
  else
    select *
    into v_encounter
    from public.odyssey_combat_encounters
    where id = v_encounter_id
      and status = 'active'
      and ended_at is null
    for update;
  end if;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'ENCOUNTER_NOT_ACTIVE', 'message', 'Encounter is not active.');
  end if;

  if v_grid_type not in ('square', 'hex_vertical', 'hex_horizontal') then
    return jsonb_build_object('ok', false, 'error', 'GRID_NOT_SUPPORTED', 'message', 'Only square and hex grids are supported.');
  end if;

  if v_distance_mode not in ('chebyshev', 'manhattan', 'hex') then
    return jsonb_build_object('ok', false, 'error', 'GRID_NOT_SUPPORTED', 'message', 'Only chebyshev, manhattan, and hex distance modes are supported.');
  end if;

  if v_grid_dpi <= 0 then
    return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'grid_dpi must be greater than 0.');
  end if;

  insert into public.odyssey_combat_grid_settings (
    encounter_id,
    grid_type,
    distance_mode,
    meters_per_cell,
    anchor_scene_x,
    anchor_scene_y,
    grid_dpi
  )
  values (
    v_encounter.id,
    v_grid_type,
    v_distance_mode,
    v_meters_per_cell,
    v_anchor_scene_x,
    v_anchor_scene_y,
    v_grid_dpi
  )
  on conflict (encounter_id) do update
  set
    grid_type = excluded.grid_type,
    distance_mode = excluded.distance_mode,
    meters_per_cell = excluded.meters_per_cell,
    anchor_scene_x = excluded.anchor_scene_x,
    anchor_scene_y = excluded.anchor_scene_y,
    grid_dpi = excluded.grid_dpi,
    updated_at = timezone('utc', now());

  for v_item in
    select value
    from jsonb_array_elements(v_positions)
  loop
    v_character_id := public.odyssey_try_parse_uuid(v_item->>'character_id');
    v_token_id := coalesce(nullif(trim(coalesce(v_item->>'token_id', '')), ''), '');
    v_cell_q := coalesce(nullif(trim(coalesce(v_item->>'cell_q', '')), '')::integer, 0);
    v_cell_r := coalesce(nullif(trim(coalesce(v_item->>'cell_r', '')), '')::integer, 0);
    v_scene_x := coalesce(nullif(trim(coalesce(v_item->>'scene_x', '')), '')::numeric, 0);
    v_scene_y := coalesce(nullif(trim(coalesce(v_item->>'scene_y', '')), '')::numeric, 0);

    if v_character_id is null or v_token_id = '' then
      continue;
    end if;

    if not exists (
      select 1
      from public.odyssey_initiative_entries e
      where e.encounter_id = v_encounter.id
        and e.character_id = v_character_id
        and e.is_active = true
    ) then
      continue;
    end if;

    insert into public.odyssey_combat_positions (
      encounter_id,
      character_id,
      token_id,
      cell_q,
      cell_r,
      scene_x,
      scene_y
    )
    values (
      v_encounter.id,
      v_character_id,
      v_token_id,
      v_cell_q,
      v_cell_r,
      v_scene_x,
      v_scene_y
    )
    on conflict (encounter_id, character_id) do update
    set
      token_id = excluded.token_id,
      cell_q = excluded.cell_q,
      cell_r = excluded.cell_r,
      scene_x = excluded.scene_x,
      scene_y = excluded.scene_y,
      updated_at = timezone('utc', now());

    v_synced_count := v_synced_count + 1;
  end loop;

  perform public.odyssey_increment_encounter_state_version(v_encounter.id);

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter.id,
    'synced_count', v_synced_count,
    'runtime', public.odyssey_build_combat_runtime(v_encounter.id, v_actor_player_id, true, true, 5)
  );
end;
$$;

create or replace function public.combat_move_character(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_destination jsonb := case when jsonb_typeof(v_payload->'destination') = 'object' then v_payload->'destination' else '{}'::jsonb end;
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_id');
  v_token_id text := coalesce(nullif(trim(coalesce(v_payload->>'token_id', '')), ''), '');
  v_expected_state_version integer := nullif(trim(coalesce(v_payload->>'expected_state_version', '')), '')::integer;
  v_expected_movement_version integer := nullif(trim(coalesce(v_payload->>'expected_movement_version', '')), '')::integer;
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_dest_q integer := nullif(trim(coalesce(v_destination->>'cell_q', '')), '')::integer;
  v_dest_r integer := nullif(trim(coalesce(v_destination->>'cell_r', '')), '')::integer;
  v_dest_scene_x numeric := nullif(trim(coalesce(v_destination->>'scene_x', '')), '')::numeric;
  v_dest_scene_y numeric := nullif(trim(coalesce(v_destination->>'scene_y', '')), '')::numeric;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_entry public.odyssey_initiative_entries%rowtype;
  v_position public.odyssey_combat_positions%rowtype;
  v_grid public.odyssey_combat_grid_settings%rowtype;
  v_control jsonb := '{}'::jsonb;
  v_distance_cells integer := 0;
  v_move_cost_m integer := 0;
  v_log_id uuid := null;
  v_state_version integer := 0;
  v_prev_cell_q integer := 0;
  v_prev_cell_r integer := 0;
  v_prev_scene_x numeric := 0;
  v_prev_scene_y numeric := 0;
begin
  if v_encounter_id is null or v_character_id is null then
    return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'encounter_id and character_id are required.');
  end if;

  if v_dest_q is null or v_dest_r is null or v_dest_scene_x is null or v_dest_scene_y is null then
    return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'destination cell and scene coordinates are required.');
  end if;

  select *
  into v_encounter
  from public.odyssey_combat_encounters
  where id = v_encounter_id
    and status = 'active'
    and ended_at is null
  for update;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'ENCOUNTER_NOT_ACTIVE', 'message', 'Encounter is not active.');
  end if;

  select *
  into v_entry
  from public.odyssey_initiative_entries
  where encounter_id = v_encounter_id
    and character_id = v_character_id
    and is_active = true
  for update;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'PARTICIPANT_NOT_FOUND', 'message', 'Participant was not found.');
  end if;

  v_control := public.odyssey_can_control_character(v_character_id, v_actor_player_id, v_actor_is_gm);
  if coalesce((v_control->>'allowed')::boolean, false) = false then
    return jsonb_build_object('ok', false, 'error', 'CONTROL_DENIED', 'message', 'You cannot control this participant.');
  end if;

  if v_encounter.active_entry_id is distinct from v_entry.id then
    return jsonb_build_object(
      'ok', false,
      'error', 'NOT_CURRENT_TURN',
      'message', 'It is not this participant''s turn.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_state_version is not null
     and coalesce(v_encounter.state_version, 0) <> v_expected_state_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STATE_VERSION_CONFLICT',
      'message', 'Combat state changed. Reload authoritative runtime.',
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_movement_version is not null
     and coalesce(v_entry.movement_version, 0) <> v_expected_movement_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STATE_VERSION_CONFLICT',
      'message', 'Movement state changed. Reload authoritative runtime.',
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select *
  into v_grid
  from public.odyssey_combat_grid_settings
  where encounter_id = v_encounter_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'TACTICAL_GRID_NOT_SYNCED',
      'message', 'The tactical grid has not been synced by the GM yet.'
    );
  end if;

  select *
  into v_position
  from public.odyssey_combat_positions
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'POSITION_NOT_SYNCED',
      'message', 'This token position has not been synced by the GM yet.'
    );
  end if;

  if v_token_id <> '' and v_position.token_id <> v_token_id then
    return jsonb_build_object(
      'ok', false,
      'error', 'STATE_VERSION_CONFLICT',
      'message', 'Token position changed. Reload authoritative runtime.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  v_prev_cell_q := v_position.cell_q;
  v_prev_cell_r := v_position.cell_r;
  v_prev_scene_x := v_position.scene_x;
  v_prev_scene_y := v_position.scene_y;

  v_distance_cells := public.odyssey_tactical_distance_cells(
    v_grid.grid_type,
    v_grid.distance_mode,
    v_position.cell_q,
    v_position.cell_r,
    v_dest_q,
    v_dest_r
  );
  v_move_cost_m := v_distance_cells * greatest(coalesce(v_grid.meters_per_cell, 1), 1);

  if coalesce(v_entry.move_current, 0) < v_move_cost_m then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_NOT_AVAILABLE',
      'message', 'Not enough MOVE is available.',
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_current', coalesce(v_entry.move_current, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_distance_cells = 0 then
    return jsonb_build_object(
      'ok', true,
      'encounter_id', v_encounter_id,
      'character_id', v_character_id,
      'position',
        jsonb_build_object(
          'token_id', v_position.token_id,
          'cell_q', v_position.cell_q,
          'cell_r', v_position.cell_r,
          'scene_x', v_position.scene_x,
          'scene_y', v_position.scene_y,
          'updated_at', v_position.updated_at
        ),
      'distance_cells', 0,
      'move_cost_m', 0,
      'move_current', coalesce(v_entry.move_current, 0),
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'log_id', null,
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  update public.odyssey_combat_positions
  set
    token_id = coalesce(nullif(v_token_id, ''), token_id),
    cell_q = v_dest_q,
    cell_r = v_dest_r,
    scene_x = v_dest_scene_x,
    scene_y = v_dest_scene_y,
    updated_at = timezone('utc', now())
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  returning * into v_position;

  update public.odyssey_initiative_entries
  set
    move_current = greatest(move_current - v_move_cost_m, 0),
    movement_version = coalesce(movement_version, 0) + 1
  where id = v_entry.id
  returning * into v_entry;

  v_state_version := public.odyssey_increment_encounter_state_version(v_encounter_id);

  v_log_id := public.odyssey_combat_log_insert(
    v_encounter.campaign_id,
    v_encounter.room_id,
    v_encounter.scene_id,
    v_encounter.id,
    v_encounter.current_round,
    v_character_id,
    null,
    v_character_id,
    'public',
    'move',
    public.odyssey_character_display_name(v_character_id) || ' moved ' || v_move_cost_m || ' m.',
    jsonb_build_object(
      'token_id', v_position.token_id,
      'from_cell_q', v_prev_cell_q,
      'from_cell_r', v_prev_cell_r,
      'from_scene_x', v_prev_scene_x,
      'from_scene_y', v_prev_scene_y,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'to_scene_x', v_dest_scene_x,
      'to_scene_y', v_dest_scene_y,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    jsonb_build_object(
      'token_id', v_position.token_id,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    coalesce(nullif(v_actor_player_id, ''), 'system')
  );

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter_id,
    'character_id', v_character_id,
    'position',
      jsonb_build_object(
        'token_id', v_position.token_id,
        'cell_q', v_position.cell_q,
        'cell_r', v_position.cell_r,
        'scene_x', v_position.scene_x,
        'scene_y', v_position.scene_y,
        'updated_at', v_position.updated_at
      ),
    'distance_cells', v_distance_cells,
    'move_cost_m', v_move_cost_m,
    'move_current', coalesce(v_entry.move_current, 0),
    'movement_version', coalesce(v_entry.movement_version, 0),
    'state_version', v_state_version,
    'log_id', v_log_id,
    'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
  );
end;
$$;

grant execute on function public.odyssey_tactical_distance_cells(text, text, integer, integer, integer, integer) to anon, authenticated;
grant execute on function public.combat_sync_positions_from_owlbear(jsonb) to anon, authenticated;
grant execute on function public.combat_move_character(jsonb) to anon, authenticated;
