create table if not exists public.odyssey_weapon_model_ability_links (
  id uuid primary key default gen_random_uuid(),
  weapon_model_id uuid not null references public.odyssey_weapon_model_defs(id) on delete cascade,
  ability_def_id uuid not null references public.odyssey_ability_defs(id) on delete cascade,
  profile_id uuid null references public.odyssey_weapon_model_profiles(id) on delete cascade,
  is_enabled_by_default boolean not null default true,
  sort_order integer not null default 0,
  data jsonb not null default '{}'::jsonb check (jsonb_typeof(data) = 'object'),
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create unique index if not exists odyssey_weapon_model_ability_links_unique_idx
  on public.odyssey_weapon_model_ability_links (
    weapon_model_id,
    ability_def_id,
    coalesce(profile_id, '00000000-0000-0000-0000-000000000000'::uuid)
  );

create index if not exists odyssey_weapon_model_ability_links_weapon_idx
  on public.odyssey_weapon_model_ability_links (weapon_model_id, sort_order, created_at);

create index if not exists odyssey_weapon_model_ability_links_profile_idx
  on public.odyssey_weapon_model_ability_links (profile_id, sort_order, created_at);

create index if not exists odyssey_weapon_model_ability_links_ability_idx
  on public.odyssey_weapon_model_ability_links (ability_def_id, sort_order, created_at);

alter table public.odyssey_weapon_model_ability_links enable row level security;

drop policy if exists "odyssey_weapon_model_ability_links_full_access" on public.odyssey_weapon_model_ability_links;
create policy "odyssey_weapon_model_ability_links_full_access"
on public.odyssey_weapon_model_ability_links
for all
to anon, authenticated
using (true)
with check (true);

grant select, insert, update, delete on public.odyssey_weapon_model_ability_links to anon, authenticated;

drop trigger if exists odyssey_touch_updated_at_weapon_model_ability_links on public.odyssey_weapon_model_ability_links;
create trigger odyssey_touch_updated_at_weapon_model_ability_links
before update on public.odyssey_weapon_model_ability_links
for each row
execute function public.odyssey_touch_updated_at();

alter table public.odyssey_character_abilities
  add column if not exists source_character_weapon_id uuid null references public.odyssey_character_weapons(id) on delete cascade;

alter table public.odyssey_character_effects
  add column if not exists source_character_weapon_id uuid null references public.odyssey_character_weapons(id) on delete cascade;

drop index if exists public.odyssey_character_abilities_unique_source_idx;
create unique index if not exists odyssey_character_abilities_unique_source_idx
  on public.odyssey_character_abilities (
    character_id,
    ability_def_id,
    coalesce(source_equipment_item_id, '00000000-0000-0000-0000-000000000000'::uuid),
    coalesce(source_character_item_id, '00000000-0000-0000-0000-000000000000'::uuid),
    coalesce(source_character_weapon_id, '00000000-0000-0000-0000-000000000000'::uuid)
  );

create unique index if not exists odyssey_character_abilities_weapon_source_idx
  on public.odyssey_character_abilities (character_id, ability_def_id, source_character_weapon_id)
  where source_character_weapon_id is not null;

create index if not exists odyssey_character_effects_weapon_source_idx
  on public.odyssey_character_effects (source_character_weapon_id, is_active, updated_at desc)
  where source_character_weapon_id is not null;

alter table public.odyssey_character_abilities
  drop constraint if exists odyssey_character_abilities_single_source_check;

alter table public.odyssey_character_abilities
  add constraint odyssey_character_abilities_single_source_check
  check (num_nonnulls(source_equipment_item_id, source_character_item_id, source_character_weapon_id) <= 1);

create or replace function public.odyssey_sync_weapon_model_ability_links_from_legacy(
  p_weapon_model_id uuid default null
)
returns void
language plpgsql
as $$
begin
  insert into public.odyssey_weapon_model_ability_links (
    weapon_model_id,
    ability_def_id,
    profile_id,
    is_enabled_by_default,
    sort_order,
    data
  )
  select
    legacy.weapon_model_id,
    legacy.ability_def_id,
    legacy.profile_id,
    coalesce(legacy.is_enabled, true),
    coalesce(legacy.sort_order, 0),
    coalesce(legacy.data, '{}'::jsonb)
  from public.odyssey_weapon_model_abilities legacy
  where p_weapon_model_id is null
     or legacy.weapon_model_id = p_weapon_model_id
  on conflict (
    weapon_model_id,
    ability_def_id,
    coalesce(profile_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) do update
  set
    is_enabled_by_default = excluded.is_enabled_by_default,
    sort_order = excluded.sort_order,
    data = excluded.data,
    updated_at = timezone('utc', now());

  delete from public.odyssey_weapon_model_ability_links link
  where (p_weapon_model_id is null or link.weapon_model_id = p_weapon_model_id)
    and not exists (
      select 1
      from public.odyssey_weapon_model_abilities legacy
      where legacy.weapon_model_id = link.weapon_model_id
        and legacy.ability_def_id = link.ability_def_id
        and legacy.profile_id is not distinct from link.profile_id
    );
end;
$$;

create or replace function public.odyssey_build_weapon_ability_effect_key(
  p_character_weapon_id uuid,
  p_ability_code text,
  p_effect_code text default null
)
returns text
language plpgsql
immutable
as $$
declare
  v_weapon_id text := coalesce(p_character_weapon_id::text, '');
  v_ability_code text := lower(trim(coalesce(p_ability_code, '')));
  v_effect_code text := lower(trim(coalesce(p_effect_code, '')));
begin
  if v_weapon_id = '' then
    return coalesce(nullif(v_effect_code, ''), nullif(v_ability_code, ''), 'weapon_ability');
  end if;

  if v_effect_code <> '' then
    return format('weapon_ability:%s:%s:%s', v_weapon_id, coalesce(nullif(v_ability_code, ''), 'ability'), v_effect_code);
  end if;

  return format('weapon_ability:%s:%s', v_weapon_id, coalesce(nullif(v_ability_code, ''), 'ability'));
end;
$$;

create or replace function public.initialize_character_weapon_abilities(
  p_character_weapon_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_weapon record;
  v_link record;
  v_payload_data jsonb := '{}'::jsonb;
  v_processed_ability_ids uuid[] := '{}'::uuid[];
  v_upserted_count integer := 0;
  v_hidden_count integer := 0;
begin
  select
    weapon.id,
    weapon.character_id,
    weapon.weapon_model_id,
    model.code as weapon_model_code,
    model.name as weapon_model_name
  into v_weapon
  from public.odyssey_character_weapons weapon
  join public.odyssey_weapon_model_defs model on model.id = weapon.weapon_model_id
  where weapon.id = p_character_weapon_id;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_WEAPON_NOT_FOUND',
      'character_weapon_id', p_character_weapon_id
    );
  end if;

  perform public.odyssey_sync_weapon_model_ability_links_from_legacy(v_weapon.weapon_model_id);

  for v_link in
    with ranked_links as (
      select
        link.*,
        profile.code as profile_code,
        row_number() over (
          partition by link.ability_def_id
          order by
            case when link.profile_id is null then 1 else 0 end,
            link.sort_order,
            link.created_at,
            link.id
        ) as link_rank
      from public.odyssey_weapon_model_ability_links link
      left join public.odyssey_weapon_model_profiles profile on profile.id = link.profile_id
      where link.weapon_model_id = v_weapon.weapon_model_id
    )
    select *
    from ranked_links
    where link_rank = 1
    order by sort_order, created_at, id
  loop
    v_payload_data := jsonb_strip_nulls(
      coalesce(v_link.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'weapon_model',
        'weapon_link_id', v_link.id::text,
        'weapon_model_id', v_weapon.weapon_model_id::text,
        'weapon_model_code', v_weapon.weapon_model_code,
        'weapon_model_name', v_weapon.weapon_model_name,
        'required_profile_id', case when v_link.profile_id is not null then v_link.profile_id::text else null end,
        'required_profile_code', v_link.profile_code,
        'source_removed', false
      )
    );

    insert into public.odyssey_character_abilities (
      character_id,
      ability_def_id,
      character_skill_id,
      learned_level,
      source_character_weapon_id,
      is_enabled,
      is_hidden,
      current_cooldown_rounds,
      current_charges,
      max_charges,
      data,
      notes,
      sort_order
    )
    values (
      v_weapon.character_id,
      v_link.ability_def_id,
      null,
      greatest(coalesce(nullif(trim(coalesce(v_payload_data->>'learned_level', '')), '')::integer, 1), 1),
      v_weapon.id,
      coalesce(v_link.is_enabled_by_default, true),
      false,
      greatest(coalesce(nullif(trim(coalesce(v_payload_data->>'cooldown_rounds', '')), '')::integer, 0), 0),
      nullif(trim(coalesce(v_payload_data->>'default_current_charges', '')), '')::integer,
      nullif(trim(coalesce(v_payload_data->>'default_max_charges', '')), '')::integer,
      v_payload_data,
      '',
      coalesce(v_link.sort_order, 0)
    )
    on conflict (character_id, ability_def_id, source_character_weapon_id)
    where source_character_weapon_id is not null
    do update
    set
      learned_level = greatest(coalesce(public.odyssey_character_abilities.learned_level, 0), greatest(coalesce(nullif(trim(coalesce(excluded.data->>'learned_level', '')), '')::integer, 1), 1)),
      is_enabled = excluded.is_enabled,
      is_hidden = false,
      data = excluded.data,
      sort_order = excluded.sort_order,
      updated_at = timezone('utc', now())
    ;

    v_processed_ability_ids := array_append(v_processed_ability_ids, v_link.ability_def_id);
    v_upserted_count := v_upserted_count + 1;
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    data = jsonb_set(coalesce(ability.data, '{}'::jsonb), '{source_removed}', 'true'::jsonb, true),
    updated_at = timezone('utc', now())
  where ability.character_id = v_weapon.character_id
    and ability.source_character_weapon_id = v_weapon.id
    and coalesce((ability.data->>'generated')::boolean, false) = true
    and (
      coalesce(array_length(v_processed_ability_ids, 1), 0) = 0
      or not (ability.ability_def_id = any(v_processed_ability_ids))
    );

  get diagnostics v_hidden_count = row_count;

  return jsonb_build_object(
    'ok', true,
    'character_weapon_id', v_weapon.id,
    'character_id', v_weapon.character_id,
    'weapon_model_id', v_weapon.weapon_model_id,
    'upserted_count', v_upserted_count,
    'hidden_count', v_hidden_count
  );
end;
$$;

create or replace function public.odyssey_sync_character_weapon_abilities_for_model(
  p_weapon_model_id uuid
)
returns void
language plpgsql
as $$
declare
  v_weapon record;
begin
  if p_weapon_model_id is null then
    return;
  end if;

  for v_weapon in
    select weapon.id
    from public.odyssey_character_weapons weapon
    where weapon.weapon_model_id = p_weapon_model_id
  loop
    perform public.initialize_character_weapon_abilities(v_weapon.id);
  end loop;
end;
$$;

create or replace function public.odyssey_handle_legacy_weapon_ability_links_sync()
returns trigger
language plpgsql
as $$
declare
  v_weapon_model_id uuid := coalesce(new.weapon_model_id, old.weapon_model_id);
begin
  perform public.odyssey_sync_weapon_model_ability_links_from_legacy(v_weapon_model_id);
  perform public.odyssey_sync_character_weapon_abilities_for_model(v_weapon_model_id);
  return null;
end;
$$;

drop trigger if exists odyssey_sync_weapon_ability_links_legacy_ins_upd on public.odyssey_weapon_model_abilities;
create trigger odyssey_sync_weapon_ability_links_legacy_ins_upd
after insert or update or delete on public.odyssey_weapon_model_abilities
for each row
execute function public.odyssey_handle_legacy_weapon_ability_links_sync();

create or replace function public.odyssey_initialize_character_weapon_abilities_trigger()
returns trigger
language plpgsql
as $$
begin
  perform public.initialize_character_weapon_abilities(new.id);
  return new;
end;
$$;

drop trigger if exists odyssey_initialize_character_weapon_abilities_after_write on public.odyssey_character_weapons;
create trigger odyssey_initialize_character_weapon_abilities_after_write
after insert or update of weapon_model_id, character_id on public.odyssey_character_weapons
for each row
execute function public.odyssey_initialize_character_weapon_abilities_trigger();

do $$
declare
  v_weapon record;
begin
  perform public.odyssey_sync_weapon_model_ability_links_from_legacy(null);

  for v_weapon in
    select weapon.id
    from public.odyssey_character_weapons weapon
  loop
    perform public.initialize_character_weapon_abilities(v_weapon.id);
  end loop;
end;
$$;

create or replace function public.get_character_abilities(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_character_exists boolean := false;
  v_resource_pools jsonb := '[]'::jsonb;
  v_abilities jsonb := '[]'::jsonb;
begin
  select exists(
    select 1
    from public.odyssey_characters c
    where c.id = p_character_id
      and coalesce(c.is_deleted, false) = false
  )
  into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'character_id', p_character_id,
      'resource_pools', '[]'::jsonb,
      'abilities', '[]'::jsonb
    );
  end if;

  perform public.initialize_character_weapon_abilities(weapon.id)
  from public.odyssey_character_weapons weapon
  where weapon.character_id = p_character_id;

  with resource_rows as (
    select
      d.sort_order,
      d.code,
      jsonb_build_object(
        'id', p.id,
        'resource_pool_def_id', d.id,
        'code', d.code,
        'name', d.name,
        'source_type', d.source_type,
        'attribute_code', attr.code,
        'recovery_mode', d.recovery_mode,
        'current_value',
          coalesce(
            p.current_value,
            case
              when d.default_current_value is not null then least(d.default_current_value, case
                when d.source_type = 'attribute' and d.attribute_def_id is not null then greatest(coalesce(a.value, d.default_max_value, 0), 0)
                else greatest(coalesce(d.default_max_value, 0), 0)
              end)
              when d.source_type = 'attribute' and d.attribute_def_id is not null then greatest(coalesce(a.value, d.default_max_value, 0), 0)
              else greatest(coalesce(d.default_max_value, 0), 0)
            end,
            0
          ),
        'max_value',
          case
            when d.source_type = 'attribute' and d.attribute_def_id is not null then greatest(coalesce(a.value, d.default_max_value, 0), 0)
            else greatest(coalesce(d.default_max_value, 0), 0)
          end,
        'reserved_value', coalesce(p.reserved_value, 0),
        'description', d.description,
        'data', coalesce(p.data, '{}'::jsonb),
        'notes', coalesce(p.notes, ''),
        'tags', d.tags
      ) as payload
    from public.odyssey_resource_pool_defs d
    left join public.odyssey_attribute_defs attr on attr.id = d.attribute_def_id
    left join public.odyssey_character_attributes a
      on a.character_id = p_character_id
     and a.attribute_def_id = d.attribute_def_id
    left join public.odyssey_character_resource_pools p
      on p.character_id = p_character_id
     and p.resource_pool_def_id = d.id
  )
  select coalesce(jsonb_agg(payload order by sort_order, code), '[]'::jsonb)
  into v_resource_pools
  from resource_rows;

  with ability_rows as (
    select
      ability.sort_order,
      def.sort_order as def_sort_order,
      def.code,
      ability.id,
      ability.character_id,
      def.id as ability_def_id,
      def.code as ability_code,
      def.name as ability_name,
      def.ability_kind,
      def.source_type,
      def.activation_type,
      def.target_type,
      def.effect_mode,
      def.attack_type,
      def.description,
      def.linked_skill_id,
      linked_def.code as linked_skill_code,
      linked_def.name as linked_skill_name,
      coalesce(direct_skill.id, linked_skill.id) as resolved_character_skill_id,
      coalesce(direct_skill.level, linked_skill.level, 0) as resolved_character_skill_level,
      ability.learned_level,
      greatest(coalesce(direct_skill.level, linked_skill.level, ability.learned_level, 0), 0) as effective_level,
      ability.is_enabled,
      ability.is_hidden,
      ability.current_cooldown_rounds,
      ability.current_charges,
      ability.max_charges,
      ability.source_equipment_item_id,
      ability.source_character_item_id,
      ability.source_character_weapon_id,
      ability.data,
      ability.notes,
      def.tags,
      level_data.*,
      source_weapon.custom_name as source_weapon_custom_name,
      source_weapon_model.id as source_weapon_model_id,
      source_weapon_model.code as source_weapon_model_code,
      source_weapon_model.name as source_weapon_model_name,
      source_weapon_profile.id as source_weapon_active_profile_id,
      source_weapon_profile.code as source_weapon_active_profile_code
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    left join public.odyssey_skill_defs linked_def on linked_def.id = def.linked_skill_id
    left join public.odyssey_character_skills direct_skill
      on direct_skill.id = ability.character_skill_id
    left join public.odyssey_character_skills linked_skill
      on ability.character_skill_id is null
     and linked_skill.character_id = ability.character_id
     and linked_skill.skill_def_id = def.linked_skill_id
    left join lateral (
      select level_entry.*
      from public.odyssey_ability_level_defs level_entry
      where level_entry.ability_def_id = def.id
        and level_entry.ability_level <= greatest(coalesce(direct_skill.level, linked_skill.level, ability.learned_level, 0), 0)
      order by level_entry.ability_level desc
      limit 1
    ) level_data on true
    left join public.odyssey_character_weapons source_weapon on source_weapon.id = ability.source_character_weapon_id
    left join public.odyssey_weapon_model_defs source_weapon_model on source_weapon_model.id = source_weapon.weapon_model_id
    left join public.odyssey_weapon_model_profiles source_weapon_profile on source_weapon_profile.id = source_weapon.active_profile_id
    where ability.character_id = p_character_id
  )
  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'id', id,
        'character_id', character_id,
        'ability_def_id', ability_def_id,
        'code', ability_code,
        'name', ability_name,
        'ability_kind', ability_kind,
        'source_type', source_type,
        'activation_type', activation_type,
        'target_type', target_type,
        'effect_mode', effect_mode,
        'attack_type', attack_type,
        'description', description,
        'linked_skill_id', linked_skill_id,
        'linked_skill_code', linked_skill_code,
        'linked_skill_name', linked_skill_name,
        'character_skill_id', resolved_character_skill_id,
        'character_skill_level', resolved_character_skill_level,
        'learned_level', learned_level,
        'effective_level', effective_level,
        'is_enabled', is_enabled,
        'is_hidden', is_hidden,
        'current_cooldown_rounds', current_cooldown_rounds,
        'current_charges', current_charges,
        'max_charges', max_charges,
        'resource',
          jsonb_build_object(
            'mode', source_type,
            'pool_code', coalesce(nullif(level_data.resource_pool_code, ''), null),
            'item_code', coalesce(nullif(level_data.resource_item_code, ''), null),
            'cost', coalesce(level_data.resource_cost, 0)
          ),
        'source_equipment_item_id', source_equipment_item_id,
        'source_character_item_id', source_character_item_id,
        'source_character_weapon_id', source_character_weapon_id,
        'source',
          case
            when source_character_weapon_id is not null then jsonb_strip_nulls(
              jsonb_build_object(
                'type', 'weapon',
                'character_weapon_id', source_character_weapon_id,
                'weapon_name', coalesce(nullif(trim(source_weapon_custom_name), ''), source_weapon_model_name),
                'weapon_model_id', source_weapon_model_id,
                'weapon_model_code', source_weapon_model_code,
                'required_profile_id', nullif(trim(coalesce(data->>'required_profile_id', '')), ''),
                'required_profile_code', nullif(trim(coalesce(data->>'required_profile_code', '')), ''),
                'is_available_for_active_profile',
                  case
                    when nullif(trim(coalesce(data->>'required_profile_id', '')), '') is null then true
                    else source_weapon_active_profile_id::text = nullif(trim(coalesce(data->>'required_profile_id', '')), '')
                  end
              )
            )
            else 'null'::jsonb
          end,
        'data', data,
        'notes', notes,
        'tags', tags,
        'level_data',
          case
            when level_data.id is null then null
            else jsonb_build_object(
              'id', level_data.id,
              'ability_level', level_data.ability_level,
              'resource_cost', level_data.resource_cost,
              'cooldown_rounds', level_data.cooldown_rounds,
              'range_profile_id', level_data.range_profile_id,
              'attack_accuracy_bonus', level_data.attack_accuracy_bonus,
              'attack_damage_bonus', level_data.attack_damage_bonus,
              'attack_armor_pierce', level_data.attack_armor_pierce,
              'ignore_armor', level_data.ignore_armor,
              'special_armor_value', level_data.special_armor_value,
              'special_max_critical', level_data.special_max_critical,
              'duration_rounds', level_data.duration_rounds,
              'data', level_data.data,
              'effect_data', level_data.effect_data
            )
          end
      )
      order by sort_order, def_sort_order, code
    ),
    '[]'::jsonb
  )
  into v_abilities
  from ability_rows;

  return jsonb_build_object(
    'ok', true,
    'character_id', p_character_id,
    'resource_pools', v_resource_pools,
    'abilities', v_abilities
  );
end;
$$;

create or replace function public.get_character_armory(
  p_character_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_weapons jsonb := '[]'::jsonb;
  v_magazines jsonb := '[]'::jsonb;
begin
  perform public.initialize_character_weapon_abilities(weapon.id)
  from public.odyssey_character_weapons weapon
  where weapon.character_id = p_character_id;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', w.id,
          'character_id', w.character_id,
          'custom_name', w.custom_name,
          'name', coalesce(nullif(trim(w.custom_name), ''), wm.name),
          'notes', w.notes,
          'sort_order', w.sort_order,
          'active_profile_id', w.active_profile_id,
          'data', coalesce(w.data, '{}'::jsonb),
          'equipped_slot', w.equipped_slot,
          'model',
            jsonb_build_object(
              'id', wm.id,
              'code', wm.code,
              'name', wm.name,
              'weapon_class', mwc.code,
              'weapon_class_name', mwc.name,
              'linked_skill', mskill.code,
              'linked_skill_name', mskill.name,
              'caliber', mcal.code,
              'caliber_name', mcal.name,
              'base_accuracy_bonus', wm.base_accuracy_bonus,
              'base_melee_damage', wm.base_melee_damage,
              'range_profile', mrp.code,
              'range_profile_name', mrp.name,
              'tags', wm.tags
            ),
          'active_profile', runtime.active_profile_json,
          'profiles', runtime.profiles_json,
          'features', coalesce(runtime.features_bundle->'features', '[]'::jsonb),
          'loaded_magazine', coalesce(runtime.active_profile_json->'loaded_magazine', 'null'::jsonb),
          'selected_fire_mode', coalesce(runtime.active_profile_json->'selected_fire_mode', 'null'::jsonb),
          'available_fire_modes', coalesce(runtime.active_profile_json->'available_fire_modes', '[]'::jsonb),
          'compatible_magazines', coalesce(runtime.active_profile_json->'compatible_magazines', '[]'::jsonb),
          'lock_state', public.odyssey_get_weapon_lock_state(w.character_id, w.id),
          'weapon_abilities',
            coalesce(
              (
                select jsonb_agg(
                  jsonb_build_object(
                    'id', ability.id,
                    'character_weapon_id', w.id,
                    'ability_def_id', ability.ability_def_id,
                    'code', def.code,
                    'name', def.name,
                    'ability_kind', def.ability_kind,
                    'activation_type', def.activation_type,
                    'effect_mode', def.effect_mode,
                    'attack_type', def.attack_type,
                    'effective_level', greatest(coalesce(skill.level, ability.learned_level, 0), 0),
                    'is_enabled', ability.is_enabled,
                    'is_hidden', ability.is_hidden,
                    'current_cooldown_rounds', ability.current_cooldown_rounds,
                    'current_charges', ability.current_charges,
                    'max_charges', ability.max_charges,
                    'required_profile_id', nullif(trim(coalesce(ability.data->>'required_profile_id', '')), ''),
                    'required_profile_code', nullif(trim(coalesce(ability.data->>'required_profile_code', '')), ''),
                    'is_available_for_active_profile',
                      case
                        when nullif(trim(coalesce(ability.data->>'required_profile_id', '')), '') is null then true
                        else w.active_profile_id::text = nullif(trim(coalesce(ability.data->>'required_profile_id', '')), '')
                      end
                  )
                  order by ability.sort_order, def.sort_order, def.code
                )
                from public.odyssey_character_abilities ability
                join public.odyssey_ability_defs def on def.id = ability.ability_def_id
                left join public.odyssey_character_skills skill
                  on skill.character_id = ability.character_id
                 and skill.skill_def_id = def.linked_skill_id
                where ability.character_id = p_character_id
                  and ability.source_character_weapon_id = w.id
              ),
              '[]'::jsonb
            )
        )
        order by w.sort_order, coalesce(nullif(trim(w.custom_name), ''), wm.name), w.id
      ),
      '[]'::jsonb
    )
  into v_weapons
  from public.odyssey_character_weapons w
  join public.odyssey_weapon_model_defs wm on wm.id = w.weapon_model_id
  join public.odyssey_weapon_class_defs mwc on mwc.id = wm.weapon_class_id
  join public.odyssey_skill_defs mskill on mskill.id = wm.linked_skill_id
  left join public.odyssey_caliber_defs mcal on mcal.id = wm.caliber_id
  join public.odyssey_range_profile_defs mrp on mrp.id = wm.range_profile_id
  left join lateral (
    select
      public.odyssey_get_active_character_weapon_profile(w.id) as active_profile_json,
      public.odyssey_get_character_weapon_profiles(w.id) as profiles_json,
      public.get_character_weapon_features(w.id) as features_bundle
  ) runtime on true
  where w.character_id = p_character_id;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', cm.id,
          'character_id', cm.character_id,
          'custom_name', cm.custom_name,
          'name', coalesce(nullif(trim(cm.custom_name), ''), md.name),
          'notes', cm.notes,
          'current_rounds', cm.current_rounds,
          'magazine_def',
            jsonb_build_object(
              'id', md.id,
              'code', md.code,
              'name', md.name,
              'capacity', md.capacity,
              'caliber', caliber.code,
              'caliber_name', caliber.name
            ),
          'ammo_type',
            jsonb_build_object(
              'id', ammo.id,
              'code', ammo.code,
              'name', ammo.name,
              'caliber', ammo_caliber.code,
              'caliber_name', ammo_caliber.name
            )
        )
        order by md.sort_order, md.name, cm.created_at, cm.id
      ),
      '[]'::jsonb
    )
  into v_magazines
  from public.odyssey_character_magazines cm
  join public.odyssey_magazine_defs md on md.id = cm.magazine_def_id
  join public.odyssey_caliber_defs caliber on caliber.id = md.caliber_id
  join public.odyssey_ammo_type_defs ammo on ammo.id = cm.ammo_type_id
  join public.odyssey_caliber_defs ammo_caliber on ammo_caliber.id = ammo.caliber_id
  where cm.character_id = p_character_id;

  return jsonb_build_object(
    'character_id', p_character_id,
    'weapons', coalesce(v_weapons, '[]'::jsonb),
    'magazines', coalesce(v_magazines, '[]'::jsonb)
  );
end;
$$;

create or replace function public.add_character_effect(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_character_id uuid := nullif(trim(coalesce(p_payload->>'character_id', '')), '')::uuid;
  v_effect_code text := lower(trim(coalesce(p_payload->>'effect_code', '')));
  v_effect_key text := trim(coalesce(p_payload->>'effect_key', ''));
  v_name text := trim(coalesce(p_payload->>'name', ''));
  v_description text := coalesce(p_payload->>'description', '');
  v_duration_type text := lower(trim(coalesce(p_payload->>'duration_type', '')));
  v_rounds_left integer := nullif(trim(coalesce(p_payload->>'rounds_left', '')), '')::integer;
  v_source text := coalesce(p_payload->>'source', '');
  v_source_type text := coalesce(p_payload->>'source_type', '');
  v_source_id uuid := nullif(trim(coalesce(p_payload->>'source_id', '')), '')::uuid;
  v_source_character_id uuid := nullif(trim(coalesce(p_payload->>'source_character_id', '')), '')::uuid;
  v_source_character_weapon_id uuid := nullif(trim(coalesce(p_payload->>'source_character_weapon_id', '')), '')::uuid;
  v_created_by text := trim(coalesce(p_payload->>'created_by', ''));
  v_payload_data jsonb := case when jsonb_typeof(p_payload->'data') = 'object' then p_payload->'data' else '{}'::jsonb end;
  v_payload_category text := lower(trim(coalesce(p_payload->>'category', '')));
  v_stacks integer := greatest(coalesce(nullif(trim(coalesce(p_payload->>'stacks', '')), '')::integer, 1), 1);
  v_effect_def public.odyssey_effect_defs%rowtype;
  v_stacking_mode text := 'stack';
  v_merged_data jsonb := '{}'::jsonb;
  v_existing_effect_id uuid := null;
  v_inserted_id uuid := null;
  v_refresh jsonb := '{}'::jsonb;
  v_effective_stats jsonb := '{}'::jsonb;
  v_effect_json jsonb := '{}'::jsonb;
begin
  if v_character_id is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'message', 'character_id is required.'
    );
  end if;

  if not exists (
    select 1
    from public.odyssey_characters c
    where c.id = v_character_id
      and coalesce(c.is_deleted, false) = false
  ) then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'character_id', v_character_id
    );
  end if;

  if v_source_character_weapon_id is not null and not exists (
    select 1
    from public.odyssey_character_weapons weapon
    where weapon.id = v_source_character_weapon_id
      and weapon.character_id = v_source_character_id
  ) then
    return jsonb_build_object(
      'ok', false,
      'error', 'WEAPON_ABILITY_SOURCE_NOT_AVAILABLE',
      'message', 'Weapon source was not found for this effect.',
      'source_character_weapon_id', v_source_character_weapon_id
    );
  end if;

  if v_effect_code <> '' then
    select *
    into v_effect_def
    from public.odyssey_effect_defs d
    where d.code = v_effect_code;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'EFFECT_DEF_NOT_FOUND',
        'effect_code', v_effect_code
      );
    end if;
  end if;

  if v_payload_category <> '' and v_payload_category not in ('buff', 'debuff', 'condition', 'combat', 'psionic', 'equipment', 'weapon', 'armor', 'narrative', 'custom') then
    v_payload_category := 'custom';
  end if;

  if v_effect_def.id is not null then
    v_effect_key := coalesce(nullif(v_effect_key, ''), v_effect_def.code);
    v_name := coalesce(nullif(v_name, ''), v_effect_def.name);
    v_description := coalesce(nullif(v_description, ''), v_effect_def.description);
    v_duration_type := coalesce(nullif(v_duration_type, ''), v_effect_def.default_duration_type);
    if v_rounds_left is null then
      v_rounds_left := v_effect_def.default_rounds;
    end if;
    v_stacking_mode := v_effect_def.stacking_mode;
    v_merged_data := public.odyssey_merge_effect_data(v_effect_def.data, v_payload_data);
  else
    v_stacking_mode := 'stack';
    if v_payload_category = '' then
      v_payload_category := 'custom';
    end if;
    v_merged_data := public.odyssey_merge_effect_data('{}'::jsonb, v_payload_data);
  end if;

  if v_payload_category <> '' then
    v_merged_data := jsonb_set(v_merged_data, '{category}', to_jsonb(v_payload_category), true);
  end if;

  v_duration_type := case v_duration_type
    when 'rounds' then 'rounds'
    when 'until_turn_start' then 'until_turn_start'
    when 'until_turn_end' then 'until_turn_end'
    when 'scene' then 'scene'
    when 'until_used' then 'until_used'
    else 'manual'
  end;

  if v_effect_key = '' then
    v_effect_key := regexp_replace(
      regexp_replace(lower(coalesce(nullif(v_name, ''), 'custom_effect')), '[^a-z0-9]+', '_', 'g'),
      '(^_+|_+$)',
      '',
      'g'
    );
  end if;

  if v_effect_key = '' then
    v_effect_key := 'custom_effect';
  end if;

  if v_name = '' then
    v_name := initcap(replace(v_effect_key, '_', ' '));
  end if;

  if v_stacking_mode in ('replace', 'highest', 'lowest') then
    update public.odyssey_character_effects
    set
      is_active = false,
      updated_at = timezone('utc', now())
    where character_id = v_character_id
      and is_active = true
      and effect_key = v_effect_key;
  elsif v_stacking_mode = 'unique' then
    select e.id
    into v_existing_effect_id
    from public.odyssey_character_effects e
    where e.character_id = v_character_id
      and e.is_active = true
      and e.effect_key = v_effect_key
    order by e.created_at desc, e.id desc
    limit 1;

    if v_existing_effect_id is not null then
      v_effective_stats := public.get_effective_character_stats(v_character_id);
      select jsonb_build_object(
        'id', e.id,
        'effect_def_id', e.effect_def_id,
        'code', coalesce(d.code, e.effect_key),
        'effect_key', e.effect_key,
        'name', e.name,
        'category', coalesce(d.category, nullif(e.data->>'category', ''), 'custom'),
        'description', e.description,
        'source', e.source,
        'source_type', e.source_type,
        'source_id', e.source_id,
        'source_character_id', e.source_character_id,
        'source_character_weapon_id', e.source_character_weapon_id,
        'duration_type', e.duration_type,
        'rounds_left', e.rounds_left,
        'stacks', e.stacks,
        'data', e.data,
        'created_by', e.created_by,
        'created_at', e.created_at,
        'updated_at', e.updated_at
      )
      into v_effect_json
      from public.odyssey_character_effects e
      left join public.odyssey_effect_defs d on d.id = e.effect_def_id
      where e.id = v_existing_effect_id;

      return jsonb_build_object(
        'ok', true,
        'created', false,
        'character_id', v_character_id,
        'effect', v_effect_json,
        'effective_stats', v_effective_stats,
        'combat_state',
          coalesce(
            (
              select jsonb_build_object(
                'character_id', s.character_id,
                'campaign_id', s.campaign_id,
                'room_id', s.room_id,
                'body_summary', s.body_summary,
                'armor_summary', s.armor_summary,
                'active_effects', s.active_effects,
                'active_penalties', s.active_penalties,
                'effective_stats', s.effective_stats,
                'combat_flags', s.combat_flags,
                'overlay_text', s.overlay_text,
                'overlay_data', s.overlay_data,
                'tracker_minor', s.tracker_minor,
                'tracker_serious', s.tracker_serious,
                'is_alive', s.is_alive,
                'is_conscious', s.is_conscious,
                'state_version', s.state_version,
                'updated_at', s.updated_at
              )
              from public.odyssey_character_combat_state s
              where s.character_id = v_character_id
            ),
            '{}'::jsonb
          )
      );
    end if;
  end if;

  insert into public.odyssey_character_effects (
    character_id,
    effect_def_id,
    effect_key,
    name,
    description,
    source,
    source_type,
    source_id,
    source_character_id,
    source_character_weapon_id,
    duration_type,
    rounds_left,
    stacks,
    data,
    is_active,
    created_by
  )
  values (
    v_character_id,
    v_effect_def.id,
    v_effect_key,
    v_name,
    v_description,
    v_source,
    v_source_type,
    v_source_id,
    v_source_character_id,
    v_source_character_weapon_id,
    v_duration_type,
    v_rounds_left,
    v_stacks,
    v_merged_data,
    true,
    v_created_by
  )
  returning id into v_inserted_id;

  v_refresh := public.odyssey_refresh_character_combat_state(v_character_id);
  v_effective_stats := public.get_effective_character_stats(v_character_id);

  select jsonb_build_object(
    'id', e.id,
    'effect_def_id', e.effect_def_id,
    'code', coalesce(d.code, e.effect_key),
    'effect_key', e.effect_key,
    'name', e.name,
    'category', coalesce(d.category, nullif(e.data->>'category', ''), 'custom'),
    'description', e.description,
    'source', e.source,
    'source_type', e.source_type,
    'source_id', e.source_id,
    'source_character_id', e.source_character_id,
    'source_character_weapon_id', e.source_character_weapon_id,
    'duration_type', e.duration_type,
    'rounds_left', e.rounds_left,
    'stacks', e.stacks,
    'data', e.data,
    'created_by', e.created_by,
    'created_at', e.created_at,
    'updated_at', e.updated_at
  )
  into v_effect_json
  from public.odyssey_character_effects e
  left join public.odyssey_effect_defs d on d.id = e.effect_def_id
  where e.id = v_inserted_id;

  return jsonb_build_object(
    'ok', true,
    'created', true,
    'character_id', v_character_id,
    'effect', v_effect_json,
    'effective_stats', v_effective_stats,
    'combat_state', coalesce(v_refresh->'combat_state', '{}'::jsonb)
  );
end;
$$;

create or replace function public.odyssey_use_ability_with_weapon_support(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_character_ability_id uuid := nullif(trim(coalesce(p_payload->>'character_ability_id', '')), '')::uuid;
  v_character_id uuid := nullif(trim(coalesce(p_payload->>'character_id', '')), '')::uuid;
  v_ability_code text := lower(trim(coalesce(p_payload->>'ability_code', '')));
  v_target_character_id uuid := nullif(trim(coalesce(p_payload->>'target_character_id', '')), '')::uuid;
  v_target_body_part_id uuid := nullif(trim(coalesce(p_payload->>'target_body_part_id', '')), '')::uuid;
  v_target_armor_item_id uuid := nullif(trim(coalesce(p_payload->>'target_armor_item_id', '')), '')::uuid;
  v_scene_id text := coalesce(nullif(trim(coalesce(p_payload->>'scene_id', '')), ''), '');
  v_created_by text := coalesce(nullif(trim(coalesce(p_payload->>'created_by', '')), ''), '');
  v_encounter_id uuid := nullif(trim(coalesce(p_payload->>'encounter_id', '')), '')::uuid;
  v_ability record;
  v_level record;
  v_effective_level integer := 0;
  v_target_part record;
  v_resource_result jsonb := '{}'::jsonb;
  v_effect_result jsonb := '{}'::jsonb;
  v_effect_results jsonb := '[]'::jsonb;
  v_merged_ability_data jsonb := '{}'::jsonb;
  v_effect_payload_data jsonb := '{}'::jsonb;
  v_effect_code text := '';
  v_effect_links jsonb := '[]'::jsonb;
  v_effect_link jsonb := '{}'::jsonb;
  v_link_data jsonb := '{}'::jsonb;
  v_link_effect_code text := '';
  v_link_effect_id uuid := null;
  v_effect_instance_data jsonb := '{}'::jsonb;
  v_effect_context jsonb := '{}'::jsonb;
  v_refresh jsonb := '{}'::jsonb;
  v_log_id uuid := null;
  v_log_data jsonb := '{}'::jsonb;
  v_message text := '';
  v_source_character_weapon_id uuid := null;
begin
  if v_character_ability_id is null then
    if v_character_id is null or v_ability_code = '' then
      return jsonb_build_object(
        'ok', false,
        'error', 'ABILITY_NOT_FOUND',
        'message', 'character_ability_id or character_id + ability_code is required.'
      );
    end if;

    select ability.id
    into v_character_ability_id
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    where ability.character_id = v_character_id
      and def.code = v_ability_code
      and ability.is_enabled = true
    order by ability.sort_order, ability.created_at, ability.id
    limit 1;
  end if;

  select
    ability.*,
    def.code as ability_code,
    def.name as ability_name,
    def.ability_kind,
    def.source_type,
    def.activation_type,
    def.target_type,
    def.effect_mode,
    def.attack_type,
    def.resource_mode,
    def.resource_pool_code,
    def.resource_item_code,
    def.description as ability_description,
    def.effect_data as def_effect_data,
    def.data as def_data
  into v_ability
  from public.odyssey_character_abilities ability
  join public.odyssey_ability_defs def on def.id = ability.ability_def_id
  where ability.id = v_character_ability_id
    and ability.is_enabled = true
  for update of ability;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_NOT_FOUND',
      'character_ability_id', v_character_ability_id
    );
  end if;

  v_character_id := v_ability.character_id;
  v_source_character_weapon_id := v_ability.source_character_weapon_id;
  v_effective_level := public.odyssey_get_character_ability_effective_level(v_character_ability_id);

  select *
  into v_level
  from public.odyssey_ability_level_defs level_data
  where level_data.ability_def_id = v_ability.ability_def_id
    and level_data.ability_level <= v_effective_level
  order by level_data.ability_level desc
  limit 1;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_LEVEL_NOT_AVAILABLE',
      'character_ability_id', v_character_ability_id,
      'effective_level', v_effective_level
    );
  end if;

  v_merged_ability_data :=
    coalesce(v_ability.def_data, '{}'::jsonb)
    || coalesce(v_ability.data, '{}'::jsonb)
    || coalesce(v_level.data, '{}'::jsonb);

  v_effect_payload_data := public.odyssey_merge_effect_data(
    public.odyssey_merge_effect_data(
      coalesce(v_ability.def_effect_data, '{}'::jsonb),
      case
        when jsonb_typeof(v_ability.data->'effect_data') = 'object' then v_ability.data->'effect_data'
        else '{}'::jsonb
      end
    ),
    coalesce(v_level.effect_data, '{}'::jsonb)
  );

  v_effect_code := lower(trim(coalesce(
    nullif(v_merged_ability_data->>'effect_code', ''),
    nullif(v_effect_payload_data->>'effect_code', ''),
    ''
  )));

  if jsonb_typeof(v_merged_ability_data->'effect_links') = 'array' then
    v_effect_links := v_merged_ability_data->'effect_links';
  end if;

  if v_ability.ability_kind = 'attack' or v_ability.effect_mode = 'attack' then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_REQUIRES_ATTACK_RESOLUTION',
      'message', 'Attack abilities must be resolved through perform_attack.',
      'character_ability_id', v_character_ability_id
    );
  end if;

  if v_ability.target_type = 'self' then
    v_target_character_id := v_character_id;
  elsif v_target_character_id is null then
    v_target_character_id := v_character_id;
  end if;

  v_resource_result := public.odyssey_consume_character_ability_cost(v_character_ability_id);
  if coalesce((v_resource_result->>'ok')::boolean, false) = false then
    return v_resource_result;
  end if;

  if coalesce(v_level.cooldown_rounds, 0) > 0 then
    update public.odyssey_character_abilities
    set current_cooldown_rounds = v_level.cooldown_rounds
    where id = v_character_ability_id;
  end if;

  v_effect_context := jsonb_strip_nulls(
    jsonb_build_object(
      'selected_body_part_id', case when v_target_body_part_id is not null then v_target_body_part_id::text else null end,
      'selected_armor_item_id', case when v_target_armor_item_id is not null then v_target_armor_item_id::text else null end,
      'source_character_weapon_id', case when v_source_character_weapon_id is not null then v_source_character_weapon_id::text else null end
    )
  );

  if v_ability.effect_mode = 'apply_effect' then
    if jsonb_typeof(v_effect_links) = 'array' and jsonb_array_length(v_effect_links) > 0 then
      for v_effect_link in
        select value
        from jsonb_array_elements(v_effect_links)
        order by coalesce(nullif(value->>'sort_order', '')::integer, 0)
      loop
        v_link_effect_code := lower(trim(coalesce(v_effect_link->>'effect_code', '')));
        v_link_effect_id := nullif(trim(coalesce(v_effect_link->>'effect_def_id', '')), '')::uuid;
        if v_link_effect_code = '' and v_link_effect_id is not null then
          select effect_def.code
          into v_link_effect_code
          from public.odyssey_effect_defs effect_def
          where effect_def.id = v_link_effect_id;
        end if;

        if v_link_effect_code = '' then
          return jsonb_build_object(
            'ok', false,
            'error', 'ABILITY_EFFECT_NOT_CONFIGURED',
            'message', 'One of the linked effects is missing effect_def_id/effect_code.',
            'character_ability_id', v_character_ability_id
          );
        end if;

        v_link_data := case
          when jsonb_typeof(v_effect_link->'data') = 'object' then v_effect_link->'data'
          else '{}'::jsonb
        end;
        v_effect_instance_data := public.odyssey_merge_effect_data(v_effect_payload_data, v_link_data);
        if v_effect_context <> '{}'::jsonb then
          v_effect_instance_data := public.odyssey_merge_effect_data(
            v_effect_instance_data,
            jsonb_build_object('context', v_effect_context)
          );
        end if;

        v_effect_result := public.add_character_effect(
          jsonb_build_object(
            'character_id', v_target_character_id,
            'effect_code', v_link_effect_code,
            'effect_key',
              case
                when v_source_character_weapon_id is not null
                  then public.odyssey_build_weapon_ability_effect_key(v_source_character_weapon_id, v_ability.ability_code, v_link_effect_code)
                else v_ability.ability_code || ':' || v_link_effect_code
              end,
            'name', v_ability.ability_name,
            'description', v_ability.ability_description,
            'category',
              case
                when v_ability.source_type = 'psionic' then 'psionic'
                when v_ability.source_type in ('implant', 'prosthetic', 'equipment', 'item') then 'equipment'
                when v_source_character_weapon_id is not null then 'weapon'
                else 'custom'
              end,
            'duration_type', case when v_level.duration_rounds is not null and v_level.duration_rounds > 0 then 'rounds' else 'manual' end,
            'rounds_left', v_level.duration_rounds,
            'source', v_ability.ability_name,
            'source_type', case when v_source_character_weapon_id is not null then 'weapon_ability' else v_ability.source_type end,
            'source_id', v_character_ability_id::text,
            'source_character_id', v_character_id::text,
            'source_character_weapon_id', case when v_source_character_weapon_id is not null then v_source_character_weapon_id::text else null end,
            'data',
              public.odyssey_merge_effect_data(
                v_effect_instance_data,
                jsonb_strip_nulls(jsonb_build_object(
                  'scope', case when v_source_character_weapon_id is not null then 'weapon' else null end,
                  'source_character_weapon_id', case when v_source_character_weapon_id is not null then v_source_character_weapon_id::text else null end,
                  'source_character_ability_id', v_character_ability_id::text
                ))
              ),
            'created_by', v_created_by
          )
        );

        if coalesce((v_effect_result->>'ok')::boolean, false) = false then
          return v_effect_result;
        end if;

        v_refresh := coalesce(v_effect_result->'combat_state', v_refresh);
        v_effect_results := v_effect_results || jsonb_build_array(coalesce(v_effect_result->'effect', '{}'::jsonb));
      end loop;

      v_effect_result := jsonb_build_object(
        'ok', true,
        'effects', v_effect_results,
        'combat_state', v_refresh
      );
    elsif v_effect_code <> '' then
      v_effect_instance_data := v_effect_payload_data;
      if v_effect_context <> '{}'::jsonb then
        v_effect_instance_data := public.odyssey_merge_effect_data(
          v_effect_instance_data,
          jsonb_build_object('context', v_effect_context)
        );
      end if;

      v_effect_result := public.add_character_effect(
        jsonb_build_object(
          'character_id', v_target_character_id,
          'effect_code', v_effect_code,
          'effect_key',
            case
              when v_source_character_weapon_id is not null
                then public.odyssey_build_weapon_ability_effect_key(v_source_character_weapon_id, v_ability.ability_code, null)
              else v_ability.ability_code
            end,
          'name', v_ability.ability_name,
          'description', v_ability.ability_description,
          'category',
            case
              when v_ability.source_type = 'psionic' then 'psionic'
              when v_ability.source_type in ('implant', 'prosthetic', 'equipment', 'item') then 'equipment'
              when v_source_character_weapon_id is not null then 'weapon'
              else 'custom'
            end,
          'duration_type', case when v_level.duration_rounds is not null and v_level.duration_rounds > 0 then 'rounds' else 'manual' end,
          'rounds_left', v_level.duration_rounds,
          'source', v_ability.ability_name,
          'source_type', case when v_source_character_weapon_id is not null then 'weapon_ability' else v_ability.source_type end,
          'source_id', v_character_ability_id::text,
          'source_character_id', v_character_id::text,
          'source_character_weapon_id', case when v_source_character_weapon_id is not null then v_source_character_weapon_id::text else null end,
          'data',
            public.odyssey_merge_effect_data(
              v_effect_instance_data,
              jsonb_strip_nulls(jsonb_build_object(
                'scope', case when v_source_character_weapon_id is not null then 'weapon' else null end,
                'source_character_weapon_id', case when v_source_character_weapon_id is not null then v_source_character_weapon_id::text else null end,
                'source_character_ability_id', v_character_ability_id::text
              ))
            ),
          'created_by', v_created_by
        )
      );

      if coalesce((v_effect_result->>'ok')::boolean, false) = false then
        return v_effect_result;
      end if;

      v_refresh := coalesce(v_effect_result->'combat_state', '{}'::jsonb);
    else
      v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
      v_effect_result := jsonb_build_object(
        'ok', true,
        'narrative_only', true,
        'combat_state', v_refresh
      );
    end if;
  elsif v_ability.effect_mode = 'grant_special' then
    select
      b.id,
      b.character_id,
      b.part_key,
      b.max_critical,
      b.critical
    into v_target_part
    from public.odyssey_character_body_parts b
    left join public.odyssey_body_part_defs d on d.id = b.body_part_def_id
    where b.character_id = v_target_character_id
      and coalesce(d.code, public.odyssey_normalize_part_code(b.part_key)) = 'special'
    limit 1
    for update of b;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'SPECIAL_BODY_PART_NOT_FOUND',
        'target_character_id', v_target_character_id
      );
    end if;

    update public.odyssey_character_body_parts
    set
      natural_armor_value = greatest(coalesce(v_level.special_armor_value, 0), 0),
      max_critical = greatest(coalesce(v_level.special_max_critical, max_critical), 0),
      critical = 0,
      serious = 0,
      minor = 0,
      disabled = false,
      destroyed = false
    where id = v_target_part.id;

    perform public.recompute_character_armor(v_target_character_id);
    v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
    v_effect_result := jsonb_build_object(
      'ok', true,
      'special', public.odyssey_get_character_body_part_state(v_target_part.id),
      'combat_state', v_refresh
    );
  else
    v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
    v_effect_result := jsonb_build_object(
      'ok', true,
      'narrative_only', true,
      'combat_state', v_refresh
    );
  end if;

  v_message := format(
    '%s uses %s.',
    coalesce(
      (
        select coalesce(nullif(trim(c.resources->>'name'), ''), c.character_key)
        from public.odyssey_characters c
        where c.id = v_character_id
      ),
      v_character_id::text
    ),
    v_ability.ability_name
  );

  v_log_data := jsonb_build_object(
    'type', 'ability_use',
    'ok', true,
    'character_ability_id', v_character_ability_id,
    'character_id', v_character_id,
    'target_character_id', v_target_character_id,
    'target_body_part_id', v_target_body_part_id,
    'target_armor_item_id', v_target_armor_item_id,
    'source_character_weapon_id', v_source_character_weapon_id,
    'ability',
      jsonb_build_object(
        'code', v_ability.ability_code,
        'name', v_ability.ability_name,
        'ability_kind', v_ability.ability_kind,
        'source_type', v_ability.source_type,
        'effect_mode', v_ability.effect_mode,
        'effective_level', v_effective_level
      ),
    'resource', v_resource_result,
    'result', v_effect_result
  );

  insert into public.odyssey_combat_log (
    campaign_id,
    room_id,
    scene_id,
    encounter_id,
    actor_character_id,
    target_character_id,
    event_type,
    message,
    data,
    created_by
  )
  values (
    coalesce((select c.campaign_id from public.odyssey_characters c where c.id = v_character_id), ''),
    coalesce((select c.room_id from public.odyssey_characters c where c.id = v_character_id), ''),
    v_scene_id,
    v_encounter_id,
    v_character_id,
    v_target_character_id,
    'ability_use',
    v_message,
    v_log_data,
    v_created_by
  )
  returning id into v_log_id;

  perform public.odyssey_trim_combat_log(v_encounter_id, coalesce((select c.room_id from public.odyssey_characters c where c.id = v_character_id), ''));

  return jsonb_build_object(
    'ok', true,
    'character_ability_id', v_character_ability_id,
    'character_id', v_character_id,
    'target_character_id', v_target_character_id,
    'target_body_part_id', v_target_body_part_id,
    'target_armor_item_id', v_target_armor_item_id,
    'source_character_weapon_id', v_source_character_weapon_id,
    'ability',
      jsonb_build_object(
        'code', v_ability.ability_code,
        'name', v_ability.ability_name,
        'ability_kind', v_ability.ability_kind,
        'source_type', v_ability.source_type,
        'effect_mode', v_ability.effect_mode,
        'effective_level', v_effective_level
      ),
    'resource', v_resource_result,
    'result', v_effect_result,
    'combat_state', v_refresh,
    'log_id', v_log_id
  );
end;
$$;

create or replace function public.use_ability(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_character_weapon_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_weapon_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'character_id', v_payload->>'attacker_character_id'));
  v_character_ability_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_ability_id');
  v_ability_code text := lower(trim(coalesce(v_payload->>'ability_code', '')));
  v_lock_state jsonb := '{}'::jsonb;
  v_ability record;
  v_required_profile_id uuid := null;
begin
  if v_character_ability_id is not null or (v_character_id is not null and v_ability_code <> '') then
    select
      ability.id,
      ability.character_id,
      ability.source_character_weapon_id,
      ability.is_enabled,
      ability.is_hidden,
      ability.data,
      def.code as ability_code
    into v_ability
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    where (
      (v_character_ability_id is not null and ability.id = v_character_ability_id)
      or (
        v_character_ability_id is null
        and ability.character_id = v_character_id
        and def.code = v_ability_code
      )
    )
    order by ability.sort_order, ability.created_at, ability.id
    limit 1;

    if found and v_ability.source_character_weapon_id is not null then
      v_character_weapon_id := v_ability.source_character_weapon_id;
      v_character_id := v_ability.character_id;
      v_required_profile_id := public.odyssey_try_parse_uuid(v_ability.data->>'required_profile_id');

      if coalesce(v_ability.is_enabled, false) = false
         or coalesce(v_ability.is_hidden, false) = true
         or coalesce((v_ability.data->>'source_removed')::boolean, false) then
        return jsonb_build_object(
          'ok', false,
          'error', 'WEAPON_ABILITY_SOURCE_NOT_AVAILABLE',
          'message', 'This weapon ability is no longer available on the source weapon.',
          'character_ability_id', v_ability.id,
          'character_weapon_id', v_character_weapon_id
        );
      end if;

      if not exists (
        select 1
        from public.odyssey_character_weapons weapon
        where weapon.id = v_character_weapon_id
          and weapon.character_id = v_character_id
      ) then
        return jsonb_build_object(
          'ok', false,
          'error', 'WEAPON_ABILITY_SOURCE_NOT_AVAILABLE',
          'message', 'The source weapon for this ability is not available.',
          'character_ability_id', v_ability.id,
          'character_weapon_id', v_character_weapon_id
        );
      end if;

      if v_required_profile_id is not null and not exists (
        select 1
        from public.odyssey_character_weapons weapon
        where weapon.id = v_character_weapon_id
          and weapon.active_profile_id = v_required_profile_id
      ) then
        return jsonb_build_object(
          'ok', false,
          'error', 'ABILITY_NOT_AVAILABLE_FOR_WEAPON_PROFILE',
          'message', 'This weapon ability is not available for the currently active weapon profile.',
          'character_ability_id', v_ability.id,
          'character_weapon_id', v_character_weapon_id,
          'required_profile_id', v_required_profile_id
        );
      end if;

      v_payload := v_payload || jsonb_build_object(
        'character_weapon_id', v_character_weapon_id::text,
        'character_id', v_character_id::text
      );
    end if;
  end if;

  if v_character_weapon_id is not null and v_character_id is not null then
    v_lock_state := public.odyssey_get_weapon_lock_state(v_character_id, v_character_weapon_id);
    if coalesce((v_lock_state->>'locked')::boolean, false)
       or coalesce((v_lock_state->>'actor_attack_locked')::boolean, false) then
      return jsonb_build_object(
        'ok', false,
        'error', coalesce(v_lock_state->>'error', 'WEAPON_LOCKED'),
        'message', coalesce(v_lock_state->>'message', 'Weapon is locked.')
      );
    end if;
  end if;

  return public.odyssey_use_ability_with_weapon_support(v_payload);
end;
$$;

grant execute on function public.odyssey_sync_weapon_model_ability_links_from_legacy(uuid) to anon, authenticated;
grant execute on function public.odyssey_build_weapon_ability_effect_key(uuid, text, text) to anon, authenticated;
grant execute on function public.initialize_character_weapon_abilities(uuid) to anon, authenticated;
grant execute on function public.odyssey_sync_character_weapon_abilities_for_model(uuid) to anon, authenticated;
grant execute on function public.odyssey_use_ability_with_weapon_support(jsonb) to anon, authenticated;

-- ===== END 88_weapon_abilities.sql =====


-- ===== BEGIN 89_creator_definition_refresh_and_armor_pierce.sql =====

-- 89_creator_definition_refresh_and_armor_pierce.sql

create or replace function public.get_character_effect_summary(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_active_effects jsonb := '[]'::jsonb;
  v_modifier_rows jsonb := '[]'::jsonb;
  v_attribute_modifiers jsonb := '{}'::jsonb;
  v_skill_modifiers jsonb := '{}'::jsonb;
  v_skill_minimums jsonb := '{}'::jsonb;
  v_attack_accuracy integer := 0;
  v_defense integer := 0;
  v_damage integer := 0;
  v_armor integer := 0;
  v_armor_pierce integer := 0;
  v_movement_m integer := 0;
  v_action_count integer := 0;
  v_concentration_slots integer := 0;
  v_aim_difficulty integer := 0;
  v_range integer := 0;
  v_skip_main_action boolean := false;
  v_skip_movement boolean := false;
  v_consumes_full_turn boolean := false;
  v_helpless boolean := false;
  v_fatal_on_any_damage_if_unprotected boolean := false;
  v_suppress_movement boolean := false;
  v_cannot_leave_cover boolean := false;
  v_expires_after_attack boolean := false;
  v_expires_after_turn boolean := false;
  v_requires_concentration boolean := false;
begin
  with active_effect_rows as (
    select
      effect_rows.id,
      effect_rows.character_id,
      effect_rows.effect_def_id,
      effect_rows.code,
      effect_rows.effect_key,
      effect_rows.name,
      effect_rows.category,
      effect_rows.description,
      effect_rows.source,
      effect_rows.source_type,
      effect_rows.source_id,
      effect_rows.source_character_id,
      effect_rows.source_character_weapon_id,
      effect_rows.duration_type,
      effect_rows.rounds_left,
      effect_rows.stacks,
      effect_rows.data,
      effect_rows.stacking_mode,
      effect_rows.is_negative,
      effect_rows.is_narrative,
      effect_rows.created_by,
      effect_rows.created_at,
      effect_rows.updated_at
    from (
      select
        e.id,
        e.character_id,
        e.effect_def_id,
        coalesce(d.code, nullif(e.effect_key, ''), 'custom') as code,
        e.effect_key,
        e.name,
        coalesce(d.category, nullif(e.data->>'category', ''), 'custom') as category,
        e.description,
        e.source,
        coalesce(e.source_type, '') as source_type,
        e.source_id,
        e.source_character_id,
        e.source_character_weapon_id,
        e.duration_type,
        e.rounds_left,
        e.stacks,
        e.data,
        coalesce(d.stacking_mode, 'stack') as stacking_mode,
        coalesce(d.is_negative, false) as is_negative,
        coalesce(d.is_narrative, false) as is_narrative,
        e.created_by,
        e.created_at,
        e.updated_at
      from public.odyssey_character_effects e
      left join public.odyssey_effect_defs d on d.id = e.effect_def_id
      where e.character_id = p_character_id
        and e.is_active = true

      union all

      select
        item.id,
        item.character_id,
        null::uuid as effect_def_id,
        coalesce(nullif(trim(model.code), ''), 'equipment') as code,
        'equipment:' || item.id::text as effect_key,
        coalesce(nullif(trim(item.custom_name), ''), model.name) as name,
        coalesce(nullif(trim(item_effect.effect_data->>'category'), ''), 'equipment') as category,
        coalesce(
          nullif(trim(item_effect.effect_data->>'description'), ''),
          nullif(trim(model.description), ''),
          coalesce(nullif(trim(item.custom_name), ''), model.name)
        ) as description,
        coalesce(nullif(trim(item.custom_name), ''), model.name) as source,
        coalesce(nullif(trim(model.item_type), ''), 'equipment') as source_type,
        item.id as source_id,
        item.character_id as source_character_id,
        null::uuid as source_character_weapon_id,
        'manual'::text as duration_type,
        null::integer as rounds_left,
        1 as stacks,
        item_effect.effect_data as data,
        coalesce(nullif(trim(item_effect.effect_data->>'stacking_mode'), ''), 'stack') as stacking_mode,
        coalesce(nullif(trim(item_effect.effect_data->>'is_negative'), '')::boolean, false) as is_negative,
        coalesce(nullif(trim(item_effect.effect_data->>'is_narrative'), '')::boolean, false) as is_narrative,
        ''::text as created_by,
        item.created_at,
        item.updated_at
      from public.odyssey_character_equipment_items item
      join public.odyssey_equipment_model_defs model on model.id = item.equipment_model_id
      cross join lateral (
        select public.odyssey_merge_effect_data(
          coalesce(model.effect_data, '{}'::jsonb),
          case
            when jsonb_typeof(item.data->'effect_data') = 'object' then item.data->'effect_data'
            else '{}'::jsonb
          end
        ) as effect_data
      ) item_effect
      where item.character_id = p_character_id
        and item.is_equipped = true
        and (
          (
            jsonb_typeof(item_effect.effect_data->'modifiers') = 'array'
            and jsonb_array_length(item_effect.effect_data->'modifiers') > 0
          )
          or (
            jsonb_typeof(item_effect.effect_data->'flags') = 'object'
            and item_effect.effect_data->'flags' <> '{}'::jsonb
          )
        )
    ) effect_rows
  ),
  modifier_raw as (
    select
      aer.effect_key,
      aer.code,
      aer.category,
      aer.stacking_mode,
      lower(coalesce(modifier.value->>'target', '')) as target,
      lower(coalesce(modifier.value->>'mode', '')) as mode,
      nullif(trim(coalesce(modifier.value->>'attribute', '')), '') as attribute_ref,
      nullif(trim(coalesce(modifier.value->>'skill_code', modifier.value->>'skill', '')), '') as skill_ref,
      coalesce(nullif(trim(coalesce(modifier.value->>'value', '')), '')::integer, 0) as value
    from active_effect_rows aer
    join lateral jsonb_array_elements(
      case
        when jsonb_typeof(aer.data->'modifiers') = 'array' then aer.data->'modifiers'
        else '[]'::jsonb
      end
    ) modifier(value) on true
    where aer.source_character_weapon_id is null
  ),
  modifier_resolved as (
    select
      raw.effect_key,
      raw.code,
      raw.category,
      raw.stacking_mode,
      raw.target,
      raw.mode,
      case
        when raw.target = 'attribute' then coalesce(attribute_by_id.code, attribute_by_code.code, lower(raw.attribute_ref))
        else null
      end as attribute_code,
      case
        when raw.target = 'skill' then coalesce(skill_by_id.code, skill_by_code.code, lower(raw.skill_ref))
        else null
      end as skill_code,
      raw.value
    from modifier_raw raw
    left join public.odyssey_attribute_defs attribute_by_id
      on attribute_by_id.id = public.odyssey_try_parse_uuid(raw.attribute_ref)
    left join public.odyssey_attribute_defs attribute_by_code
      on lower(attribute_by_code.code) = lower(raw.attribute_ref)
    left join public.odyssey_skill_defs skill_by_id
      on skill_by_id.id = public.odyssey_try_parse_uuid(raw.skill_ref)
    left join public.odyssey_skill_defs skill_by_code
      on lower(skill_by_code.code) = lower(raw.skill_ref)
  ),
  modifier_summary as (
    select
      target,
      attribute_code,
      skill_code,
      array_remove(array_agg(distinct effect_key), null) as effect_keys,
      array_remove(array_agg(distinct code), null) as effect_codes,
      case
        when bool_or(stacking_mode = 'lowest') then min(value)
        when bool_or(stacking_mode = 'highest') then max(value)
        else sum(value)
      end as resolved_value,
      case
        when bool_or(stacking_mode = 'lowest') then 'lowest'
        when bool_or(stacking_mode = 'highest') then 'highest'
        when bool_or(stacking_mode = 'replace') then 'replace'
        when bool_or(stacking_mode = 'unique') then 'unique'
        else 'stack'
      end as aggregation
    from modifier_resolved
    where target <> ''
      and coalesce(mode, '') <> 'set_min'
    group by target, attribute_code, skill_code
  ),
  skill_minimum_summary as (
    select
      skill_code,
      max(value) as minimum_value
    from modifier_resolved
    where target = 'skill'
      and skill_code is not null
      and mode = 'set_min'
    group by skill_code
  ),
  flag_raw as (
    select
      lower(flags.key) as flag_key,
      case
        when jsonb_typeof(flags.value) = 'boolean' then (flags.value #>> '{}')::boolean
        when lower(coalesce(flags.value #>> '{}', 'false')) in ('true', '1', 'yes', 'on') then true
        else false
      end as flag_value
    from active_effect_rows aer
    join lateral jsonb_each(
      case
        when jsonb_typeof(aer.data->'flags') = 'object' then aer.data->'flags'
        else '{}'::jsonb
      end
    ) flags(key, value) on true
    where aer.source_character_weapon_id is null
  )
  select
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'id', id,
            'effect_def_id', effect_def_id,
            'code', code,
            'effect_key', effect_key,
            'name', name,
            'category', category,
            'description', description,
            'source', source,
            'source_type', source_type,
            'source_id', source_id,
            'source_character_id', source_character_id,
            'source_character_weapon_id', source_character_weapon_id,
            'duration_type', duration_type,
            'rounds_left', rounds_left,
            'stacks', stacks,
            'data', data,
            'is_negative', is_negative,
            'is_narrative', is_narrative,
            'created_by', created_by,
            'created_at', created_at,
            'updated_at', updated_at
          )
          order by created_at desc, id
        )
        from active_effect_rows
      ),
      '[]'::jsonb
    ),
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'effect_keys', to_jsonb(effect_keys),
            'effect_codes', to_jsonb(effect_codes),
            'target', target,
            'attribute', attribute_code,
            'skill_code', skill_code,
            'value', resolved_value,
            'aggregation', aggregation,
            'mode', aggregation
          )
          order by target, attribute_code, skill_code
        )
        from modifier_summary
      ),
      '[]'::jsonb
    ),
    coalesce(
      (
        select jsonb_object_agg(attribute_code, resolved_value)
        from modifier_summary
        where target = 'attribute'
          and attribute_code is not null
      ),
      '{}'::jsonb
    ),
    coalesce(
      (
        select jsonb_object_agg(skill_code, resolved_value)
        from modifier_summary
        where target = 'skill'
          and skill_code is not null
      ),
      '{}'::jsonb
    ),
    coalesce(
      (
        select jsonb_object_agg(skill_code, minimum_value)
        from skill_minimum_summary
      ),
      '{}'::jsonb
    ),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'attack_accuracy'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'defense'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'damage'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'armor'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'armor_pierce'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'movement_m'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'action_count'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'concentration_slots'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'aim_difficulty'), 0),
    coalesce((select sum(resolved_value) from modifier_summary where target = 'range'), 0),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'skip_main_action'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'skip_movement'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'consumes_full_turn'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'helpless'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'fatal_on_any_damage_if_unprotected'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'suppress_movement'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'cannot_leave_cover'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'expires_after_attack'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'expires_after_turn'), false),
    coalesce((select bool_or(flag_value) from flag_raw where flag_key = 'requires_concentration'), false)
  into
    v_active_effects,
    v_modifier_rows,
    v_attribute_modifiers,
    v_skill_modifiers,
    v_skill_minimums,
    v_attack_accuracy,
    v_defense,
    v_damage,
    v_armor,
    v_armor_pierce,
    v_movement_m,
    v_action_count,
    v_concentration_slots,
    v_aim_difficulty,
    v_range,
    v_skip_main_action,
    v_skip_movement,
    v_consumes_full_turn,
    v_helpless,
    v_fatal_on_any_damage_if_unprotected,
    v_suppress_movement,
    v_cannot_leave_cover,
    v_expires_after_attack,
    v_expires_after_turn,
    v_requires_concentration;

  return jsonb_build_object(
    'character_id', p_character_id,
    'active_effects', v_active_effects,
    'modifier_rows', v_modifier_rows,
    'modifiers',
      jsonb_build_object(
        'attributes', v_attribute_modifiers,
        'skills', v_skill_modifiers,
        'skills_set_min', v_skill_minimums,
        'attack_accuracy', v_attack_accuracy,
        'defense', v_defense,
        'damage', v_damage,
        'armor', v_armor,
        'armor_pierce', v_armor_pierce,
        'movement_m', v_movement_m,
        'action_count', v_action_count,
        'concentration_slots', v_concentration_slots,
        'aim_difficulty', v_aim_difficulty,
        'range', v_range
      ),
    'flags',
      jsonb_build_object(
        'helpless', v_helpless,
        'skip_main_action', v_skip_main_action,
        'skip_movement', v_skip_movement,
        'consumes_full_turn', v_consumes_full_turn,
        'fatal_on_any_damage_if_unprotected', v_fatal_on_any_damage_if_unprotected,
        'suppress_movement', v_suppress_movement,
        'cannot_leave_cover', v_cannot_leave_cover,
        'expires_after_attack', v_expires_after_attack,
        'expires_after_turn', v_expires_after_turn,
        'requires_concentration', v_requires_concentration
      )
  );
end;
$$;

create or replace function public.odyssey_get_weapon_effect_summary(
  p_character_id uuid,
  p_character_weapon_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_active_effects jsonb := '[]'::jsonb;
  v_attack_accuracy integer := 0;
  v_damage integer := 0;
  v_armor_pierce integer := 0;
  v_aim_difficulty integer := 0;
  v_range integer := 0;
begin
  with active_effect_rows as (
    select
      e.id,
      e.character_id,
      e.effect_def_id,
      coalesce(d.code, nullif(e.effect_key, ''), 'custom') as code,
      e.effect_key,
      e.name,
      coalesce(d.category, nullif(e.data->>'category', ''), 'custom') as category,
      e.description,
      e.source,
      coalesce(e.source_type, '') as source_type,
      e.source_id,
      e.source_character_id,
      e.source_character_weapon_id,
      e.duration_type,
      e.rounds_left,
      e.stacks,
      e.data,
      coalesce(d.stacking_mode, 'stack') as stacking_mode,
      coalesce(d.is_negative, false) as is_negative,
      coalesce(d.is_narrative, false) as is_narrative,
      e.created_by,
      e.created_at,
      e.updated_at
    from public.odyssey_character_effects e
    left join public.odyssey_effect_defs d on d.id = e.effect_def_id
    where e.character_id = p_character_id
      and e.is_active = true
      and e.source_character_weapon_id = p_character_weapon_id
  ),
  modifier_rows as (
    select
      lower(coalesce(modifier.value->>'target', '')) as target,
      coalesce(nullif(trim(coalesce(modifier.value->>'value', '')), '')::integer, 0) as value
    from active_effect_rows aer
    join lateral jsonb_array_elements(
      case
        when jsonb_typeof(aer.data->'modifiers') = 'array' then aer.data->'modifiers'
        else '[]'::jsonb
      end
    ) modifier(value) on true
  )
  select
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'id', id,
            'effect_def_id', effect_def_id,
            'code', code,
            'effect_key', effect_key,
            'name', name,
            'category', category,
            'description', description,
            'source', source,
            'source_type', source_type,
            'source_id', source_id,
            'source_character_id', source_character_id,
            'source_character_weapon_id', source_character_weapon_id,
            'duration_type', duration_type,
            'rounds_left', rounds_left,
            'stacks', stacks,
            'data', data,
            'is_negative', is_negative,
            'is_narrative', is_narrative,
            'created_by', created_by,
            'created_at', created_at,
            'updated_at', updated_at
          )
          order by created_at desc, id
        )
        from active_effect_rows
      ),
      '[]'::jsonb
    ),
    coalesce((select sum(value) from modifier_rows where target = 'attack_accuracy'), 0),
    coalesce((select sum(value) from modifier_rows where target = 'damage'), 0),
    coalesce((select sum(value) from modifier_rows where target = 'armor_pierce'), 0),
    coalesce((select sum(value) from modifier_rows where target = 'aim_difficulty'), 0),
    coalesce((select sum(value) from modifier_rows where target = 'range'), 0)
  into
    v_active_effects,
    v_attack_accuracy,
    v_damage,
    v_armor_pierce,
    v_aim_difficulty,
    v_range;

  return jsonb_build_object(
    'character_id', p_character_id,
    'character_weapon_id', p_character_weapon_id,
    'active_effects', v_active_effects,
    'attack_accuracy', v_attack_accuracy,
    'damage', v_damage,
    'armor_pierce', v_armor_pierce,
    'aim_difficulty', v_aim_difficulty,
    'range', v_range
  );
end;
$$;

create or replace function public.get_effective_character_stats(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_result jsonb := '{}'::jsonb;
  v_force_dead boolean := false;
  v_armor_pierce_modifier integer := 0;
begin
  v_result := public.odyssey_get_effective_character_stats_legacy(p_character_id);

  if coalesce((v_result->>'ok')::boolean, false) = false then
    return v_result;
  end if;

  v_armor_pierce_modifier := coalesce(
    nullif(jsonb_extract_path_text(v_result, 'effect_summary', 'modifiers', 'armor_pierce'), '')::integer,
    0
  );

  v_result := jsonb_set(
    v_result,
    '{derived,armor_pierce_modifier}',
    to_jsonb(v_armor_pierce_modifier),
    true
  );

  select exists(
    select 1
    from public.odyssey_character_effects e
    where e.character_id = p_character_id
      and e.is_active = true
      and coalesce(nullif(e.data#>>'{flags,force_dead}', '')::boolean, false)
  )
  into v_force_dead;

  if v_force_dead then
    v_result := jsonb_set(v_result, '{derived,is_alive}', 'false'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,is_conscious}', 'false'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,helpless}', 'true'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,skip_main_action}', 'true'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,skip_movement}', 'true'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,consumes_full_turn}', 'true'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,main_actions_per_turn}', '0'::jsonb, true);
    v_result := jsonb_set(v_result, '{derived,movement_available_m}', '0'::jsonb, true);
  end if;

  return v_result;
end;
$$;

do $$
begin
  if to_regprocedure('public.odyssey_perform_ability_attack(jsonb)') is not null
     and to_regprocedure('public.odyssey_perform_ability_attack_legacy(jsonb)') is null then
    alter function public.odyssey_perform_ability_attack(jsonb)
      rename to odyssey_perform_ability_attack_legacy;
  end if;
end;
$$;

do $$
declare
  v_function_def text := null;
begin
  select pg_get_functiondef(p.oid)
  into v_function_def
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname = 'public'
    and p.proname = 'odyssey_perform_ability_attack_legacy'
    and pg_get_function_identity_arguments(p.oid) = 'p_payload jsonb';

  if v_function_def is null then
    raise exception 'Function public.odyssey_perform_ability_attack_legacy(jsonb) was not found.';
  end if;

  if position(
    $needle$v_runtime_data := public.odyssey_merge_runtime_data(
      public.odyssey_merge_runtime_data(
        coalesce(v_ability.ability_definition_data, '{}'::jsonb),
        coalesce(v_ability.data, '{}'::jsonb)
      ),
      coalesce(v_level.data, '{}'::jsonb)
    );$needle$
    in v_function_def
  ) > 0 then
    v_function_def := replace(
      v_function_def,
      $old$v_runtime_data := public.odyssey_merge_runtime_data(
      public.odyssey_merge_runtime_data(
        coalesce(v_ability.ability_definition_data, '{}'::jsonb),
        coalesce(v_ability.data, '{}'::jsonb)
      ),
      coalesce(v_level.data, '{}'::jsonb)
    );$old$,
      $new$v_runtime_data := public.odyssey_merge_runtime_data(
      public.odyssey_merge_runtime_data(
        public.odyssey_merge_runtime_data(
          coalesce(v_ability.ability_definition_data, '{}'::jsonb),
          coalesce(v_ability.data, '{}'::jsonb)
        ),
        coalesce(v_level.data, '{}'::jsonb)
      ),
      case
        when jsonb_typeof(p_payload->'runtime_data') = 'object' then p_payload->'runtime_data'
        else '{}'::jsonb
      end
    );$new$
    );
    execute v_function_def;
  end if;
end;
$$;

create or replace function public.odyssey_perform_ability_attack(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_character_ability_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_ability_id');
  v_attacker_character_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'attacker_character_id', v_payload->>'character_id'));
  v_ability_code text := lower(trim(coalesce(v_payload->>'ability_code', '')));
  v_ability record;
  v_weapon_effect_summary jsonb := '{}'::jsonb;
  v_runtime_modifiers jsonb := '[]'::jsonb;
  v_existing_runtime_data jsonb := case
    when jsonb_typeof(v_payload->'runtime_data') = 'object' then v_payload->'runtime_data'
    else '{}'::jsonb
  end;
  v_runtime_data jsonb := '{}'::jsonb;
  v_required_profile_id uuid := null;
  v_result jsonb := '{}'::jsonb;
begin
  if v_character_ability_id is not null or (v_attacker_character_id is not null and v_ability_code <> '') then
    select
      ability.id,
      ability.character_id,
      ability.source_character_weapon_id,
      ability.is_enabled,
      ability.is_hidden,
      ability.data,
      def.code as ability_code,
      def.attack_type,
      def.ability_kind,
      def.effect_mode
    into v_ability
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    where (
      (v_character_ability_id is not null and ability.id = v_character_ability_id)
      or (
        v_character_ability_id is null
        and ability.character_id = v_attacker_character_id
        and def.code = v_ability_code
      )
    )
    order by ability.sort_order, ability.created_at, ability.id
    limit 1;
  end if;

  if found and v_ability.source_character_weapon_id is not null then
    v_attacker_character_id := v_ability.character_id;
    v_required_profile_id := public.odyssey_try_parse_uuid(v_ability.data->>'required_profile_id');

    if coalesce(v_ability.is_enabled, false) = false
       or coalesce(v_ability.is_hidden, false) = true
       or coalesce((v_ability.data->>'source_removed')::boolean, false) then
      return jsonb_build_object(
        'ok', false,
        'error', 'WEAPON_ABILITY_SOURCE_NOT_AVAILABLE',
        'message', 'This weapon ability is no longer available on the source weapon.',
        'character_ability_id', v_ability.id,
        'character_weapon_id', v_ability.source_character_weapon_id
      );
    end if;

    if not exists (
      select 1
      from public.odyssey_character_weapons weapon
      where weapon.id = v_ability.source_character_weapon_id
        and weapon.character_id = v_attacker_character_id
    ) then
      return jsonb_build_object(
        'ok', false,
        'error', 'WEAPON_ABILITY_SOURCE_NOT_AVAILABLE',
        'message', 'The source weapon for this ability is not available.',
        'character_ability_id', v_ability.id,
        'character_weapon_id', v_ability.source_character_weapon_id
      );
    end if;

    if v_required_profile_id is not null and not exists (
      select 1
      from public.odyssey_character_weapons weapon
      where weapon.id = v_ability.source_character_weapon_id
        and weapon.active_profile_id = v_required_profile_id
    ) then
      return jsonb_build_object(
        'ok', false,
        'error', 'ABILITY_NOT_AVAILABLE_FOR_WEAPON_PROFILE',
        'message', 'This weapon ability is not available for the currently active weapon profile.',
        'character_ability_id', v_ability.id,
        'character_weapon_id', v_ability.source_character_weapon_id,
        'required_profile_id', v_required_profile_id
      );
    end if;

    v_weapon_effect_summary := public.odyssey_get_weapon_effect_summary(
      v_attacker_character_id,
      v_ability.source_character_weapon_id
    );

    if coalesce(nullif(v_weapon_effect_summary->>'attack_accuracy', '')::integer, 0) <> 0 then
      v_runtime_modifiers := v_runtime_modifiers || jsonb_build_array(
        jsonb_build_object(
          'target', 'attack_accuracy',
          'value', coalesce(nullif(v_weapon_effect_summary->>'attack_accuracy', '')::integer, 0)
        )
      );
    end if;
    if coalesce(nullif(v_weapon_effect_summary->>'damage', '')::integer, 0) <> 0 then
      v_runtime_modifiers := v_runtime_modifiers || jsonb_build_array(
        jsonb_build_object(
          'target', 'damage',
          'value', coalesce(nullif(v_weapon_effect_summary->>'damage', '')::integer, 0)
        )
      );
    end if;
    if coalesce(nullif(v_weapon_effect_summary->>'armor_pierce', '')::integer, 0) <> 0 then
      v_runtime_modifiers := v_runtime_modifiers || jsonb_build_array(
        jsonb_build_object(
          'target', 'armor_pierce',
          'value', coalesce(nullif(v_weapon_effect_summary->>'armor_pierce', '')::integer, 0)
        )
      );
    end if;
    if coalesce(nullif(v_weapon_effect_summary->>'aim_difficulty', '')::integer, 0) <> 0 then
      v_runtime_modifiers := v_runtime_modifiers || jsonb_build_array(
        jsonb_build_object(
          'target', 'aim_difficulty',
          'value', coalesce(nullif(v_weapon_effect_summary->>'aim_difficulty', '')::integer, 0)
        )
      );
    end if;
    if coalesce(nullif(v_weapon_effect_summary->>'range', '')::integer, 0) <> 0 then
      v_runtime_modifiers := v_runtime_modifiers || jsonb_build_array(
        jsonb_build_object(
          'target', 'range',
          'value', coalesce(nullif(v_weapon_effect_summary->>'range', '')::integer, 0)
        )
      );
    end if;

    if jsonb_array_length(v_runtime_modifiers) > 0 then
      v_runtime_data := public.odyssey_merge_runtime_data(
        v_existing_runtime_data,
        jsonb_build_object(
          'modifiers', v_runtime_modifiers
        )
      );
      v_payload := v_payload || jsonb_build_object('runtime_data', v_runtime_data);
    end if;

    v_payload := v_payload || jsonb_build_object(
      'character_weapon_id', v_ability.source_character_weapon_id::text,
      'attacker_character_id', v_attacker_character_id::text,
      'character_id', v_attacker_character_id::text
    );
  end if;

  v_result := public.odyssey_perform_ability_attack_legacy(v_payload);
  if found and v_ability.source_character_weapon_id is not null and coalesce((v_result->>'ok')::boolean, false) = true then
    v_result := v_result || jsonb_build_object(
      'weapon_effects', v_weapon_effect_summary
    );
  end if;
  return v_result;
end;
$$;

do $$
declare
  v_function_def text := null;
begin
  select pg_get_functiondef(p.oid)
  into v_function_def
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname = 'public'
    and p.proname = 'odyssey_perform_weapon_attack'
    and pg_get_function_identity_arguments(p.oid) = 'p_payload jsonb';

  if v_function_def is null then
    raise exception 'Function public.odyssey_perform_weapon_attack(jsonb) was not found.';
  end if;

  if position('v_weapon_effect_summary jsonb := ''{}''::jsonb;' in v_function_def) = 0 then
    v_function_def := replace(
      v_function_def,
      $old$v_feature_range_modifier integer := 0;
  v_pending_saves jsonb := '[]'::jsonb;$old$,
      $new$v_feature_range_modifier integer := 0;
  v_weapon_effect_summary jsonb := '{}'::jsonb;
  v_weapon_effect_attack_accuracy_modifier integer := 0;
  v_weapon_effect_damage_modifier integer := 0;
  v_weapon_effect_armor_pierce_modifier integer := 0;
  v_weapon_effect_aim_difficulty_modifier integer := 0;
  v_weapon_effect_range_modifier integer := 0;
  v_pending_saves jsonb := '[]'::jsonb;$new$
    );
  end if;

  if position('v_weapon_effect_summary := public.odyssey_get_weapon_effect_summary(' in v_function_def) = 0 then
    v_function_def := replace(
      v_function_def,
      $old$v_target_defense_modifier := coalesce(nullif(jsonb_extract_path_text(v_target_effective_stats, 'derived', 'defense_modifier'), '')::integer, 0);
    v_target_armor_modifier := coalesce(nullif(jsonb_extract_path_text(v_target_effective_stats, 'derived', 'armor_modifier'), '')::integer, 0);$old$,
      $new$v_target_defense_modifier := coalesce(nullif(jsonb_extract_path_text(v_target_effective_stats, 'derived', 'defense_modifier'), '')::integer, 0);
    v_target_armor_modifier := coalesce(nullif(jsonb_extract_path_text(v_target_effective_stats, 'derived', 'armor_modifier'), '')::integer, 0);
    v_weapon_effect_summary := public.odyssey_get_weapon_effect_summary(v_attacker_character_id, v_weapon.id);
    v_weapon_effect_attack_accuracy_modifier := coalesce(nullif(v_weapon_effect_summary->>'attack_accuracy', '')::integer, 0);
    v_weapon_effect_damage_modifier := coalesce(nullif(v_weapon_effect_summary->>'damage', '')::integer, 0);
    v_weapon_effect_armor_pierce_modifier := coalesce(nullif(v_weapon_effect_summary->>'armor_pierce', '')::integer, 0);
    v_weapon_effect_aim_difficulty_modifier := coalesce(nullif(v_weapon_effect_summary->>'aim_difficulty', '')::integer, 0);
    v_weapon_effect_range_modifier := coalesce(nullif(v_weapon_effect_summary->>'range', '')::integer, 0);$new$
    );
  end if;

  v_function_def := replace(
    v_function_def,
    'v_total_weapon_damage := greatest(v_total_weapon_damage + v_attacker_damage_modifier + v_feature_damage_modifier, 0);',
    'v_total_weapon_damage := greatest(v_total_weapon_damage + v_attacker_damage_modifier + v_feature_damage_modifier + v_weapon_effect_damage_modifier, 0);'
  );

  v_function_def := replace(
    v_function_def,
    'v_armor_pierce := greatest(v_armor_pierce + v_feature_armor_pierce_modifier, 0);',
    'v_armor_pierce := greatest(v_armor_pierce + v_feature_armor_pierce_modifier + v_weapon_effect_armor_pierce_modifier, 0);'
  );
  v_function_def := replace(
    v_function_def,
    'v_armor_pierce := coalesce(v_armor_pierce, 0) + v_feature_armor_pierce_modifier;',
    'v_armor_pierce := greatest(coalesce(v_armor_pierce, 0) + v_feature_armor_pierce_modifier + v_weapon_effect_armor_pierce_modifier, 0);'
  );

  v_function_def := replace(
    v_function_def,
    'v_range_modifier := v_range_modifier + v_feature_range_modifier;',
    'v_range_modifier := v_range_modifier + v_feature_range_modifier + v_weapon_effect_range_modifier;'
  );
  v_function_def := replace(
    v_function_def,
    'v_attacker_attack_accuracy_modifier := v_attacker_attack_accuracy_modifier + v_feature_attack_accuracy_modifier;',
    'v_attacker_attack_accuracy_modifier := v_attacker_attack_accuracy_modifier + v_feature_attack_accuracy_modifier + v_weapon_effect_attack_accuracy_modifier;'
  );
  v_function_def := replace(
    v_function_def,
    'v_attacker_aim_difficulty_modifier := v_attacker_aim_difficulty_modifier + v_feature_aim_difficulty_modifier;',
    'v_attacker_aim_difficulty_modifier := v_attacker_aim_difficulty_modifier + v_feature_aim_difficulty_modifier + v_weapon_effect_aim_difficulty_modifier;'
  );

  if position($needle$'feature_usage', v_feature_usage_log,$needle$ in v_function_def) > 0
     and position($needle$'weapon_effects', v_weapon_effect_summary,$needle$ in v_function_def) = 0 then
    v_function_def := replace(
      v_function_def,
      $old$'feature_usage', v_feature_usage_log,$old$,
      $new$'feature_usage', v_feature_usage_log,
    'weapon_effects', v_weapon_effect_summary,$new$
    );
  end if;

  execute v_function_def;
end;
$$;

grant execute on function public.get_character_effect_summary(uuid) to anon, authenticated;
grant execute on function public.odyssey_get_weapon_effect_summary(uuid, uuid) to anon, authenticated;
grant execute on function public.get_effective_character_stats(uuid) to anon, authenticated;
grant execute on function public.odyssey_perform_ability_attack(jsonb) to anon, authenticated;

-- ===== END 89_creator_definition_refresh_and_armor_pierce.sql =====

-- ===== BEGIN 95_automatic_combat_movement.sql =====
-- Automatic combat movement:
-- - clearer movement validation / error codes
-- - GM override reposition RPC without mandatory MOVE spend

create or replace function public.combat_move_character(
  p_payload jsonb
)
returns jsonb
language plpgsql
set search_path = public
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_destination jsonb := case when jsonb_typeof(v_payload->'destination') = 'object' then v_payload->'destination' else '{}'::jsonb end;
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_id');
  v_token_id text := coalesce(nullif(trim(coalesce(v_payload->>'token_id', '')), ''), '');
  v_expected_state_version integer := nullif(trim(coalesce(v_payload->>'expected_state_version', '')), '')::integer;
  v_expected_movement_version integer := nullif(trim(coalesce(v_payload->>'expected_movement_version', '')), '')::integer;
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_dest_q integer := nullif(trim(coalesce(v_destination->>'cell_q', '')), '')::integer;
  v_dest_r integer := nullif(trim(coalesce(v_destination->>'cell_r', '')), '')::integer;
  v_dest_scene_x numeric := nullif(trim(coalesce(v_destination->>'scene_x', '')), '')::numeric;
  v_dest_scene_y numeric := nullif(trim(coalesce(v_destination->>'scene_y', '')), '')::numeric;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_entry public.odyssey_initiative_entries%rowtype;
  v_position public.odyssey_combat_positions%rowtype;
  v_grid public.odyssey_combat_grid_settings%rowtype;
  v_control jsonb := '{}'::jsonb;
  v_distance_cells integer := 0;
  v_move_cost_m integer := 0;
  v_log_id uuid := null;
  v_state_version integer := 0;
  v_prev_cell_q integer := 0;
  v_prev_cell_r integer := 0;
  v_prev_scene_x numeric := 0;
  v_prev_scene_y numeric := 0;
  v_effective_stats jsonb := '{}'::jsonb;
  v_skip_movement boolean := false;
  v_consumes_full_turn boolean := false;
  v_suppress_movement boolean := false;
  v_is_alive boolean := true;
  v_is_conscious boolean := true;
  v_resolved_token_id text := '';
  v_has_token_link boolean := false;
begin
  if v_encounter_id is null or v_character_id is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'encounter_id and character_id are required.'
    );
  end if;

  if v_dest_q is null or v_dest_r is null or v_dest_scene_x is null or v_dest_scene_y is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'destination cell and scene coordinates are required.'
    );
  end if;

  select *
  into v_encounter
  from public.odyssey_combat_encounters
  where id = v_encounter_id
    and status = 'active'
    and ended_at is null
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ENCOUNTER_NOT_ACTIVE',
      'message', 'Encounter is not active.'
    );
  end if;

  select *
  into v_entry
  from public.odyssey_initiative_entries
  where encounter_id = v_encounter_id
    and character_id = v_character_id
    and is_active = true
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'PARTICIPANT_NOT_FOUND',
      'message', 'Participant was not found.'
    );
  end if;

  v_control := public.odyssey_can_control_character(v_character_id, v_actor_player_id, v_actor_is_gm);
  if coalesce((v_control->>'allowed')::boolean, false) = false then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_NOT_ALLOWED',
      'message', 'You cannot control this participant.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_encounter.active_entry_id is distinct from v_entry.id then
    return jsonb_build_object(
      'ok', false,
      'error', 'NOT_ACTIVE_TURN',
      'message', 'It is not this participant''s turn.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_state_version is not null
     and coalesce(v_encounter.state_version, 0) <> v_expected_state_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Combat state changed. Reload authoritative runtime.',
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_movement_version is not null
     and coalesce(v_entry.movement_version, 0) <> v_expected_movement_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Movement state changed. Reload authoritative runtime.',
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select *
  into v_grid
  from public.odyssey_combat_grid_settings
  where encounter_id = v_encounter_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'The tactical grid has not been synced by the GM yet.'
    );
  end if;

  if v_grid.grid_type not in ('square', 'hex_vertical', 'hex_horizontal')
     or (
       v_grid.grid_type = 'square'
       and v_grid.distance_mode not in ('chebyshev', 'manhattan')
     )
     or (
       v_grid.grid_type in ('hex_vertical', 'hex_horizontal')
       and v_grid.distance_mode <> 'hex'
     )
     or coalesce(v_grid.meters_per_cell, 0) <= 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'Combat grid settings are invalid.'
    );
  end if;

  select *
  into v_position
  from public.odyssey_combat_positions
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'This combat token position has not been synced yet.'
    );
  end if;

  v_resolved_token_id := coalesce(nullif(v_token_id, ''), coalesce(v_position.token_id, ''));

  if v_token_id <> '' and v_position.token_id <> v_token_id then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'Token link changed. Reload authoritative runtime.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select exists(
    select 1
    from public.odyssey_token_links link
    where link.room_id = v_encounter.room_id
      and link.scene_id = v_encounter.scene_id
      and link.character_id = v_character_id
      and link.token_id = v_resolved_token_id
      and link.is_active = true
  )
  into v_has_token_link;

  if not v_has_token_link then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'Active token link was not found for this combatant.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  v_effective_stats := public.get_effective_character_stats(v_character_id);
  v_skip_movement := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'skip_movement'), '')::boolean, false);
  v_consumes_full_turn := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'consumes_full_turn'), '')::boolean, false);
  v_suppress_movement := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'suppress_movement'), '')::boolean, false);
  v_is_alive := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'is_alive'), '')::boolean, true);
  v_is_conscious := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'is_conscious'), '')::boolean, true);

  if not v_is_alive or not v_is_conscious or v_skip_movement or v_consumes_full_turn or v_suppress_movement then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVEMENT_LOCKED',
      'message', 'Movement is currently blocked by combat state or effects.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  v_prev_cell_q := v_position.cell_q;
  v_prev_cell_r := v_position.cell_r;
  v_prev_scene_x := v_position.scene_x;
  v_prev_scene_y := v_position.scene_y;

  v_distance_cells := public.odyssey_tactical_distance_cells(
    v_grid.grid_type,
    v_grid.distance_mode,
    v_position.cell_q,
    v_position.cell_r,
    v_dest_q,
    v_dest_r
  );
  v_move_cost_m := v_distance_cells * greatest(coalesce(v_grid.meters_per_cell, 1), 1);

  if coalesce(v_entry.move_current, 0) < v_move_cost_m then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_EXCEEDS_REMAINING',
      'message', 'Movement exceeds remaining distance.',
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_current', coalesce(v_entry.move_current, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_distance_cells = 0 then
    return jsonb_build_object(
      'ok', true,
      'encounter_id', v_encounter_id,
      'character_id', v_character_id,
      'position',
        jsonb_build_object(
          'token_id', v_position.token_id,
          'cell_q', v_position.cell_q,
          'cell_r', v_position.cell_r,
          'scene_x', v_position.scene_x,
          'scene_y', v_position.scene_y,
          'updated_at', v_position.updated_at
        ),
      'distance_cells', 0,
      'move_cost_m', 0,
      'move_current', coalesce(v_entry.move_current, 0),
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'log_id', null,
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  update public.odyssey_combat_positions
  set
    token_id = v_resolved_token_id,
    cell_q = v_dest_q,
    cell_r = v_dest_r,
    scene_x = v_dest_scene_x,
    scene_y = v_dest_scene_y,
    updated_at = timezone('utc', now())
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  returning * into v_position;

  update public.odyssey_initiative_entries
  set
    move_current = greatest(move_current - v_move_cost_m, 0),
    movement_version = coalesce(movement_version, 0) + 1
  where id = v_entry.id
  returning * into v_entry;

  v_state_version := public.odyssey_increment_encounter_state_version(v_encounter_id);

  v_log_id := public.odyssey_combat_log_insert(
    v_encounter.campaign_id,
    v_encounter.room_id,
    v_encounter.scene_id,
    v_encounter.id,
    v_encounter.current_round,
    v_character_id,
    null,
    v_character_id,
    'public',
    'move',
    public.odyssey_character_display_name(v_character_id) || ' moved ' || v_move_cost_m || ' m.',
    jsonb_build_object(
      'token_id', v_position.token_id,
      'from_cell_q', v_prev_cell_q,
      'from_cell_r', v_prev_cell_r,
      'from_scene_x', v_prev_scene_x,
      'from_scene_y', v_prev_scene_y,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'to_scene_x', v_dest_scene_x,
      'to_scene_y', v_dest_scene_y,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    jsonb_build_object(
      'token_id', v_position.token_id,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    coalesce(nullif(v_actor_player_id, ''), 'system')
  );

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter_id,
    'character_id', v_character_id,
    'position',
      jsonb_build_object(
        'token_id', v_position.token_id,
        'cell_q', v_position.cell_q,
        'cell_r', v_position.cell_r,
        'scene_x', v_position.scene_x,
        'scene_y', v_position.scene_y,
        'updated_at', v_position.updated_at
      ),
    'distance_cells', v_distance_cells,
    'move_cost_m', v_move_cost_m,
    'move_current', coalesce(v_entry.move_current, 0),
    'movement_version', coalesce(v_entry.movement_version, 0),
    'state_version', v_state_version,
    'log_id', v_log_id,
    'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
  );
end;
$$;

create or replace function public.combat_gm_reposition_character(
  p_payload jsonb
)
returns jsonb
language plpgsql
set search_path = public
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_destination jsonb := case when jsonb_typeof(v_payload->'destination') = 'object' then v_payload->'destination' else '{}'::jsonb end;
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_id');
  v_token_id text := coalesce(nullif(trim(coalesce(v_payload->>'token_id', '')), ''), '');
  v_expected_state_version integer := nullif(trim(coalesce(v_payload->>'expected_state_version', '')), '')::integer;
  v_expected_movement_version integer := nullif(trim(coalesce(v_payload->>'expected_movement_version', '')), '')::integer;
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_consume_movement boolean := coalesce(nullif(trim(coalesce(v_payload->>'consume_movement', '')), '')::boolean, false);
  v_dest_q integer := nullif(trim(coalesce(v_destination->>'cell_q', '')), '')::integer;
  v_dest_r integer := nullif(trim(coalesce(v_destination->>'cell_r', '')), '')::integer;
  v_dest_scene_x numeric := nullif(trim(coalesce(v_destination->>'scene_x', '')), '')::numeric;
  v_dest_scene_y numeric := nullif(trim(coalesce(v_destination->>'scene_y', '')), '')::numeric;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_entry public.odyssey_initiative_entries%rowtype;
  v_position public.odyssey_combat_positions%rowtype;
  v_grid public.odyssey_combat_grid_settings%rowtype;
  v_distance_cells integer := 0;
  v_move_cost_m integer := 0;
  v_log_id uuid := null;
  v_state_version integer := 0;
  v_prev_cell_q integer := 0;
  v_prev_cell_r integer := 0;
  v_prev_scene_x numeric := 0;
  v_prev_scene_y numeric := 0;
  v_resolved_token_id text := '';
  v_has_token_link boolean := false;
begin
  if not v_actor_is_gm then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_NOT_ALLOWED',
      'message', 'Only the GM may reposition combatants.'
    );
  end if;

  if v_encounter_id is null or v_character_id is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'encounter_id and character_id are required.'
    );
  end if;

  if v_dest_q is null or v_dest_r is null or v_dest_scene_x is null or v_dest_scene_y is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'destination cell and scene coordinates are required.'
    );
  end if;

  select *
  into v_encounter
  from public.odyssey_combat_encounters
  where id = v_encounter_id
    and status = 'active'
    and ended_at is null
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ENCOUNTER_NOT_ACTIVE',
      'message', 'Encounter is not active.'
    );
  end if;

  select *
  into v_entry
  from public.odyssey_initiative_entries
  where encounter_id = v_encounter_id
    and character_id = v_character_id
    and is_active = true
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'PARTICIPANT_NOT_FOUND',
      'message', 'Participant was not found.'
    );
  end if;

  if v_expected_state_version is not null
     and coalesce(v_encounter.state_version, 0) <> v_expected_state_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Combat state changed. Reload authoritative runtime.',
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
    );
  end if;

  if v_expected_movement_version is not null
     and coalesce(v_entry.movement_version, 0) <> v_expected_movement_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Movement state changed. Reload authoritative runtime.',
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
    );
  end if;

  select *
  into v_grid
  from public.odyssey_combat_grid_settings
  where encounter_id = v_encounter_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'The tactical grid has not been synced by the GM yet.'
    );
  end if;

  if v_grid.grid_type not in ('square', 'hex_vertical', 'hex_horizontal')
     or (
       v_grid.grid_type = 'square'
       and v_grid.distance_mode not in ('chebyshev', 'manhattan')
     )
     or (
       v_grid.grid_type in ('hex_vertical', 'hex_horizontal')
       and v_grid.distance_mode <> 'hex'
     )
     or coalesce(v_grid.meters_per_cell, 0) <= 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'Combat grid settings are invalid.'
    );
  end if;

  select *
  into v_position
  from public.odyssey_combat_positions
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'This combat token position has not been synced yet.'
    );
  end if;

  v_resolved_token_id := coalesce(nullif(v_token_id, ''), coalesce(v_position.token_id, ''));

  select exists(
    select 1
    from public.odyssey_token_links link
    where link.room_id = v_encounter.room_id
      and link.scene_id = v_encounter.scene_id
      and link.character_id = v_character_id
      and link.token_id = v_resolved_token_id
      and link.is_active = true
  )
  into v_has_token_link;

  if not v_has_token_link then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'Active token link was not found for this combatant.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
    );
  end if;

  v_prev_cell_q := v_position.cell_q;
  v_prev_cell_r := v_position.cell_r;
  v_prev_scene_x := v_position.scene_x;
  v_prev_scene_y := v_position.scene_y;

  v_distance_cells := public.odyssey_tactical_distance_cells(
    v_grid.grid_type,
    v_grid.distance_mode,
    v_position.cell_q,
    v_position.cell_r,
    v_dest_q,
    v_dest_r
  );
  v_move_cost_m := v_distance_cells * greatest(coalesce(v_grid.meters_per_cell, 1), 1);

  if v_consume_movement and coalesce(v_entry.move_current, 0) < v_move_cost_m then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_EXCEEDS_REMAINING',
      'message', 'Movement exceeds remaining distance.',
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_current', coalesce(v_entry.move_current, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
    );
  end if;

  if v_distance_cells = 0 then
    return jsonb_build_object(
      'ok', true,
      'encounter_id', v_encounter_id,
      'character_id', v_character_id,
      'position',
        jsonb_build_object(
          'token_id', v_position.token_id,
          'cell_q', v_position.cell_q,
          'cell_r', v_position.cell_r,
          'scene_x', v_position.scene_x,
          'scene_y', v_position.scene_y,
          'updated_at', v_position.updated_at
        ),
      'distance_cells', 0,
      'move_cost_m', 0,
      'move_current', coalesce(v_entry.move_current, 0),
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'log_id', null,
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
    );
  end if;

  update public.odyssey_combat_positions
  set
    token_id = v_resolved_token_id,
    cell_q = v_dest_q,
    cell_r = v_dest_r,
    scene_x = v_dest_scene_x,
    scene_y = v_dest_scene_y,
    updated_at = timezone('utc', now())
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  returning * into v_position;

  update public.odyssey_initiative_entries
  set
    move_current = case
      when v_consume_movement then greatest(move_current - v_move_cost_m, 0)
      else move_current
    end,
    movement_version = coalesce(movement_version, 0) + 1
  where id = v_entry.id
  returning * into v_entry;

  v_state_version := public.odyssey_increment_encounter_state_version(v_encounter_id);

  v_log_id := public.odyssey_combat_log_insert(
    v_encounter.campaign_id,
    v_encounter.room_id,
    v_encounter.scene_id,
    v_encounter.id,
    v_encounter.current_round,
    v_character_id,
    null,
    v_character_id,
    'public',
    'move',
    'GM repositioned ' || public.odyssey_character_display_name(v_character_id) || '.',
    jsonb_build_object(
      'override', true,
      'consume_movement', v_consume_movement,
      'token_id', v_position.token_id,
      'from_cell_q', v_prev_cell_q,
      'from_cell_r', v_prev_cell_r,
      'from_scene_x', v_prev_scene_x,
      'from_scene_y', v_prev_scene_y,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'to_scene_x', v_dest_scene_x,
      'to_scene_y', v_dest_scene_y,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    jsonb_build_object(
      'override', true,
      'consume_movement', v_consume_movement,
      'token_id', v_position.token_id,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    coalesce(nullif(v_actor_player_id, ''), 'system')
  );

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter_id,
    'character_id', v_character_id,
    'position',
      jsonb_build_object(
        'token_id', v_position.token_id,
        'cell_q', v_position.cell_q,
        'cell_r', v_position.cell_r,
        'scene_x', v_position.scene_x,
        'scene_y', v_position.scene_y,
        'updated_at', v_position.updated_at
      ),
    'distance_cells', v_distance_cells,
    'move_cost_m', v_move_cost_m,
    'move_current', coalesce(v_entry.move_current, 0),
    'movement_version', coalesce(v_entry.movement_version, 0),
    'state_version', v_state_version,
    'log_id', v_log_id,
    'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, true, true, 5)
  );
end;
$$;

grant execute on function public.combat_move_character(jsonb) to anon, authenticated;
grant execute on function public.combat_gm_reposition_character(jsonb) to anon, authenticated;
-- ===== END 95_automatic_combat_movement.sql =====

-- ===== BEGIN 96_move_default_10m.sql =====
-- Keep encounter-level move default aligned with the 10m combat movement baseline.

alter table public.odyssey_combat_encounters
  alter column move_default set default 10;

update public.odyssey_combat_encounters
set move_default = 10
where coalesce(move_default, 0) <> 10;
-- ===== END 96_move_default_10m.sql =====

-- ===== BEGIN 97_force_existing_move_entries_to_10m.sql =====
-- Hard-normalize initiative movement to the fixed 10m baseline while preserving
-- already-spent movement on active encounters.

alter table public.odyssey_initiative_entries
  alter column move_max set default 10,
  alter column move_current set default 10;

update public.odyssey_initiative_entries e
set
  move_max = 10,
  move_current = case
    when coalesce(e.move_current, 0) <= 0 then 0
    when coalesce(e.move_current, 0) = coalesce(e.move_max, 0) then 10
    else least(coalesce(e.move_current, 0), 10)
  end
where coalesce(e.move_max, 0) <> 10
   or coalesce(e.move_current, 0) > 10
   or (
     coalesce(e.move_current, 0) = coalesce(e.move_max, 0)
     and coalesce(e.move_current, 0) <> 10
   );
-- ===== END 97_force_existing_move_entries_to_10m.sql =====

-- ===== BEGIN 98_tactical_sync_idempotent.sql =====
-- Make tactical sync idempotent so passive refreshes do not bump encounter state.

create or replace function public.combat_sync_positions_from_owlbear(
  p_payload jsonb
)
returns jsonb
language plpgsql
set search_path = public
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_campaign_id text := coalesce(nullif(trim(coalesce(v_payload->>'campaign_id', '')), ''), '');
  v_room_id text := coalesce(nullif(trim(coalesce(v_payload->>'room_id', '')), ''), '');
  v_scene_id text := coalesce(nullif(trim(coalesce(v_payload->>'scene_id', '')), ''), '');
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_grid_type text := lower(trim(coalesce(v_payload->>'grid_type', '')));
  v_distance_mode text := lower(trim(coalesce(v_payload->>'distance_mode', '')));
  v_meters_per_cell integer := greatest(coalesce(nullif(trim(coalesce(v_payload->>'meters_per_cell', '')), '')::integer, 1), 1);
  v_anchor_scene_x numeric := coalesce(nullif(trim(coalesce(v_payload->>'anchor_scene_x', '')), '')::numeric, 0);
  v_anchor_scene_y numeric := coalesce(nullif(trim(coalesce(v_payload->>'anchor_scene_y', '')), '')::numeric, 0);
  v_grid_dpi numeric := coalesce(nullif(trim(coalesce(v_payload->>'grid_dpi', '')), '')::numeric, 0);
  v_positions jsonb := case when jsonb_typeof(v_payload->'positions') = 'array' then v_payload->'positions' else '[]'::jsonb end;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_existing_grid public.odyssey_combat_grid_settings%rowtype;
  v_existing_position public.odyssey_combat_positions%rowtype;
  v_item jsonb;
  v_character_id uuid;
  v_token_id text;
  v_cell_q integer;
  v_cell_r integer;
  v_scene_x numeric;
  v_scene_y numeric;
  v_synced_count integer := 0;
  v_grid_changed boolean := false;
  v_positions_changed boolean := false;
  v_state_version integer := 0;
begin
  if not v_actor_is_gm then
    return jsonb_build_object('ok', false, 'error', 'CONTROL_DENIED', 'message', 'Only the GM may sync tactical positions.');
  end if;

  if v_encounter_id is null then
    if v_room_id = '' or v_scene_id = '' then
      return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'encounter_id or room/scene context is required.');
    end if;

    select *
    into v_encounter
    from public.odyssey_get_active_encounter(v_campaign_id, v_room_id, v_scene_id)
    for update;
  else
    select *
    into v_encounter
    from public.odyssey_combat_encounters
    where id = v_encounter_id
      and status = 'active'
      and ended_at is null
    for update;
  end if;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'ENCOUNTER_NOT_ACTIVE', 'message', 'Encounter is not active.');
  end if;

  if v_grid_type not in ('square', 'hex_vertical', 'hex_horizontal') then
    return jsonb_build_object('ok', false, 'error', 'GRID_NOT_SUPPORTED', 'message', 'Only square and hex grids are supported.');
  end if;

  if v_distance_mode not in ('chebyshev', 'manhattan', 'hex') then
    return jsonb_build_object('ok', false, 'error', 'GRID_NOT_SUPPORTED', 'message', 'Only chebyshev, manhattan, and hex distance modes are supported.');
  end if;

  if v_grid_dpi <= 0 then
    return jsonb_build_object('ok', false, 'error', 'INVALID_PAYLOAD', 'message', 'grid_dpi must be greater than 0.');
  end if;

  select *
  into v_existing_grid
  from public.odyssey_combat_grid_settings
  where encounter_id = v_encounter.id
  for update;

  if not found then
    insert into public.odyssey_combat_grid_settings (
      encounter_id,
      grid_type,
      distance_mode,
      meters_per_cell,
      anchor_scene_x,
      anchor_scene_y,
      grid_dpi
    )
    values (
      v_encounter.id,
      v_grid_type,
      v_distance_mode,
      v_meters_per_cell,
      v_anchor_scene_x,
      v_anchor_scene_y,
      v_grid_dpi
    );
    v_grid_changed := true;
  elsif v_existing_grid.grid_type is distinct from v_grid_type
     or v_existing_grid.distance_mode is distinct from v_distance_mode
     or coalesce(v_existing_grid.meters_per_cell, 0) is distinct from v_meters_per_cell
     or coalesce(v_existing_grid.anchor_scene_x, 0) is distinct from v_anchor_scene_x
     or coalesce(v_existing_grid.anchor_scene_y, 0) is distinct from v_anchor_scene_y
     or coalesce(v_existing_grid.grid_dpi, 0) is distinct from v_grid_dpi then
    update public.odyssey_combat_grid_settings
    set
      grid_type = v_grid_type,
      distance_mode = v_distance_mode,
      meters_per_cell = v_meters_per_cell,
      anchor_scene_x = v_anchor_scene_x,
      anchor_scene_y = v_anchor_scene_y,
      grid_dpi = v_grid_dpi,
      updated_at = timezone('utc', now())
    where encounter_id = v_encounter.id;
    v_grid_changed := true;
  end if;

  for v_item in
    select value
    from jsonb_array_elements(v_positions)
  loop
    v_character_id := public.odyssey_try_parse_uuid(v_item->>'character_id');
    v_token_id := coalesce(nullif(trim(coalesce(v_item->>'token_id', '')), ''), '');
    v_cell_q := coalesce(nullif(trim(coalesce(v_item->>'cell_q', '')), '')::integer, 0);
    v_cell_r := coalesce(nullif(trim(coalesce(v_item->>'cell_r', '')), '')::integer, 0);
    v_scene_x := coalesce(nullif(trim(coalesce(v_item->>'scene_x', '')), '')::numeric, 0);
    v_scene_y := coalesce(nullif(trim(coalesce(v_item->>'scene_y', '')), '')::numeric, 0);

    if v_character_id is null or v_token_id = '' then
      continue;
    end if;

    if not exists (
      select 1
      from public.odyssey_initiative_entries e
      where e.encounter_id = v_encounter.id
        and e.character_id = v_character_id
        and e.is_active = true
    ) then
      continue;
    end if;

    select *
    into v_existing_position
    from public.odyssey_combat_positions
    where encounter_id = v_encounter.id
      and character_id = v_character_id
    for update;

    if not found then
      insert into public.odyssey_combat_positions (
        encounter_id,
        character_id,
        token_id,
        cell_q,
        cell_r,
        scene_x,
        scene_y
      )
      values (
        v_encounter.id,
        v_character_id,
        v_token_id,
        v_cell_q,
        v_cell_r,
        v_scene_x,
        v_scene_y
      );
      v_positions_changed := true;
      v_synced_count := v_synced_count + 1;
    elsif v_existing_position.token_id is distinct from v_token_id
       or v_existing_position.cell_q is distinct from v_cell_q
       or v_existing_position.cell_r is distinct from v_cell_r
       or coalesce(v_existing_position.scene_x, 0) is distinct from v_scene_x
       or coalesce(v_existing_position.scene_y, 0) is distinct from v_scene_y then
      update public.odyssey_combat_positions
      set
        token_id = v_token_id,
        cell_q = v_cell_q,
        cell_r = v_cell_r,
        scene_x = v_scene_x,
        scene_y = v_scene_y,
        updated_at = timezone('utc', now())
      where encounter_id = v_encounter.id
        and character_id = v_character_id;
      v_positions_changed := true;
      v_synced_count := v_synced_count + 1;
    end if;
  end loop;

  v_state_version := coalesce(v_encounter.state_version, 0);
  if v_grid_changed or v_positions_changed then
    v_state_version := public.odyssey_increment_encounter_state_version(v_encounter.id);
  end if;

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter.id,
    'synced_count', v_synced_count,
    'state_version', v_state_version,
    'runtime', public.odyssey_build_combat_runtime(v_encounter.id, v_actor_player_id, true, true, 5)
  );
end;
$$;
-- ===== END 98_tactical_sync_idempotent.sql =====

-- ===== BEGIN 99_tactical_move_v1_square_path.sql =====
-- Tactical move v1:
-- - square grid only
-- - direct deterministic Chebyshev path
-- - route blocking by occupied combat cells

create or replace function public.odyssey_build_straight_square_path(
  p_from_q integer,
  p_from_r integer,
  p_to_q integer,
  p_to_r integer
)
returns table(
  step_index integer,
  cell_q integer,
  cell_r integer
)
language sql
immutable
set search_path = public
as $$
  with recursive path(step_index, cell_q, cell_r) as (
    select
      0,
      coalesce(p_from_q, 0),
      coalesce(p_from_r, 0)

    union all

    select
      path.step_index + 1,
      path.cell_q + case
        when path.cell_q < coalesce(p_to_q, 0) then 1
        when path.cell_q > coalesce(p_to_q, 0) then -1
        else 0
      end,
      path.cell_r + case
        when path.cell_r < coalesce(p_to_r, 0) then 1
        when path.cell_r > coalesce(p_to_r, 0) then -1
        else 0
      end
    from path
    where path.cell_q <> coalesce(p_to_q, 0)
       or path.cell_r <> coalesce(p_to_r, 0)
  )
  select
    path.step_index,
    path.cell_q,
    path.cell_r
  from path
  order by path.step_index;
$$;

create or replace function public.combat_move_character(
  p_payload jsonb
)
returns jsonb
language plpgsql
set search_path = public
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_destination jsonb := case when jsonb_typeof(v_payload->'destination') = 'object' then v_payload->'destination' else '{}'::jsonb end;
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_id');
  v_token_id text := coalesce(nullif(trim(coalesce(v_payload->>'token_id', '')), ''), '');
  v_expected_state_version integer := nullif(trim(coalesce(v_payload->>'expected_state_version', '')), '')::integer;
  v_expected_movement_version integer := nullif(trim(coalesce(v_payload->>'expected_movement_version', '')), '')::integer;
  v_actor_player_id text := coalesce(nullif(trim(coalesce(v_payload->>'actor_player_id', '')), ''), '');
  v_actor_is_gm boolean := coalesce(nullif(trim(coalesce(v_payload->>'actor_is_gm', '')), '')::boolean, false);
  v_dest_q integer := nullif(trim(coalesce(v_destination->>'cell_q', '')), '')::integer;
  v_dest_r integer := nullif(trim(coalesce(v_destination->>'cell_r', '')), '')::integer;
  v_dest_scene_x numeric := nullif(trim(coalesce(v_destination->>'scene_x', '')), '')::numeric;
  v_dest_scene_y numeric := nullif(trim(coalesce(v_destination->>'scene_y', '')), '')::numeric;
  v_encounter public.odyssey_combat_encounters%rowtype;
  v_entry public.odyssey_initiative_entries%rowtype;
  v_position public.odyssey_combat_positions%rowtype;
  v_grid public.odyssey_combat_grid_settings%rowtype;
  v_control jsonb := '{}'::jsonb;
  v_distance_cells integer := 0;
  v_move_cost_m integer := 0;
  v_log_id uuid := null;
  v_state_version integer := 0;
  v_prev_cell_q integer := 0;
  v_prev_cell_r integer := 0;
  v_prev_scene_x numeric := 0;
  v_prev_scene_y numeric := 0;
  v_effective_stats jsonb := '{}'::jsonb;
  v_skip_movement boolean := false;
  v_consumes_full_turn boolean := false;
  v_suppress_movement boolean := false;
  v_is_alive boolean := true;
  v_is_conscious boolean := true;
  v_resolved_token_id text := '';
  v_has_token_link boolean := false;
  v_blocked_cell_q integer := null;
  v_blocked_cell_r integer := null;
  v_blocked_token_id text := '';
  v_blocked_character_id uuid := null;
begin
  if v_encounter_id is null or v_character_id is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'encounter_id and character_id are required.'
    );
  end if;

  if v_dest_q is null or v_dest_r is null or v_dest_scene_x is null or v_dest_scene_y is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'destination cell and scene coordinates are required.'
    );
  end if;

  select *
  into v_encounter
  from public.odyssey_combat_encounters
  where id = v_encounter_id
    and status = 'active'
    and ended_at is null
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ENCOUNTER_NOT_ACTIVE',
      'message', 'Encounter is not active.'
    );
  end if;

  select *
  into v_entry
  from public.odyssey_initiative_entries
  where encounter_id = v_encounter_id
    and character_id = v_character_id
    and is_active = true
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'PARTICIPANT_NOT_FOUND',
      'message', 'Participant was not found.'
    );
  end if;

  v_control := public.odyssey_can_control_character(v_character_id, v_actor_player_id, v_actor_is_gm);
  if coalesce((v_control->>'allowed')::boolean, false) = false then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_NOT_ALLOWED',
      'message', 'You cannot control this participant.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_encounter.active_entry_id is distinct from v_entry.id then
    return jsonb_build_object(
      'ok', false,
      'error', 'NOT_ACTIVE_TURN',
      'message', 'It is not this participant''s turn.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_state_version is not null
     and coalesce(v_encounter.state_version, 0) <> v_expected_state_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Combat state changed. Reload authoritative runtime.',
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if v_expected_movement_version is not null
     and coalesce(v_entry.movement_version, 0) <> v_expected_movement_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'STALE_MOVEMENT_STATE',
      'message', 'Movement state changed. Reload authoritative runtime.',
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select *
  into v_grid
  from public.odyssey_combat_grid_settings
  where encounter_id = v_encounter_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'The tactical grid has not been synced by the GM yet.'
    );
  end if;

  if v_grid.grid_type <> 'square'
     or coalesce(v_grid.meters_per_cell, 0) <= 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_COMBAT_GRID',
      'message', 'Tactical Move v1 supports only square grids.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select *
  into v_position
  from public.odyssey_combat_positions
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  for update;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'This combat token position has not been synced yet.'
    );
  end if;

  v_resolved_token_id := coalesce(nullif(v_token_id, ''), coalesce(v_position.token_id, ''));

  if v_token_id <> '' and v_position.token_id <> v_token_id then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'Token link changed. Reload authoritative runtime.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select exists(
    select 1
    from public.odyssey_token_links link
    where link.room_id = v_encounter.room_id
      and link.scene_id = v_encounter.scene_id
      and link.character_id = v_character_id
      and link.token_id = v_resolved_token_id
      and link.is_active = true
  )
  into v_has_token_link;

  if not v_has_token_link then
    return jsonb_build_object(
      'ok', false,
      'error', 'TOKEN_LINK_NOT_FOUND',
      'message', 'Active token link was not found for this combatant.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  v_effective_stats := public.get_effective_character_stats(v_character_id);
  v_skip_movement := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'skip_movement'), '')::boolean, false);
  v_consumes_full_turn := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'consumes_full_turn'), '')::boolean, false);
  v_suppress_movement := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'suppress_movement'), '')::boolean, false);
  v_is_alive := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'is_alive'), '')::boolean, true);
  v_is_conscious := coalesce(nullif(jsonb_extract_path_text(v_effective_stats, 'derived', 'is_conscious'), '')::boolean, true);

  if not v_is_alive or not v_is_conscious or v_skip_movement or v_consumes_full_turn or v_suppress_movement then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVEMENT_LOCKED',
      'message', 'Movement is currently blocked by combat state or effects.',
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  v_prev_cell_q := v_position.cell_q;
  v_prev_cell_r := v_position.cell_r;
  v_prev_scene_x := v_position.scene_x;
  v_prev_scene_y := v_position.scene_y;

  v_distance_cells := greatest(
    abs(coalesce(v_dest_q, 0) - coalesce(v_position.cell_q, 0)),
    abs(coalesce(v_dest_r, 0) - coalesce(v_position.cell_r, 0))
  );
  v_move_cost_m := v_distance_cells * greatest(coalesce(v_grid.meters_per_cell, 1), 1);

  if v_distance_cells = 0 then
    return jsonb_build_object(
      'ok', true,
      'encounter_id', v_encounter_id,
      'character_id', v_character_id,
      'position',
        jsonb_build_object(
          'token_id', v_position.token_id,
          'cell_q', v_position.cell_q,
          'cell_r', v_position.cell_r,
          'scene_x', v_position.scene_x,
          'scene_y', v_position.scene_y,
          'updated_at', v_position.updated_at
        ),
      'distance_cells', 0,
      'move_cost_m', 0,
      'move_current', coalesce(v_entry.move_current, 0),
      'movement_version', coalesce(v_entry.movement_version, 0),
      'state_version', coalesce(v_encounter.state_version, 0),
      'log_id', null,
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  select
    path.cell_q,
    path.cell_r,
    occupied.token_id,
    occupied.character_id
  into
    v_blocked_cell_q,
    v_blocked_cell_r,
    v_blocked_token_id,
    v_blocked_character_id
  from public.odyssey_build_straight_square_path(
    v_position.cell_q,
    v_position.cell_r,
    v_dest_q,
    v_dest_r
  ) path
  join public.odyssey_combat_positions occupied
    on occupied.encounter_id = v_encounter_id
   and occupied.cell_q = path.cell_q
   and occupied.cell_r = path.cell_r
   and occupied.character_id <> v_character_id
  join public.odyssey_initiative_entries occupied_entry
    on occupied_entry.encounter_id = v_encounter_id
   and occupied_entry.character_id = occupied.character_id
   and occupied_entry.is_active = true
  where path.step_index > 0
  order by path.step_index
  limit 1;

  if found then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_PATH_BLOCKED',
      'message', 'Path blocked by another combatant.',
      'blocked_cell',
        jsonb_build_object(
          'cell_q', v_blocked_cell_q,
          'cell_r', v_blocked_cell_r
        ),
      'blocked_token_id', nullif(v_blocked_token_id, ''),
      'blocked_character_id', v_blocked_character_id,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_current', coalesce(v_entry.move_current, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  if coalesce(v_entry.move_current, 0) < v_move_cost_m then
    return jsonb_build_object(
      'ok', false,
      'error', 'MOVE_EXCEEDS_REMAINING',
      'message', 'Movement exceeds remaining distance.',
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_current', coalesce(v_entry.move_current, 0),
      'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
    );
  end if;

  update public.odyssey_combat_positions
  set
    token_id = v_resolved_token_id,
    cell_q = v_dest_q,
    cell_r = v_dest_r,
    scene_x = v_dest_scene_x,
    scene_y = v_dest_scene_y,
    updated_at = timezone('utc', now())
  where encounter_id = v_encounter_id
    and character_id = v_character_id
  returning * into v_position;

  update public.odyssey_initiative_entries
  set
    move_current = greatest(move_current - v_move_cost_m, 0),
    movement_version = coalesce(movement_version, 0) + 1
  where id = v_entry.id
  returning * into v_entry;

  v_state_version := public.odyssey_increment_encounter_state_version(v_encounter_id);

  v_log_id := public.odyssey_combat_log_insert(
    v_encounter.campaign_id,
    v_encounter.room_id,
    v_encounter.scene_id,
    v_encounter.id,
    v_encounter.current_round,
    v_character_id,
    null,
    v_character_id,
    'public',
    'move',
    public.odyssey_character_display_name(v_character_id) || ' moved ' || v_move_cost_m || ' m.',
    jsonb_build_object(
      'token_id', v_position.token_id,
      'from_cell_q', v_prev_cell_q,
      'from_cell_r', v_prev_cell_r,
      'from_scene_x', v_prev_scene_x,
      'from_scene_y', v_prev_scene_y,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'to_scene_x', v_dest_scene_x,
      'to_scene_y', v_dest_scene_y,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    jsonb_build_object(
      'token_id', v_position.token_id,
      'to_cell_q', v_dest_q,
      'to_cell_r', v_dest_r,
      'distance_cells', v_distance_cells,
      'move_cost_m', v_move_cost_m,
      'move_remaining', v_entry.move_current
    ),
    coalesce(nullif(v_actor_player_id, ''), 'system')
  );

  return jsonb_build_object(
    'ok', true,
    'encounter_id', v_encounter_id,
    'character_id', v_character_id,
    'position',
      jsonb_build_object(
        'token_id', v_position.token_id,
        'cell_q', v_position.cell_q,
        'cell_r', v_position.cell_r,
        'scene_x', v_position.scene_x,
        'scene_y', v_position.scene_y,
        'updated_at', v_position.updated_at
      ),
    'distance_cells', v_distance_cells,
    'move_cost_m', v_move_cost_m,
    'move_current', coalesce(v_entry.move_current, 0),
    'movement_version', coalesce(v_entry.movement_version, 0),
    'state_version', v_state_version,
    'log_id', v_log_id,
    'runtime', public.odyssey_build_combat_runtime(v_encounter_id, v_actor_player_id, v_actor_is_gm, v_actor_is_gm, 5)
  );
end;
$$;

grant execute on function public.odyssey_build_straight_square_path(integer, integer, integer, integer) to anon, authenticated;
grant execute on function public.combat_move_character(jsonb) to anon, authenticated;
-- ===== END 99_tactical_move_v1_square_path.sql =====


-- ===== BEGIN 92_ability_quickbar_foundation.sql =====

-- Phase 4.0 — Ability Quickbar Foundation
--
-- Creates per-character quickbar layout storage with optimistic version control.
-- Quickbar is a UI preference (which ability goes in which slot), not a game mechanic.
-- Layout persists across sessions; one layout per character; supports empty slots.
--
-- Authority: Canonical quick-actions come from odyssey_character_abilities
-- (manual activation, non-passive, enabled, not-hidden). Server validates that
-- every slot refers to an action that exists in that character's runtime.
--
-- Version conflict detection: expected_version must match current version before
-- update. Stale version is rejected without mutation. Client uses server response
-- as source of truth after Save.
--
-- No remote secret/credential exposure: layout contains only slot → action mappings.

create table if not exists public.odyssey_character_quickbar_layouts (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null,
  layout jsonb not null default '{
    "slots": []
  }'::jsonb check (jsonb_typeof(layout) = 'object'),
  version integer not null default 1 check (version >= 1),
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),

  constraint fk_character_id foreign key (character_id) references public.odyssey_characters(id) on delete cascade,
  constraint unique_layout_per_character unique (character_id)
);

comment on table public.odyssey_character_quickbar_layouts is
  'Per-character quickbar layout: which ability/action occupies which UI slot (1–20+). '
  'Layout is a UI preference, not a game mechanic. Empty slots are supported.';
comment on column public.odyssey_character_quickbar_layouts.layout is
  'Quickbar layout as { slots: [{ slotIndex: int, characterActionId: uuid|null, empty: bool }] }';
comment on column public.odyssey_character_quickbar_layouts.version is
  'Optimistic lock version. Incremented on every successful save. Client must send '
  'expected_version; mismatch returns QUICKBAR_VERSION_CONFLICT without mutation.';

-- Utility: get current quickbar layout with safe defaults.
create or replace function public.odyssey_get_character_quickbar_layout(
  p_character_id uuid
)
returns jsonb
language sql
stable
as $$
  select coalesce(
    t.layout,
    jsonb_build_object('slots', '[]'::jsonb)
  )
  from public.odyssey_character_quickbar_layouts t
  where t.character_id = p_character_id
$$;

-- Save quickbar layout with optimistic version check.
-- Returns: { ok, error, layout, version }
-- Errors: QUICKBAR_VERSION_CONFLICT, CHARACTER_NOT_FOUND
create or replace function public.odyssey_save_character_quickbar_layout(
  p_character_id uuid,
  p_expected_version integer,
  p_slots jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_current_version integer;
  v_ok boolean := true;
  v_error text := null;
  v_result jsonb;
begin
  -- Validate character exists.
  if not exists(
    select 1 from public.odyssey_characters where id = p_character_id and not coalesce(is_deleted, false)
  ) then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'message', 'Character does not exist or is deleted'
    );
  end if;

  -- Get current version. Table alias + qualified column avoid ANY ambiguity
  -- with the plpgsql variable / the excluded pseudo-row used further below —
  -- a bare "version" here previously raised "column reference is ambiguous".
  select t.version into v_current_version
  from public.odyssey_character_quickbar_layouts t
  where t.character_id = p_character_id;

  -- Default to version 0 if no layout exists yet.
  v_current_version := coalesce(v_current_version, 0);

  -- Check version conflict.
  if p_expected_version is not null and p_expected_version != v_current_version then
    return jsonb_build_object(
      'ok', false,
      'error', 'QUICKBAR_VERSION_CONFLICT',
      'message', format('Expected version %s, but server has %s', p_expected_version, v_current_version),
      'server_version', v_current_version
    );
  end if;

  -- Insert or update layout. The target table carries an explicit alias (t) so
  -- every column in SET/RETURNING is unambiguously qualified against either
  -- the existing row (t.*) or the proposed row (excluded.*) — never a bare name.
  insert into public.odyssey_character_quickbar_layouts as t (character_id, layout, version, updated_at)
  values (p_character_id, jsonb_build_object('slots', coalesce(p_slots, '[]'::jsonb)), v_current_version + 1, timezone('utc', now()))
  on conflict (character_id) do update set
    layout = excluded.layout,
    version = t.version + 1,
    updated_at = timezone('utc', now())
  returning t.layout, t.version
  into v_result, v_current_version;

  return jsonb_build_object(
    'ok', true,
    'error', null,
    'layout', v_result,
    'version', v_current_version
  );
end;
$$;

comment on function public.odyssey_save_character_quickbar_layout is
  'Save per-character quickbar layout with optimistic version control. '
  'Returns { ok, error, layout, version }. '
  'Version mismatch returns QUICKBAR_VERSION_CONFLICT without mutation.';

-- Trigger to update updatedAt on manual layout modification (if any).
create or replace function public.odyssey_quickbar_layout_update_timestamp()
returns trigger
language plpgsql
as $$
begin
  new.updated_at := timezone('utc', now());
  return new;
end;
$$;

drop trigger if exists odyssey_quickbar_layout_timestamp on public.odyssey_character_quickbar_layouts;
create trigger odyssey_quickbar_layout_timestamp
before update on public.odyssey_character_quickbar_layouts
for each row
execute function public.odyssey_quickbar_layout_update_timestamp();

-- RPC: Get full quick-actions runtime for a character (Phase 4.0+).
-- Returns: { characterId, quickActions: [...], quickbar: { slots, maxSlots, version } }
--
-- Quick actions are: odyssey_character_abilities where
--   - is_hidden = false
--   - is_enabled = true
--   - ability_kind != 'passive'
--   - activation_type = 'manual'
--   - character is not in a state that disables them (dead, unconscious, skip_turn effect)
--
-- Each action includes: id, name, type, source, cost, cooldown, targeting, availability reason.
-- Disabled reasons are server-provided (never fabricated on client).
--
-- Quickbar layout is loaded separately and validated; slots must contain only
-- actions that exist in quickActions. Empty slots are supported.
--
-- To avoid duplication with get_character_runtime_bundle, integrate this as an
-- extension or a thin wrapper that extracts the abilities section.

create or replace function public.odyssey_get_character_quick_actions_runtime(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_character_exists boolean;
  v_is_alive boolean;
  v_is_conscious boolean;
  v_has_skip_turn_effect boolean;
  v_quick_actions jsonb := '[]'::jsonb;
  v_layout jsonb;
  v_version integer := 1;
begin
  -- Validate character exists.
  select exists(
    select 1 from public.odyssey_characters where id = p_character_id and not coalesce(is_deleted, false)
  ) into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'message', 'Character does not exist or is deleted',
      'characterId', p_character_id,
      'quickActions', '[]'::jsonb,
      'quickbar', jsonb_build_object('slots', '[]'::jsonb, 'maxSlots', 20, 'version', 1)
    );
  end if;

  -- Check character state eligibility. Alive/conscious live on the combat-state
  -- table (odyssey_character_combat_state), NOT on odyssey_characters; a character
  -- with no combat-state row yet is treated as alive + conscious (defaults).
  select coalesce(cs.is_alive, true), coalesce(cs.is_conscious, true)
  into v_is_alive, v_is_conscious
  from public.odyssey_characters c
  left join public.odyssey_character_combat_state cs on cs.character_id = c.id
  where c.id = p_character_id;

  -- Check for a skip_turn effect via the canonical engine helper (reads the
  -- effect's data.flags.skip_turn — the same source the turn engine uses).
  v_has_skip_turn_effect := public.odyssey_character_has_active_effect_flag(p_character_id, 'skip_turn');

  -- Fetch quickbar layout and version (qualified — see the save function for why).
  select t.layout, t.version into v_layout, v_version
  from public.odyssey_character_quickbar_layouts t
  where t.character_id = p_character_id;

  v_layout := coalesce(v_layout, jsonb_build_object('slots', '[]'::jsonb));
  -- No saved layout yet -> version 0, matching odyssey_save_character_quickbar_layout's
  -- own "no row" default. A client that reads version 0 here and saves with
  -- expected_version=0 must succeed (first insert bumps it to 1) — these two
  -- functions must never disagree on what "nothing saved yet" means.
  v_version := coalesce(v_version, 0);

  -- Build quick-actions list from odyssey_character_abilities.
  -- In Phase 4.0, only populate metadata; no execution.
  -- Disabled reasons are server-determined, never fabricated.
  v_quick_actions := coalesce(
    (
      select jsonb_agg(
        jsonb_build_object(
          'characterActionId', ca.id,
          'definitionId', ca.ability_def_id,
          'sourceType', ad.source_type,
          -- Canonical action type (one of attack_technique|directed|instant|toggle),
          -- derived from the definition. activation_type ('manual') is NOT the type.
          -- Toggle has no schema marker yet → deferred to Phase 4.1 (data convention).
          'type', case
            when coalesce(ad.effect_mode, '') = 'attack' or ad.ability_kind = 'attack' then 'attack_technique'
            when coalesce(ad.target_type, 'none') in ('character', 'body_part') then 'directed'
            else 'instant'
          end,
          'name', ad.name,
          'shortDescription', substring(ad.description, 1, 100),
          'fullDescription', ad.description,
          'iconKey', coalesce(ad.data->>'icon_key', 'bolt'),
          'semanticKind', ad.ability_kind,

          'targeting', jsonb_build_object(
            'mode', coalesce(ad.target_type, 'none'),
            'minTargets', 1,
            'maxTargets', 1,
            'allowAllies', true,
            'allowSelf', ad.target_type = 'self',
            'requiresBodyZone', ad.target_type = 'body_part'
          ),

          'costs', jsonb_build_object(
            'main', case when ad.resource_mode = 'pool' then 1 else 0 end,
            'move', 0,
            'psi', case when ad.resource_pool_code = 'psi' then coalesce((ald.data->>'psi_cost')::int, 0) else 0 end,
            'charges', case when ad.resource_mode = 'item' then coalesce(ca.current_charges, 0) else 0 end
          ),

          'cooldown', jsonb_build_object(
            'current', ca.current_cooldown_rounds,
            'max', coalesce(ald.cooldown_rounds, 0),
            'unit', 'turn'
          ),

          'state', jsonb_build_object(
            'available', ca.is_enabled and not v_has_skip_turn_effect and (v_is_alive or ad.target_type = 'none'),
            'active', false, -- Phase 4.1
            'disabledReason', case
              when not ca.is_enabled then 'Ability is disabled'
              when v_has_skip_turn_effect then 'Skipping turn'
              when ca.current_cooldown_rounds > 0 then format('Cooldown: %s turns', ca.current_cooldown_rounds)
              when not v_is_alive then 'Character is dead'
              else null
            end,
            'selectable', ca.is_enabled and not v_has_skip_turn_effect and (v_is_alive or ad.target_type = 'none')
          ),

          'requirements', jsonb_build_object(
            'weaponClass', null, -- Phase 4.1: weapon-linked actions
            'weaponId', null,
            'conditionSummary', null
          )
        )
        order by ca.sort_order, ca.created_at
      )
    ),
    '[]'::jsonb
  )
  from public.odyssey_character_abilities ca
  join public.odyssey_ability_defs ad on ad.id = ca.ability_def_id
  left join public.odyssey_ability_level_defs ald on ald.ability_def_id = ad.id and ald.ability_level = ca.learned_level
  where ca.character_id = p_character_id
    and ca.is_hidden = false
    and ca.is_enabled = true
    and ad.ability_kind != 'passive'
    and ad.activation_type in ('manual', 'custom');

  return jsonb_build_object(
    'ok', true,
    'error', null,
    'characterId', p_character_id,
    'quickActions', v_quick_actions,
    'quickbar', jsonb_build_object(
      'slots', coalesce(v_layout->'slots', '[]'::jsonb),
      'maxSlots', 20,
      'version', v_version
    )
  );
end;
$$;

comment on function public.odyssey_get_character_quick_actions_runtime is
  'Fetch full quick-actions runtime for a character, including quickbar layout. '
  'Returns only eligible actions (manual, non-passive, enabled, not-hidden). '
  'Disabled reasons are server-provided. Layout has version for optimistic locking. '
  'Phase 4.0: metadata only; Phase 4.1: execution.';

-- RLS: Allow characters to read/write their own layout; GM can read all.
-- (Full auth enforcement is Phase B0; UX check is Phase 4.0.)
alter table public.odyssey_character_quickbar_layouts enable row level security;

drop policy if exists quickbar_character_own_access on public.odyssey_character_quickbar_layouts;
create policy quickbar_character_own_access on public.odyssey_character_quickbar_layouts
  for all
  using (true) -- UX check in Phase 4.0; server auth in Phase B0
  with check (true);

-- Indexes for common queries.
create index if not exists odyssey_character_quickbar_layouts_character_idx
  on public.odyssey_character_quickbar_layouts(character_id);

create index if not exists odyssey_character_quickbar_layouts_updated_idx
  on public.odyssey_character_quickbar_layouts(updated_at desc);

-- ===== END 92_ability_quickbar_foundation.sql =====



-- ===== BEGIN 100_armed_attack_technique_execution.sql =====

-- Odyssey System: Phase 4.1A — Attack Techniques & ARMED Modifiers (server).
--
-- Adds server-authoritative "armed attack technique" support to the existing
-- weapon-attack path. perform_attack (redefined here, based on migration 90)
-- now accepts an optional `armed_action_ids: [character-action-id]` array
-- alongside the existing payload fields. Absence of the field, or an empty
-- array, is byte-for-byte the legacy behavior from migration 90 — nothing
-- below changes if a client never sends it.
--
-- Scope (see docs/PHASE_4_1A_ATTACK_TECHNIQUES_AUDIT.md §3 for the full
-- reasoning): only the technique's canonical `attack_accuracy_bonus`
-- (odyssey_ability_level_defs) is applied to the weapon attack, via the
-- EXISTING attack_context.manual_attack_bonus channel that perk bonuses
-- already use (migration 90, lines ~731-741) — no new effect grammar, no
-- touching odyssey_perform_weapon_attack itself. odyssey_perform_weapon_attack
-- has been hot-patched in place across six prior migrations (33, 42, 44, 46,
-- 48, 89) via pg_get_functiondef() introspection of the LIVE function; its
-- true current body cannot be safely reconstructed from static files, so it
-- is not touched here. A technique whose resolved level data carries a
-- damage bonus, armor-pierce, or ignore-armor effect is therefore rejected
-- at arm-validation time with ACTION_EFFECT_NOT_IMPLEMENTED — an honest
-- "not yet" rather than silently dropping part of its effect. Full damage/
-- armor-pierce support is Phase 4.1B, once the live function body can be
-- safely inspected with real DB access.
--
-- Stack rule: no canonical stack_group column exists anywhere in the schema
-- (confirmed empty grep in the audit). Per spec, this migration enforces the
-- safe fallback: at most one armed attack technique per attack. More than
-- one id in armed_action_ids is rejected with ACTION_STACK_CONFLICT before
-- anything else is validated.
--
-- Validate-before-spend: every rejection below (ARMED_ACTION_INVALID,
-- ARMED_ACTION_ON_COOLDOWN, NOT_ENOUGH_PSI, NOT_ENOUGH_CHARGES,
-- WEAPON_REQUIREMENT_NOT_MET, TARGET_REQUIREMENT_NOT_MET,
-- ACTION_STACK_CONFLICT, ACTION_EFFECT_NOT_IMPLEMENTED) happens BEFORE
-- odyssey_perform_weapon_attack is ever called, so an invalid armed
-- technique spends no MAIN, no ammo, no PSI, no charges, and touches no
-- cooldown — matching the existing "a rejected/failed attack spends
-- nothing" guarantee migration 90 already established for the session gate.
--
-- Consume-on-resolution: the technique's own cost (PSI/charges) and cooldown
-- are only applied AFTER odyssey_perform_weapon_attack returns ok=true (hit
-- and miss both count as "resolved" — same rule as MAIN a few lines below).
-- This reuses odyssey_consume_character_ability_cost(uuid) verbatim
-- (migration 47) — the exact same function the ability-cast path already
-- uses — so there is no second cost/cooldown implementation anywhere.
--
-- Response shape addition: every perform_attack response (including legacy
-- ones with no armed_action_ids) now carries an `armed_actions` array
-- describing what happened to each armed id: characterActionId, validated,
-- applied, stackGroup (always null until one exists), costsConsumed,
-- cooldownBefore/After, and reason when rejected. Empty array when no
-- technique was armed.

create or replace function public.perform_attack(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := coalesce(p_payload, '{}'::jsonb);
  v_character_ability_id uuid := public.odyssey_try_parse_uuid(v_payload->>'character_ability_id');
  v_ability_code text := lower(trim(coalesce(v_payload->>'ability_code', '')));
  v_attacker_character_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'attacker_character_id', v_payload->>'character_id'));
  v_target_character_id uuid := public.odyssey_try_parse_uuid(v_payload->>'target_character_id');
  v_target_body_part_id uuid := public.odyssey_try_parse_uuid(v_payload->>'target_body_part_id');
  v_character_weapon_id uuid := public.odyssey_try_parse_uuid(coalesce(v_payload->>'character_weapon_id', v_payload->>'weapon_id'));
  v_distance_m numeric := greatest(coalesce(nullif(trim(coalesce(v_payload->>'distance_m', '')), '')::numeric, 0), 0);
  v_encounter_id uuid := public.odyssey_try_parse_uuid(v_payload->>'encounter_id');
  v_debug boolean := coalesce(nullif(trim(coalesce(v_payload->>'debug', '')), '')::boolean, false);
  v_lock_state jsonb := '{}'::jsonb;
  v_perk_context_result jsonb := jsonb_build_object(
    'ok', true,
    'attack_accuracy_bonus', 0,
    'ammo_base_damage_multiplier', 1,
    'flags', '{}'::jsonb,
    'perk_modifiers', '[]'::jsonb,
    'consume_effect_ids', '[]'::jsonb
  );
  v_attack_context jsonb := '{}'::jsonb;
  v_existing_bonus integer := 0;
  v_perk_bonus integer := 0;
  v_result jsonb := '{}'::jsonb;
  v_retry_effect jsonb := jsonb_build_object('ok', true, 'applied', false);
  v_post_hooks jsonb := jsonb_build_object(
    'ok', true,
    'attacker_changed', false,
    'target_changed', false,
    'changed_effect_ids', '[]'::jsonb,
    'changed_weapon_ids', '[]'::jsonb
  );
  v_refresh_attacker boolean := false;
  v_refresh_target boolean := false;
  v_target_alive_before boolean := true;
  v_target_alive_after boolean := true;
  v_target_movement_version integer := 0;
  v_finalized jsonb := '{}'::jsonb;
  v_attacker_refresh_result jsonb := '{}'::jsonb;
  v_target_refresh_result jsonb := '{}'::jsonb;
  v_started_at timestamptz := clock_timestamp();
  v_stage_started_at timestamptz := clock_timestamp();
  v_weapon_validation_ms numeric := 0;
  v_damage_apply_ms numeric := 0;
  v_perk_hooks_ms numeric := 0;
  v_final_refresh_attacker_ms numeric := 0;
  v_final_refresh_target_ms numeric := 0;
  v_finalize_result_ms numeric := 0;
  -- Phase 3E.0 session gate state
  v_participation jsonb := null;
  v_expected_session_version integer := nullif(trim(coalesce(v_payload->>'expected_encounter_version', '')), '')::integer;
  v_session_use_reaction boolean := false;
  -- Phase 4.1A armed attack technique state
  v_armed_action_ids jsonb := case
    when jsonb_typeof(v_payload->'armed_action_ids') = 'array' then v_payload->'armed_action_ids'
    else '[]'::jsonb
  end;
  v_armed_action_id uuid := null;
  v_armed_ability record;
  v_armed_level record;
  v_armed_effective_level integer := 0;
  v_armed_technique_bonus integer := 0;
  v_armed_pool_current integer := null;
  v_armed_payload_attack_type text := nullif(trim(coalesce(v_payload->>'attack_type', '')), '');
  v_armed_results jsonb := '[]'::jsonb;
  v_armed_cost_result jsonb := null;
  v_armed_cooldown_before integer := 0;
  v_armed_cooldown_after integer := 0;
begin
  if v_target_character_id is not null then
    select coalesce(s.is_alive, true)
    into v_target_alive_before
    from public.odyssey_character_combat_state s
    where s.character_id = v_target_character_id;

    if v_encounter_id is not null then
      select coalesce(e.movement_version, 0)
      into v_target_movement_version
      from public.odyssey_initiative_entries e
      where e.encounter_id = v_encounter_id
        and e.character_id = v_target_character_id
        and e.is_active = true
      order by e.updated_at desc, e.id desc
      limit 1;
    end if;
  end if;

  if v_character_ability_id is not null or v_ability_code <> '' then
    return public.odyssey_perform_ability_attack(v_payload);
  end if;

  -- Phase 3E.0: server-authoritative combat-session gate. Looked up from the
  -- ATTACKER'S OWN participation — never from client-sent encounter context —
  -- so removing combat_session/encounter fields from the payload cannot
  -- bypass the action economy while the character is in an active encounter.
  v_participation := public.odyssey_get_active_participation(v_attacker_character_id);
  if v_participation is not null then
    if v_expected_session_version is not null
       and v_expected_session_version <> coalesce((v_participation->>'state_version')::integer, 0) then
      return jsonb_build_object(
        'ok', false,
        'error', 'STATE_VERSION_CONFLICT',
        'message', 'Combat state changed. Reload authoritative runtime.',
        'encounter_state_version', (v_participation->>'state_version')::integer
      );
    end if;

    if coalesce((v_participation->>'is_current_turn')::boolean, false) = false then
      if coalesce((v_participation->>'reaction_action_current')::integer, 0) > 0 then
        v_session_use_reaction := true;
      else
        return jsonb_build_object(
          'ok', false,
          'error', 'NOT_CURRENT_TURN',
          'message', 'It is not this character''s turn.'
        );
      end if;
    end if;

    if not v_session_use_reaction
       and coalesce((v_participation->>'action_current')::integer, 0) < 1 then
      return jsonb_build_object(
        'ok', false,
        'error', 'ACTION_NOT_AVAILABLE',
        'message', 'MAIN action is already spent.'
      );
    end if;
  end if;

  -- ---------------------------------------------------------------------
  -- Phase 4.1A: armed attack technique validation. Runs BEFORE the weapon
  -- lock / perk context / odyssey_perform_weapon_attack call, so nothing is
  -- spent when an armed technique is rejected. Max one armed id until a real
  -- stack_group column exists anywhere in the schema (see migration header).
  -- ---------------------------------------------------------------------
  if jsonb_array_length(v_armed_action_ids) > 1 then
    return jsonb_build_object(
      'ok', false,
      'error', 'ACTION_STACK_CONFLICT',
      'message', 'Only one attack technique may be armed at a time until stack groups exist.'
    );
  end if;

  if jsonb_array_length(v_armed_action_ids) = 1 then
    v_armed_action_id := public.odyssey_try_parse_uuid(v_armed_action_ids->>0);

    if v_armed_action_id is null then
      return jsonb_build_object(
        'ok', false,
        'error', 'ARMED_ACTION_INVALID',
        'message', 'Armed action id is malformed.'
      );
    end if;

    select
      ability.id,
      ability.character_id,
      ability.current_cooldown_rounds,
      ability.current_charges,
      ability.learned_level,
      def.id as ability_def_id,
      def.code as ability_code,
      def.name as ability_name,
      def.ability_kind,
      def.effect_mode,
      def.attack_type,
      def.target_type,
      def.resource_mode,
      def.resource_pool_code
    into v_armed_ability
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    where ability.id = v_armed_action_id
      and ability.character_id = v_attacker_character_id
      and ability.is_enabled = true
      and ability.is_hidden = false
    for update of ability;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'ARMED_ACTION_INVALID',
        'message', 'Armed action does not belong to the attacker, or no longer exists.',
        'character_ability_id', v_armed_action_id
      );
    end if;

    if coalesce(v_armed_ability.effect_mode, '') <> 'attack' and coalesce(v_armed_ability.ability_kind, '') <> 'attack' then
      return jsonb_build_object(
        'ok', false,
        'error', 'ARMED_ACTION_INVALID',
        'message', 'Armed action is not an attack technique.',
        'character_ability_id', v_armed_action_id
      );
    end if;

    if coalesce(v_armed_ability.current_cooldown_rounds, 0) > 0 then
      return jsonb_build_object(
        'ok', false,
        'error', 'ARMED_ACTION_ON_COOLDOWN',
        'message', format('%s is on cooldown for %s more turn(s).', v_armed_ability.ability_name, v_armed_ability.current_cooldown_rounds),
        'character_ability_id', v_armed_action_id,
        'cooldown_rounds_left', v_armed_ability.current_cooldown_rounds
      );
    end if;

    if coalesce(v_armed_ability.target_type, 'none') not in ('character', 'body_part') then
      return jsonb_build_object(
        'ok', false,
        'error', 'TARGET_REQUIREMENT_NOT_MET',
        'message', format('%s cannot be aimed at a weapon-attack target.', v_armed_ability.ability_name),
        'character_ability_id', v_armed_action_id
      );
    end if;

    -- Requirements.weaponClass/weaponId have no canonical source yet (see
    -- audit §2/§4) — the one real, existing field is the technique's own
    -- attack_type (ranged/melee), checked only when the client actually sends
    -- one. If the client never sends attack_type this check is a no-op —
    -- documented in the audit rather than papered over with an invented
    -- weapon lookup.
    if v_armed_ability.attack_type is not null
       and v_armed_payload_attack_type is not null
       and v_armed_ability.attack_type <> v_armed_payload_attack_type then
      return jsonb_build_object(
        'ok', false,
        'error', 'WEAPON_REQUIREMENT_NOT_MET',
        'message', format('%s requires a %s attack.', v_armed_ability.ability_name, v_armed_ability.attack_type),
        'character_ability_id', v_armed_action_id
      );
    end if;

    v_armed_effective_level := public.odyssey_get_character_ability_effective_level(v_armed_action_id);

    select *
    into v_armed_level
    from public.odyssey_ability_level_defs level_data
    where level_data.ability_def_id = v_armed_ability.ability_def_id
      and level_data.ability_level <= v_armed_effective_level
    order by level_data.ability_level desc
    limit 1;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'ARMED_ACTION_INVALID',
        'message', 'No level data is available for this attack technique.',
        'character_ability_id', v_armed_action_id
      );
    end if;

    -- Scope for 4.1A: only the additive accuracy bonus is supported on the
    -- weapon-attack path (see migration header). A damage/armor effect is
    -- rejected honestly rather than silently dropped.
    if coalesce(v_armed_level.attack_damage_bonus, 0) <> 0
       or coalesce(v_armed_level.attack_armor_pierce, 0) <> 0
       or coalesce(v_armed_level.ignore_armor, false) then
      return jsonb_build_object(
        'ok', false,
        'error', 'ACTION_EFFECT_NOT_IMPLEMENTED',
        'message', format('%s has a damage/armor effect not yet supported for weapon attacks.', v_armed_ability.ability_name),
        'character_ability_id', v_armed_action_id
      );
    end if;

    if v_armed_ability.resource_mode = 'pool' then
      select coalesce(p.current_value, 0)
      into v_armed_pool_current
      from public.odyssey_character_resource_pools p
      join public.odyssey_resource_pool_defs d on d.id = p.resource_pool_def_id
      where p.character_id = v_armed_ability.character_id
        and d.code = v_armed_ability.resource_pool_code
      for update of p;

      if coalesce(v_armed_pool_current, 0) < coalesce(v_armed_level.resource_cost, 0) then
        return jsonb_build_object(
          'ok', false,
          'error', 'NOT_ENOUGH_PSI',
          'message', format('Not enough %s for %s.', coalesce(v_armed_ability.resource_pool_code, 'resource'), v_armed_ability.ability_name),
          'character_ability_id', v_armed_action_id,
          'required', coalesce(v_armed_level.resource_cost, 0),
          'available', coalesce(v_armed_pool_current, 0)
        );
      end if;
    elsif v_armed_ability.resource_mode = 'item' and v_armed_ability.current_charges is not null then
      -- current_charges is the same field the quickbar already displays as
      -- costs.charges (migration 92) — this check agrees with what the
      -- player already sees, even though the deeper consume function's own
      -- item-resource branch spends from inventory rather than this counter
      -- (a pre-existing Phase 4.0 nuance, documented in the audit).
      if coalesce(v_armed_ability.current_charges, 0) <= 0 then
        return jsonb_build_object(
          'ok', false,
          'error', 'NOT_ENOUGH_CHARGES',
          'message', format('%s has no charges left.', v_armed_ability.ability_name),
          'character_ability_id', v_armed_action_id
        );
      end if;
    end if;

    v_armed_technique_bonus := coalesce(v_armed_level.attack_accuracy_bonus, 0);
    v_armed_cooldown_before := coalesce(v_armed_ability.current_cooldown_rounds, 0);
  end if;

  v_stage_started_at := clock_timestamp();

  if v_attacker_character_id is not null and v_character_weapon_id is not null then
    v_lock_state := public.odyssey_get_weapon_lock_state(v_attacker_character_id, v_character_weapon_id);
    if coalesce((v_lock_state->>'locked')::boolean, false)
       or coalesce((v_lock_state->>'actor_attack_locked')::boolean, false) then
      return jsonb_build_object(
        'ok', false,
        'error', coalesce(v_lock_state->>'error', 'WEAPON_LOCKED'),
        'message', coalesce(v_lock_state->>'message', 'Weapon is currently locked.'),
        'character_weapon_id', v_character_weapon_id
      );
    end if;

    v_perk_context_result := public.odyssey_get_character_attack_perk_context(
      v_attacker_character_id,
      v_character_weapon_id,
      v_target_character_id,
      v_target_body_part_id,
      v_distance_m,
      nullif(trim(coalesce(v_payload->>'fire_mode_code', '')), ''),
      nullif(trim(coalesce(v_payload->>'attack_type', '')), ''),
      v_encounter_id
    );

    if coalesce((v_perk_context_result->>'ok')::boolean, false) = false then
      return v_perk_context_result;
    end if;
  end if;

  v_weapon_validation_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;

  v_attack_context := case
    when jsonb_typeof(v_payload->'attack_context') = 'object' then v_payload->'attack_context'
    else '{}'::jsonb
  end;
  v_existing_bonus := coalesce(nullif(trim(coalesce(v_attack_context->>'manual_attack_bonus', '')), '')::integer, 0);
  v_perk_bonus := coalesce(nullif(trim(coalesce(v_perk_context_result->>'attack_accuracy_bonus', '')), '')::integer, 0);

  if v_perk_bonus <> 0 or v_armed_technique_bonus <> 0 then
    v_attack_context := v_attack_context || jsonb_build_object('manual_attack_bonus', v_existing_bonus + v_perk_bonus + v_armed_technique_bonus);
    v_payload := v_payload || jsonb_build_object('attack_context', v_attack_context);
  end if;

  v_payload := v_payload || jsonb_build_object('perk_context', v_perk_context_result - 'ok');

  v_stage_started_at := clock_timestamp();
  v_result := public.odyssey_perform_weapon_attack(v_payload);
  v_damage_apply_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;

  if coalesce((v_result->>'ok')::boolean, false) = false then
    return v_result;
  end if;

  -- Phase 3E.0: a RESOLVED attack (hit AND miss identically) spends MAIN (or
  -- the reaction action) atomically with the encounter version bump. Failed /
  -- rejected attacks returned above spend nothing.
  if v_participation is not null then
    perform public.odyssey_apply_turn_costs(
      public.odyssey_try_parse_uuid(v_participation->>'entry_id'),
      1,
      0,
      v_session_use_reaction
    );
    perform public.odyssey_increment_encounter_state_version(
      public.odyssey_try_parse_uuid(v_participation->>'encounter_id')
    );
  end if;

  -- Phase 4.1A: the armed technique is consumed ONLY now that the attack is
  -- resolved (hit or miss both count, exactly like MAIN above). Reuses
  -- odyssey_consume_character_ability_cost verbatim — the same function the
  -- ability-cast path already uses — so there is only ever one PSI/charge
  -- consumption implementation. A resource-consume failure here (extremely
  -- unlikely — the pool row was already locked and checked above in the same
  -- transaction) is recorded on the armed_actions entry rather than failing
  -- the already-resolved attack; nothing else in this function rolls back a
  -- resolved weapon attack for any reason, and this is no exception.
  if v_armed_action_id is not null then
    v_armed_cost_result := public.odyssey_consume_character_ability_cost(v_armed_action_id);
    v_armed_cooldown_after := v_armed_cooldown_before;

    if coalesce((v_armed_cost_result->>'ok')::boolean, false) then
      if coalesce(v_armed_level.cooldown_rounds, 0) > 0 then
        update public.odyssey_character_abilities
        set current_cooldown_rounds = v_armed_level.cooldown_rounds
        where id = v_armed_action_id;
        v_armed_cooldown_after := v_armed_level.cooldown_rounds;
      end if;

      v_armed_results := jsonb_build_array(
        jsonb_build_object(
          'characterActionId', v_armed_action_id,
          'name', v_armed_ability.ability_name,
          'stackGroup', null,
          'validated', true,
          'applied', true,
          'costsConsumed', v_armed_cost_result,
          'cooldownBefore', v_armed_cooldown_before,
          'cooldownAfter', v_armed_cooldown_after,
          'reason', null
        )
      );
    else
      v_armed_results := jsonb_build_array(
        jsonb_build_object(
          'characterActionId', v_armed_action_id,
          'name', v_armed_ability.ability_name,
          'stackGroup', null,
          'validated', true,
          'applied', false,
          'costsConsumed', null,
          'cooldownBefore', v_armed_cooldown_before,
          'cooldownAfter', v_armed_cooldown_before,
          'reason', coalesce(v_armed_cost_result->>'error', 'ARMED_ACTION_INVALID')
        )
      );
    end if;
  end if;

  if jsonb_array_length(coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb)) > 0 then
    update public.odyssey_character_effects e
    set
      is_active = false,
      rounds_left = 0,
      updated_at = timezone('utc', now())
    where e.character_id = v_attacker_character_id
      and e.id in (
        select public.odyssey_try_parse_uuid(value)
        from jsonb_array_elements_text(coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb)) value
      );
    v_refresh_attacker := true;
  end if;

  if v_target_character_id is not null then
    v_target_alive_after := coalesce(
      nullif(v_result#>>'{target_state,is_alive}', '')::boolean,
      nullif(v_result#>>'{target_state,combat_state,is_alive}', '')::boolean,
      v_target_alive_before
    );
  end if;

  v_stage_started_at := clock_timestamp();
  v_post_hooks := public.odyssey_apply_perk_post_attack_hooks(
    jsonb_build_object(
      'attacker_character_id', v_attacker_character_id,
      'character_weapon_id', v_character_weapon_id,
      'target_character_id', v_target_character_id,
      'target_movement_version', v_target_movement_version,
      'created_by', coalesce(v_payload->>'actor_token_id', ''),
      'hit', coalesce(v_result->>'hit', 'false'),
      'target_alive_before', v_target_alive_before,
      'target_alive_after', v_target_alive_after
    )
  );
  v_perk_hooks_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;

  if not coalesce((v_result->>'hit')::boolean, false) then
    v_retry_effect := public.odyssey_grant_first_time_no_retry_effect(
      v_attacker_character_id,
      v_character_weapon_id,
      v_target_character_id,
      v_target_movement_version,
      coalesce(v_payload->>'actor_token_id', '')
    );
    if coalesce((v_retry_effect->>'applied')::boolean, false) = true then
      v_refresh_attacker := true;
    end if;
  end if;

  if jsonb_array_length(coalesce(v_result->'expired_attack_effects', '[]'::jsonb)) > 0 then
    v_refresh_attacker := true;
  end if;

  if coalesce((v_post_hooks->>'attacker_changed')::boolean, false) then
    v_refresh_attacker := true;
  end if;

  if v_armed_action_id is not null then
    v_refresh_attacker := true;
  end if;

  v_refresh_target :=
    coalesce((v_post_hooks->>'target_changed')::boolean, false)
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'body_minor_delta'), '')::integer, 0) > 0
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'body_serious_delta'), '')::integer, 0) > 0
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'body_critical_delta'), '')::integer, 0) > 0
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'armor_minor_delta'), '')::integer, 0) > 0
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'armor_serious_delta'), '')::integer, 0) > 0
    or coalesce(nullif(jsonb_extract_path_text(v_result, 'damage', 'armor_critical_delta'), '')::integer, 0) > 0;

  v_result := v_result || jsonb_build_object(
    'post_attack_perks',
      jsonb_build_object(
        'consumed_effect_ids', coalesce(v_perk_context_result->'consume_effect_ids', '[]'::jsonb),
        'retry_effect', v_retry_effect,
        'post_hooks', v_post_hooks
      ),
    'armed_actions', v_armed_results
  );

  v_stage_started_at := clock_timestamp();
  v_finalized := public.odyssey_finalize_attack_result(v_result, v_target_character_id, v_target_body_part_id);
  v_finalize_result_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;

  if v_refresh_target and v_target_character_id is not null then
    v_stage_started_at := clock_timestamp();
    v_target_refresh_result := public.odyssey_refresh_character_combat_state(v_target_character_id);
    v_final_refresh_target_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;
    v_finalized := v_finalized || jsonb_build_object(
      'target_state',
      coalesce(v_target_refresh_result->'combat_state', '{}'::jsonb)
    );
  end if;

  if v_refresh_attacker and v_attacker_character_id is not null then
    v_stage_started_at := clock_timestamp();
    v_attacker_refresh_result := public.odyssey_refresh_character_combat_state(v_attacker_character_id);
    v_final_refresh_attacker_ms := extract(epoch from (clock_timestamp() - v_stage_started_at)) * 1000.0;
    v_finalized := v_finalized || jsonb_build_object(
      'attacker_state',
      coalesce(v_attacker_refresh_result->'combat_state', '{}'::jsonb)
    );
  end if;

  if v_participation is not null then
    v_finalized := v_finalized || jsonb_build_object(
      'combat_session',
      public.odyssey_build_session_cost_summary(v_participation, v_session_use_reaction)
    );
  end if;

  if v_debug then
    v_finalized := v_finalized || jsonb_build_object(
      'diagnostics',
      jsonb_build_object(
        'total_ms', extract(epoch from (clock_timestamp() - v_started_at)) * 1000.0,
        'stages',
        jsonb_build_object(
          'weapon_validation_ms', v_weapon_validation_ms,
          'attacker_state_ms', 0,
          'target_state_ms', 0,
          'damage_apply_ms', v_damage_apply_ms,
          'perk_hooks_ms', v_perk_hooks_ms,
          'final_refresh_attacker_ms', v_final_refresh_attacker_ms,
          'final_refresh_target_ms', v_final_refresh_target_ms,
          'finalize_result_ms', v_finalize_result_ms
        )
      )
    );
  end if;

  return v_finalized;
end;
$$;

grant execute on function public.perform_attack(jsonb) to anon, authenticated;

-- ===== END 100_armed_attack_technique_execution.sql =====



-- ===== BEGIN 101_quickbar_execution_availability.sql =====

-- Odyssey System: Phase 4.1A.2 — Skills Block Runtime States & Ability
-- Details (server).
--
-- Redefines odyssey_get_character_quick_actions_runtime (migration 92 —
-- fully reissued each time, never hot-patched, safe to redefine again) to
-- close two honesty gaps found in docs/PHASE_4_1A_2_SKILLS_RUNTIME_UI_AUDIT.md:
--
-- 1. `state.available`/`state.disabledReason` never factored in cooldown or
--    resource (PSI/charges) sufficiency — only is_enabled/skip_turn/alive.
--    A technique on cooldown or lacking PSI reported `available: true`, so
--    the client had no honest way to grey it out or refuse to arm it without
--    re-deriving the check itself (exactly the "client guesses" anti-pattern
--    Phase 4.1A.2 forbids).
--
-- 2. No field told the client whether a technique's own EFFECT is actually
--    executable on the current weapon-attack path. perform_attack (migration
--    100) rejects a technique with a nonzero attack_damage_bonus/
--    attack_armor_pierce/ignore_armor as ACTION_EFFECT_NOT_IMPLEMENTED, but
--    the quickbar runtime never surfaced that ahead of time — a HUD wanting
--    to warn the player before Attack would have had to hardcode a check on
--    the ability's name (e.g. "Ethric Strike"), which is explicitly what
--    this phase must NOT do. The new `executionAvailable`/`executionReason`
--    fields are computed from the EXACT SAME odyssey_ability_level_defs
--    columns migration 100 already checks (`ald` was already joined here for
--    cost/cooldown display) — one shared definition of "unsupported effect",
--    never a second client-side copy.
--
-- Everything else in this function (field shapes, join structure, the
-- pre-existing ald-at-learned_level imprecision noted in the audit doc) is
-- unchanged.

create or replace function public.odyssey_get_character_quick_actions_runtime(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_character_exists boolean;
  v_is_alive boolean;
  v_is_conscious boolean;
  v_has_skip_turn_effect boolean;
  v_quick_actions jsonb := '[]'::jsonb;
  v_layout jsonb;
  v_version integer := 1;
begin
  -- Validate character exists.
  select exists(
    select 1 from public.odyssey_characters where id = p_character_id and not coalesce(is_deleted, false)
  ) into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'message', 'Character does not exist or is deleted',
      'characterId', p_character_id,
      'quickActions', '[]'::jsonb,
      'quickbar', jsonb_build_object('slots', '[]'::jsonb, 'maxSlots', 20, 'version', 1)
    );
  end if;

  -- Check character state eligibility. Alive/conscious live on the combat-state
  -- table (odyssey_character_combat_state), NOT on odyssey_characters; a character
  -- with no combat-state row yet is treated as alive + conscious (defaults).
  select coalesce(cs.is_alive, true), coalesce(cs.is_conscious, true)
  into v_is_alive, v_is_conscious
  from public.odyssey_characters c
  left join public.odyssey_character_combat_state cs on cs.character_id = c.id
  where c.id = p_character_id;

  -- Check for a skip_turn effect via the canonical engine helper (reads the
  -- effect's data.flags.skip_turn — the same source the turn engine uses).
  v_has_skip_turn_effect := public.odyssey_character_has_active_effect_flag(p_character_id, 'skip_turn');

  -- Fetch quickbar layout and version (qualified — see the save function for why).
  select t.layout, t.version into v_layout, v_version
  from public.odyssey_character_quickbar_layouts t
  where t.character_id = p_character_id;

  v_layout := coalesce(v_layout, jsonb_build_object('slots', '[]'::jsonb));
  -- No saved layout yet -> version 0, matching odyssey_save_character_quickbar_layout's
  -- own "no row" default. A client that reads version 0 here and saves with
  -- expected_version=0 must succeed (first insert bumps it to 1) — these two
  -- functions must never disagree on what "nothing saved yet" means.
  v_version := coalesce(v_version, 0);

  -- Build quick-actions list from odyssey_character_abilities.
  -- Disabled reasons are server-determined, never fabricated.
  v_quick_actions := coalesce(
    (
      select jsonb_agg(
        jsonb_build_object(
          'characterActionId', ca.id,
          'definitionId', ca.ability_def_id,
          'sourceType', ad.source_type,
          -- Canonical action type (one of attack_technique|directed|instant|toggle),
          -- derived from the definition. activation_type ('manual') is NOT the type.
          -- Toggle has no schema marker yet → deferred to Phase 4.1 (data convention).
          'type', case
            when coalesce(ad.effect_mode, '') = 'attack' or ad.ability_kind = 'attack' then 'attack_technique'
            when coalesce(ad.target_type, 'none') in ('character', 'body_part') then 'directed'
            else 'instant'
          end,
          'name', ad.name,
          'shortDescription', substring(ad.description, 1, 100),
          'fullDescription', ad.description,
          'iconKey', coalesce(ad.data->>'icon_key', 'bolt'),
          'semanticKind', ad.ability_kind,

          'targeting', jsonb_build_object(
            'mode', coalesce(ad.target_type, 'none'),
            'minTargets', 1,
            'maxTargets', 1,
            'allowAllies', true,
            'allowSelf', ad.target_type = 'self',
            'requiresBodyZone', ad.target_type = 'body_part'
          ),

          'costs', jsonb_build_object(
            'main', case when ad.resource_mode = 'pool' then 1 else 0 end,
            'move', 0,
            'psi', case when ad.resource_pool_code = 'psi' then coalesce((ald.data->>'psi_cost')::int, 0) else 0 end,
            'charges', case when ad.resource_mode = 'item' then coalesce(ca.current_charges, 0) else 0 end
          ),

          'cooldown', jsonb_build_object(
            'current', ca.current_cooldown_rounds,
            'max', coalesce(ald.cooldown_rounds, 0),
            'unit', 'turn'
          ),

          -- Phase 4.1A.2: available/disabledReason now factor in cooldown and
          -- resource sufficiency (previously display-only via disabledReason's
          -- cooldown text — never part of `available` itself), plus the new
          -- unsupported-effect check. exec.unsupported_effect and
          -- res.insufficient_* are computed once per row (LEFT JOIN LATERAL
          -- below) and reused here rather than repeating the expressions.
          'state', jsonb_build_object(
            'available',
              ca.is_enabled
              and not v_has_skip_turn_effect
              and (v_is_alive or ad.target_type = 'none')
              and coalesce(ca.current_cooldown_rounds, 0) <= 0
              and not coalesce(res.insufficient_pool, false)
              and not coalesce(res.insufficient_charges, false)
              and not coalesce(exec.unsupported_effect, false),
            'active', false, -- Phase 4.1
            'disabledReason', case
              when not ca.is_enabled then 'Ability is disabled'
              when v_has_skip_turn_effect then 'Skipping turn'
              when not v_is_alive and ad.target_type <> 'none' then 'Character is dead'
              when coalesce(exec.unsupported_effect, false) then 'Attack effect is not supported yet'
              when coalesce(ca.current_cooldown_rounds, 0) > 0 then format('Cooldown: %s turns', ca.current_cooldown_rounds)
              when coalesce(res.insufficient_pool, false) then format('Not enough %s', coalesce(ad.resource_pool_code, 'resource'))
              when coalesce(res.insufficient_charges, false) then 'No charges left'
              else null
            end,
            'selectable',
              ca.is_enabled
              and not v_has_skip_turn_effect
              and (v_is_alive or ad.target_type = 'none')
              and coalesce(ca.current_cooldown_rounds, 0) <= 0
              and not coalesce(res.insufficient_pool, false)
              and not coalesce(res.insufficient_charges, false)
              and not coalesce(exec.unsupported_effect, false),
            -- Distinct from `available`: whether this ability's OWN effect can
            -- run on the current execution path at all, independent of
            -- cooldown/resources/turn state. Reuses the exact same
            -- odyssey_ability_level_defs columns perform_attack (migration
            -- 100) checks — one shared definition, never a client-side guess
            -- or a name-based check.
            'executionAvailable', not coalesce(exec.unsupported_effect, false),
            'executionReason', case when coalesce(exec.unsupported_effect, false) then 'ACTION_EFFECT_NOT_IMPLEMENTED' else null end,
            -- Structural signal so the client can tell "insufficient resource"
            -- apart from any other reason WITHOUT parsing disabledReason text.
            'resourceSufficient', not (coalesce(res.insufficient_pool, false) or coalesce(res.insufficient_charges, false))
          ),

          'requirements', jsonb_build_object(
            'weaponClass', null, -- Phase 4.1: weapon-linked actions
            'weaponId', null,
            'conditionSummary', null
          )
        )
        order by ca.sort_order, ca.created_at
      )
    ),
    '[]'::jsonb
  )
  from public.odyssey_character_abilities ca
  join public.odyssey_ability_defs ad on ad.id = ca.ability_def_id
  left join public.odyssey_ability_level_defs ald on ald.ability_def_id = ad.id and ald.ability_level = ca.learned_level
  left join lateral (
    select (
      coalesce(ald.attack_damage_bonus, 0) <> 0
      or coalesce(ald.attack_armor_pierce, 0) <> 0
      or coalesce(ald.ignore_armor, false)
    ) as unsupported_effect
  ) exec on true
  -- Character's PSI (or other pool) balance, when this ability spends one —
  -- (character_id, resource_pool_def_id) is at most one row, same assumption
  -- migration 100's odyssey_consume_character_ability_cost call site makes.
  left join public.odyssey_resource_pool_defs rpd on rpd.code = ad.resource_pool_code
  left join public.odyssey_character_resource_pools rp
    on rp.character_id = ca.character_id and rp.resource_pool_def_id = rpd.id
  left join lateral (
    select
      (ad.resource_mode = 'pool' and coalesce(rp.current_value, 0) < coalesce(ald.resource_cost, 0)) as insufficient_pool,
      (ad.resource_mode = 'item' and ca.current_charges is not null and ca.current_charges <= 0) as insufficient_charges
  ) res on true
  where ca.character_id = p_character_id
    and ca.is_hidden = false
    and ca.is_enabled = true
    and ad.ability_kind != 'passive'
    and ad.activation_type in ('manual', 'custom');

  return jsonb_build_object(
    'ok', true,
    'error', null,
    'characterId', p_character_id,
    'quickActions', v_quick_actions,
    'quickbar', jsonb_build_object(
      'slots', coalesce(v_layout->'slots', '[]'::jsonb),
      'maxSlots', 20,
      'version', v_version
    )
  );
end;
$$;

comment on function public.odyssey_get_character_quick_actions_runtime is
  'Fetch full quick-actions runtime for a character, including quickbar layout. '
  'Returns only eligible actions (manual, non-passive, enabled, not-hidden). '
  'available/disabledReason/executionAvailable/executionReason are all '
  'server-determined (cooldown, resource sufficiency, and effect-grammar '
  'support) — Phase 4.1A.2. Layout has version for optimistic locking.';

grant execute on function public.odyssey_get_character_quick_actions_runtime(uuid) to anon, authenticated;

-- ===== END 101_quickbar_execution_availability.sql =====

-- ===== BEGIN 102_character_ability_reconcile.sql =====

do $$
declare
  v_constraint_name text;
begin
  select conname
  into v_constraint_name
  from pg_constraint
  where conrelid = 'public.odyssey_ability_defs'::regclass
    and contype = 'c'
    and pg_get_constraintdef(oid) ilike '%source_type%';

  if v_constraint_name is not null then
    execute format(
      'alter table public.odyssey_ability_defs drop constraint %I',
      v_constraint_name
    );
  end if;
end;
$$;

alter table public.odyssey_ability_defs
  add constraint odyssey_ability_defs_source_type_check_v2
  check (
    source_type in (
      'psionic',
      'implant',
      'prosthetic',
      'equipment',
      'item',
      'weapon',
      'skill',
      'perk',
      'innate',
      'custom'
    )
  );

create table if not exists public.odyssey_ability_grants (
  id uuid primary key default gen_random_uuid(),
  source_type text not null check (
    source_type in ('skill', 'perk', 'item', 'equipment', 'weapon')
  ),
  source_def_id uuid not null,
  ability_def_id uuid not null references public.odyssey_ability_defs(id) on delete cascade,
  min_level integer not null default 1,
  is_enabled boolean not null default true,
  data jsonb not null default '{}'::jsonb check (jsonb_typeof(data) = 'object'),
  sort_order integer not null default 0,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create unique index if not exists odyssey_ability_grants_unique
  on public.odyssey_ability_grants (source_type, source_def_id, ability_def_id);

create index if not exists odyssey_ability_grants_source_idx
  on public.odyssey_ability_grants (source_type, source_def_id, is_enabled, sort_order);

create index if not exists odyssey_ability_grants_ability_idx
  on public.odyssey_ability_grants (ability_def_id, sort_order);

alter table public.odyssey_ability_grants enable row level security;

drop policy if exists "odyssey_ability_grants_full_access" on public.odyssey_ability_grants;
create policy "odyssey_ability_grants_full_access"
on public.odyssey_ability_grants
for all
to anon, authenticated
using (true)
with check (true);

grant select, insert, update, delete on public.odyssey_ability_grants to anon, authenticated;

drop trigger if exists odyssey_touch_updated_at_ability_grants on public.odyssey_ability_grants;
create trigger odyssey_touch_updated_at_ability_grants
before update on public.odyssey_ability_grants
for each row
execute function public.odyssey_touch_updated_at();

insert into public.odyssey_ability_grants (
  source_type,
  source_def_id,
  ability_def_id,
  min_level,
  is_enabled,
  data,
  sort_order
)
select
  'skill',
  ad.linked_skill_id,
  ad.id,
  1,
  true,
  jsonb_build_object(
    'generated_from_legacy_linked_skill_id', true
  ),
  coalesce(ad.sort_order, 0)
from public.odyssey_ability_defs ad
where ad.linked_skill_id is not null
  and not exists (
    select 1
    from public.odyssey_ability_grants grant_link
    where grant_link.source_type = 'skill'
      and grant_link.source_def_id = ad.linked_skill_id
      and grant_link.ability_def_id = ad.id
  );

create or replace function public.odyssey_reconcile_character_abilities(
  p_character_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_character_exists boolean := false;
  v_skill_upserted integer := 0;
  v_skill_hidden integer := 0;
  v_perk_upserted integer := 0;
  v_perk_hidden integer := 0;
  v_item_upserted integer := 0;
  v_item_hidden integer := 0;
  v_equipment_upserted integer := 0;
  v_equipment_hidden integer := 0;
  v_weapon_hidden integer := 0;
  v_weapon_result jsonb := '[]'::jsonb;
  v_source record;
  v_existing public.odyssey_character_abilities%rowtype;
  v_payload_data jsonb := '{}'::jsonb;
  v_weapon_sync_result jsonb := '{}'::jsonb;
begin
  select exists(
    select 1
    from public.odyssey_characters c
    where c.id = p_character_id
      and coalesce(c.is_deleted, false) = false
  )
  into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'character_id', p_character_id
    );
  end if;

  for v_source in
    with mapped_skill_grants as (
      select
        ad.id as ability_def_id,
        ad.code as ability_code,
        grant_link.source_def_id as skill_def_id,
        cs.id as character_skill_id,
        greatest(coalesce(cs.level, 0), 0) as skill_level,
        coalesce(grant_link.sort_order, ad.sort_order, 0) as sort_order,
        coalesce(grant_link.data, '{}'::jsonb) as grant_data,
        0 as source_priority
      from public.odyssey_ability_grants grant_link
      join public.odyssey_ability_defs ad on ad.id = grant_link.ability_def_id
      join public.odyssey_character_skills cs
        on cs.character_id = p_character_id
       and cs.skill_def_id = grant_link.source_def_id
      where grant_link.source_type = 'skill'
        and grant_link.is_enabled = true
        and greatest(coalesce(cs.level, 0), 0) >= greatest(coalesce(grant_link.min_level, 1), 1)
    ),
    legacy_skill_grants as (
      select
        ad.id as ability_def_id,
        ad.code as ability_code,
        ad.linked_skill_id as skill_def_id,
        cs.id as character_skill_id,
        greatest(coalesce(cs.level, 0), 0) as skill_level,
        coalesce(ad.sort_order, 0) as sort_order,
        jsonb_build_object(
          'generated_from_legacy_linked_skill_id', true
        ) as grant_data,
        1 as source_priority
      from public.odyssey_ability_defs ad
      join public.odyssey_character_skills cs
        on cs.character_id = p_character_id
       and cs.skill_def_id = ad.linked_skill_id
      where ad.linked_skill_id is not null
        and not exists (
          select 1
          from public.odyssey_ability_grants grant_link
          where grant_link.source_type = 'skill'
            and grant_link.source_def_id = ad.linked_skill_id
            and grant_link.ability_def_id = ad.id
        )
    )
    select distinct on (combined.ability_def_id, combined.character_skill_id)
      combined.*
    from (
      select * from legacy_skill_grants
      union all
      select * from mapped_skill_grants
    ) combined
    order by combined.ability_def_id, combined.character_skill_id, combined.source_priority
  loop
    select *
    into v_existing
    from public.odyssey_character_abilities ability
    where ability.character_id = p_character_id
      and ability.ability_def_id = v_source.ability_def_id
      and ability.source_equipment_item_id is null
      and ability.source_character_item_id is null
      and ability.source_character_weapon_id is null
      and coalesce(ability.data->>'generated_from', 'skill') = 'skill'
    for update of ability;

    v_payload_data :=
      coalesce(v_existing.data, '{}'::jsonb)
      || coalesce(v_source.grant_data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'skill',
        'skill_def_id', v_source.skill_def_id::text,
        'character_skill_id', v_source.character_skill_id::text,
        'source_removed', false
      );

    if found then
      update public.odyssey_character_abilities
      set
        character_skill_id = v_source.character_skill_id,
        learned_level = v_source.skill_level,
        is_enabled = true,
        is_hidden = false,
        data = v_payload_data,
        sort_order = v_source.sort_order,
        updated_at = timezone('utc', now())
      where id = v_existing.id;
    else
      insert into public.odyssey_character_abilities (
        character_id,
        ability_def_id,
        character_skill_id,
        learned_level,
        source_equipment_item_id,
        source_character_item_id,
        source_character_weapon_id,
        is_enabled,
        is_hidden,
        data,
        notes,
        sort_order
      )
      values (
        p_character_id,
        v_source.ability_def_id,
        v_source.character_skill_id,
        v_source.skill_level,
        null,
        null,
        null,
        true,
        false,
        v_payload_data,
        '',
        v_source.sort_order
      );
    end if;

    v_skill_upserted := v_skill_upserted + 1;
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    character_skill_id = null,
    data =
      coalesce(ability.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'skill',
        'source_removed', true,
        'source_removed_reason', 'missing_skill'
      ),
    updated_at = timezone('utc', now())
  where ability.character_id = p_character_id
    and ability.source_equipment_item_id is null
    and ability.source_character_item_id is null
    and ability.source_character_weapon_id is null
    and coalesce(ability.data->>'generated_from', 'skill') = 'skill'
    and exists (
      select 1
      from public.odyssey_ability_defs ad
      where ad.id = ability.ability_def_id
        and (
          (ad.linked_skill_id is not null)
          or exists (
            select 1
            from public.odyssey_ability_grants grant_link
            where grant_link.ability_def_id = ad.id
              and grant_link.source_type = 'skill'
          )
        )
    )
    and not exists (
      select 1
      from public.odyssey_ability_defs ad
      left join public.odyssey_character_skills skill_row
        on skill_row.character_id = p_character_id
       and skill_row.skill_def_id = ad.linked_skill_id
      where ad.id = ability.ability_def_id
        and ad.linked_skill_id is not null
        and skill_row.id is not null
      union all
      select 1
      from public.odyssey_ability_grants grant_link
      join public.odyssey_character_skills skill_row
        on skill_row.character_id = p_character_id
       and skill_row.skill_def_id = grant_link.source_def_id
      where grant_link.ability_def_id = ability.ability_def_id
        and grant_link.source_type = 'skill'
        and grant_link.is_enabled = true
        and greatest(coalesce(skill_row.level, 0), 0) >= greatest(coalesce(grant_link.min_level, 1), 1)
    );

  get diagnostics v_skill_hidden = row_count;

  for v_source in
    select
      ad.id as ability_def_id,
      ad.code as ability_code,
      cp.id as character_perk_id,
      cp.perk_def_id,
      coalesce(grant_link.sort_order, ad.sort_order, 0) as sort_order,
      coalesce(grant_link.data, '{}'::jsonb) as grant_data
    from public.odyssey_character_perks cp
    join public.odyssey_ability_grants grant_link
      on grant_link.source_type = 'perk'
     and grant_link.source_def_id = cp.perk_def_id
     and grant_link.is_enabled = true
    join public.odyssey_ability_defs ad on ad.id = grant_link.ability_def_id
    where cp.character_id = p_character_id
  loop
    select *
    into v_existing
    from public.odyssey_character_abilities ability
    where ability.character_id = p_character_id
      and ability.ability_def_id = v_source.ability_def_id
      and ability.source_equipment_item_id is null
      and ability.source_character_item_id is null
      and ability.source_character_weapon_id is null
      and coalesce(ability.data->>'generated_from', '') = 'perk'
    for update of ability;

    v_payload_data :=
      coalesce(v_existing.data, '{}'::jsonb)
      || coalesce(v_source.grant_data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'perk',
        'perk_def_id', v_source.perk_def_id::text,
        'character_perk_id', v_source.character_perk_id::text,
        'source_removed', false
      );

    if found then
      update public.odyssey_character_abilities
      set
        character_skill_id = null,
        learned_level = greatest(coalesce(v_existing.learned_level, 1), 1),
        is_enabled = true,
        is_hidden = false,
        data = v_payload_data,
        sort_order = v_source.sort_order,
        updated_at = timezone('utc', now())
      where id = v_existing.id;
    else
      begin
        insert into public.odyssey_character_abilities (
          character_id,
          ability_def_id,
          character_skill_id,
          learned_level,
          source_equipment_item_id,
          source_character_item_id,
          source_character_weapon_id,
          is_enabled,
          is_hidden,
          data,
          notes,
          sort_order
        )
        values (
          p_character_id,
          v_source.ability_def_id,
          null,
          1,
          null,
          null,
          null,
          true,
          false,
          v_payload_data,
          '',
          v_source.sort_order
        );
      exception
        when unique_violation then
          null;
      end;
    end if;

    v_perk_upserted := v_perk_upserted + 1;
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    data =
      coalesce(ability.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'perk',
        'source_removed', true,
        'source_removed_reason', 'missing_perk'
      ),
    updated_at = timezone('utc', now())
  where ability.character_id = p_character_id
    and ability.source_equipment_item_id is null
    and ability.source_character_item_id is null
    and ability.source_character_weapon_id is null
    and coalesce(ability.data->>'generated_from', '') = 'perk'
    and not exists (
      select 1
      from public.odyssey_character_perks cp
      join public.odyssey_ability_grants grant_link
        on grant_link.source_type = 'perk'
       and grant_link.source_def_id = cp.perk_def_id
       and grant_link.ability_def_id = ability.ability_def_id
       and grant_link.is_enabled = true
      where cp.character_id = p_character_id
    );

  get diagnostics v_perk_hidden = row_count;

  for v_source in
    select
      ad.id as ability_def_id,
      ad.code as ability_code,
      item.id as source_character_item_id,
      item.item_def_id,
      coalesce(link.sort_order, ad.sort_order, item.sort_order, 0) as sort_order,
      coalesce(link.grant_mode, 'activated') as grant_mode,
      coalesce(link.data, '{}'::jsonb) as grant_data
    from public.odyssey_character_items item
    join public.odyssey_item_def_abilities link
      on link.item_def_id = item.item_def_id
     and link.is_enabled = true
    join public.odyssey_ability_defs ad on ad.id = link.ability_def_id
    where item.character_id = p_character_id
      and coalesce(item.quantity, 0) > 0
  loop
    select *
    into v_existing
    from public.odyssey_character_abilities ability
    where ability.character_id = p_character_id
      and ability.ability_def_id = v_source.ability_def_id
      and ability.source_character_item_id = v_source.source_character_item_id
    for update of ability;

    v_payload_data :=
      coalesce(v_existing.data, '{}'::jsonb)
      || coalesce(v_source.grant_data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'item',
        'item_def_id', v_source.item_def_id::text,
        'source_character_item_id', v_source.source_character_item_id::text,
        'grant_mode', v_source.grant_mode,
        'source_removed', false
      );

    if found then
      update public.odyssey_character_abilities
      set
        character_skill_id = null,
        learned_level = greatest(coalesce(v_existing.learned_level, 1), 1),
        is_enabled = true,
        is_hidden = false,
        data = v_payload_data,
        sort_order = v_source.sort_order,
        updated_at = timezone('utc', now())
      where id = v_existing.id;
    else
      insert into public.odyssey_character_abilities (
        character_id,
        ability_def_id,
        character_skill_id,
        learned_level,
        source_equipment_item_id,
        source_character_item_id,
        source_character_weapon_id,
        is_enabled,
        is_hidden,
        data,
        notes,
        sort_order
      )
      values (
        p_character_id,
        v_source.ability_def_id,
        null,
        1,
        null,
        v_source.source_character_item_id,
        null,
        true,
        false,
        v_payload_data,
        '',
        v_source.sort_order
      );
    end if;

    v_item_upserted := v_item_upserted + 1;
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    data =
      coalesce(ability.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'item',
        'source_removed', true,
        'source_removed_reason', 'missing_item'
      ),
    updated_at = timezone('utc', now())
  where ability.character_id = p_character_id
    and ability.source_character_item_id is not null
    and not exists (
      select 1
      from public.odyssey_character_items item
      join public.odyssey_item_def_abilities link
        on link.item_def_id = item.item_def_id
       and link.ability_def_id = ability.ability_def_id
       and link.is_enabled = true
      where item.id = ability.source_character_item_id
        and item.character_id = p_character_id
        and coalesce(item.quantity, 0) > 0
    );

  get diagnostics v_item_hidden = row_count;

  for v_source in
    select
      ad.id as ability_def_id,
      ad.code as ability_code,
      item.id as source_equipment_item_id,
      item.equipment_model_id,
      coalesce(link.sort_order, ad.sort_order, item.sort_order, 0) as sort_order,
      coalesce(link.grant_mode, 'available') as grant_mode,
      coalesce(link.data, '{}'::jsonb) as grant_data
    from public.odyssey_character_equipment_items item
    join public.odyssey_equipment_model_abilities link
      on link.equipment_model_id = item.equipment_model_id
     and link.is_enabled = true
    join public.odyssey_ability_defs ad on ad.id = link.ability_def_id
    where item.character_id = p_character_id
      and item.is_equipped = true
  loop
    select *
    into v_existing
    from public.odyssey_character_abilities ability
    where ability.character_id = p_character_id
      and ability.ability_def_id = v_source.ability_def_id
      and ability.source_equipment_item_id = v_source.source_equipment_item_id
    for update of ability;

    v_payload_data :=
      coalesce(v_existing.data, '{}'::jsonb)
      || coalesce(v_source.grant_data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'equipment',
        'equipment_model_id', v_source.equipment_model_id::text,
        'source_equipment_item_id', v_source.source_equipment_item_id::text,
        'grant_mode', v_source.grant_mode,
        'source_removed', false
      );

    if found then
      update public.odyssey_character_abilities
      set
        character_skill_id = null,
        learned_level = greatest(coalesce(v_existing.learned_level, 1), 1),
        is_enabled = true,
        is_hidden = false,
        data = v_payload_data,
        sort_order = v_source.sort_order,
        updated_at = timezone('utc', now())
      where id = v_existing.id;
    else
      insert into public.odyssey_character_abilities (
        character_id,
        ability_def_id,
        character_skill_id,
        learned_level,
        source_equipment_item_id,
        source_character_item_id,
        source_character_weapon_id,
        is_enabled,
        is_hidden,
        data,
        notes,
        sort_order
      )
      values (
        p_character_id,
        v_source.ability_def_id,
        null,
        1,
        v_source.source_equipment_item_id,
        null,
        null,
        true,
        false,
        v_payload_data,
        '',
        v_source.sort_order
      );
    end if;

    v_equipment_upserted := v_equipment_upserted + 1;
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    data =
      coalesce(ability.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'equipment',
        'source_removed', true,
        'source_removed_reason', 'missing_equipment'
      ),
    updated_at = timezone('utc', now())
  where ability.character_id = p_character_id
    and ability.source_equipment_item_id is not null
    and not exists (
      select 1
      from public.odyssey_character_equipment_items item
      join public.odyssey_equipment_model_abilities link
        on link.equipment_model_id = item.equipment_model_id
       and link.ability_def_id = ability.ability_def_id
       and link.is_enabled = true
      where item.id = ability.source_equipment_item_id
        and item.character_id = p_character_id
        and item.is_equipped = true
    );

  get diagnostics v_equipment_hidden = row_count;

  for v_source in
    select weapon.id
    from public.odyssey_character_weapons weapon
    where weapon.character_id = p_character_id
  loop
    v_weapon_sync_result := public.initialize_character_weapon_abilities(v_source.id);
    v_weapon_result := v_weapon_result || jsonb_build_array(v_weapon_sync_result);
  end loop;

  update public.odyssey_character_abilities ability
  set
    is_enabled = false,
    is_hidden = true,
    data =
      coalesce(ability.data, '{}'::jsonb)
      || jsonb_build_object(
        'generated', true,
        'generated_from', 'weapon',
        'source_removed', true,
        'source_removed_reason', 'missing_weapon'
      ),
    updated_at = timezone('utc', now())
  where ability.character_id = p_character_id
    and ability.source_character_weapon_id is not null
    and not exists (
      select 1
      from public.odyssey_character_weapons weapon
      where weapon.id = ability.source_character_weapon_id
        and weapon.character_id = p_character_id
    );

  get diagnostics v_weapon_hidden = row_count;

  return jsonb_build_object(
    'ok', true,
    'character_id', p_character_id,
    'skill_upserted', v_skill_upserted,
    'skill_hidden', v_skill_hidden,
    'perk_upserted', v_perk_upserted,
    'perk_hidden', v_perk_hidden,
    'item_upserted', v_item_upserted,
    'item_hidden', v_item_hidden,
    'equipment_upserted', v_equipment_upserted,
    'equipment_hidden', v_equipment_hidden,
    'weapon_hidden', v_weapon_hidden,
    'weapon_result', v_weapon_result
  );
end;
$$;

create or replace function public.odyssey_reconcile_character_abilities_trigger()
returns trigger
language plpgsql
as $$
declare
  v_character_id uuid := coalesce(new.character_id, old.character_id);
begin
  if v_character_id is not null then
    perform public.odyssey_reconcile_character_abilities(v_character_id);
  end if;

  if tg_op = 'DELETE' then
    return old;
  end if;

  return new;
end;
$$;

drop trigger if exists odyssey_reconcile_character_abilities_on_skills on public.odyssey_character_skills;
create trigger odyssey_reconcile_character_abilities_on_skills
after insert or update or delete on public.odyssey_character_skills
for each row
execute function public.odyssey_reconcile_character_abilities_trigger();

drop trigger if exists odyssey_reconcile_character_abilities_on_perks on public.odyssey_character_perks;
create trigger odyssey_reconcile_character_abilities_on_perks
after insert or update or delete on public.odyssey_character_perks
for each row
execute function public.odyssey_reconcile_character_abilities_trigger();

drop trigger if exists odyssey_reconcile_character_abilities_on_items on public.odyssey_character_items;
create trigger odyssey_reconcile_character_abilities_on_items
after insert or update or delete on public.odyssey_character_items
